	bool materializeCallbackRuntimeCountersSnapshotFromDispatch(LuaCallbackExecutionContext &context,
	                                                            const bool                   withStrings)
	{
		if (context.runtimeCountersSnapshotDirty)
			return false;
		const auto *dispatchSnapshot = context.miniWindowLookupBaseSnapshot;
		if (!dispatchSnapshot || !dispatchSnapshot->hasRuntimeCountersSnapshot)
			return false;

		if (!context.hasRuntimeCountersSnapshot)
		{
			context.runtimeCountersSnapshot    = runtimeCountersSnapshotFromDispatch(*dispatchSnapshot);
			context.hasRuntimeCountersSnapshot = true;
		}
		if (withStrings && !context.hasRuntimeCountersSnapshotWithStrings)
		{
			context.runtimeCountersSnapshotWithStrings    = context.runtimeCountersSnapshot;
			context.hasRuntimeCountersSnapshotWithStrings = true;
		}
		return true;
	}

