	void adjustCallbackMappingCountSnapshot(const LuaCallbackEngine *engine, WorldRuntime *runtime,
	                                        const int delta)
	{
		auto *context = activeCallbackContext(engine);
		if (!context || delta == 0)
			return;
		WorldRuntime::RuntimeCountersSnapshot snapshot;
		static_cast<void>(resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot));
		if (context->hasRuntimeCountersSnapshot)
		{
			const int updated = qMax(0, context->runtimeCountersSnapshot.mappingCount + delta);
			context->runtimeCountersSnapshot.mappingCount = updated;
		}
		if (context->hasRuntimeCountersSnapshotWithStrings)
		{
			const int updated = qMax(0, context->runtimeCountersSnapshotWithStrings.mappingCount + delta);
			context->runtimeCountersSnapshotWithStrings.mappingCount = updated;
		}
	}

