	void clearCallbackChatInfoValues(const LuaCallbackEngine *engine, const long id)
	{
		auto *context = activeCallbackContext(engine);
		if (!context)
			return;
		const QString prefix = QStringLiteral("%1|").arg(id);
		for (auto it = context->chatInfoValuesByKey.begin(); it != context->chatInfoValuesByKey.end();)
		{
			if (it.key().startsWith(prefix))
				it = context->chatInfoValuesByKey.erase(it);
			else
				++it;
		}
		for (auto it = context->chatOptionValuesByKey.begin(); it != context->chatOptionValuesByKey.end();)
		{
			if (it.key().startsWith(prefix))
				it = context->chatOptionValuesByKey.erase(it);
			else
				++it;
		}
		context->chatIdsByLookupKey.clear();
	}

