	QString buildMappingStringFromEntries(const QStringList &entries, const bool omitComments)
	{
		QString lastDir;
		QString output;
		int     count = 0;

		auto    outputPrevious = [&](const QString &current)
		{
			if (!lastDir.isEmpty())
			{
				QString formatted = lastDir;
				if (formatted.size() > 1)
					formatted = QStringLiteral("(%1)").arg(formatted);
				if (count == 1)
					output += formatted + QLatin1Char(' ');
				else if (count > 1)
					output += QString::number(count) + formatted + QLatin1Char(' ');
			}
			lastDir = current;
			count   = 1;
		};

		for (const QString &entry : entries)
		{
			if (entry.size() > 2 && entry.startsWith(QLatin1Char('{')) && entry.endsWith(QLatin1Char('}')))
			{
				outputPrevious(QString());
				if (!omitComments)
				{
					if (!output.isEmpty())
						output += QLatin1Char('\n');
					output += entry;
					output += QLatin1Char('\n');
				}
				lastDir.clear();
				count = 0;
				continue;
			}

			if (entry == lastDir && count <= 98)
			{
				count++;
				continue;
			}
			outputPrevious(entry);
		}

		outputPrevious(QString());
		return output;
	}

	QString makeCallbackNotepadDocumentKey(const QString &title, const QString &worldId,
	                                       const WorldRuntime *runtime)
	{
		const auto runtimeToken = static_cast<qulonglong>(reinterpret_cast<quintptr>(runtime));
		return QStringLiteral("%1|%2|%3")
		    .arg(QString::number(runtimeToken, 16), worldId.trimmed().toLower(), title.trimmed().toLower());
	}

	QString makeCallbackNotepadListKey(const bool all, const QString &worldId, const WorldRuntime *runtime)
	{
		const auto runtimeToken = static_cast<qulonglong>(reinterpret_cast<quintptr>(runtime));
		return QStringLiteral("%1|%2|%3")
		    .arg(all ? QStringLiteral("1") : QStringLiteral("0"), QString::number(runtimeToken, 16),
		         worldId.trimmed().toLower());
	}

	QString makeCallbackRuntimeKey(const WorldRuntime *runtime)
	{
		if (!runtime)
			return {};
		const auto runtimeToken = static_cast<qulonglong>(reinterpret_cast<quintptr>(runtime));
		return QString::number(runtimeToken, 16);
	}

