	bool tryResolveCallbackMainWindowPositionFromDispatchSnapshot(const LuaCallbackEngine *engine,
	                                                              const bool useGetWindowRect, QRect &rect)
	{
		if (const auto *context = activeCallbackContextConst(engine);
		    context && context->mainWindowPositionsDirty)
		{
			return false;
		}
		const auto *snapshot = engine ? engine->currentDispatchMiniWindowSnapshot() : nullptr;
		if (!snapshot || !snapshot->hasUiSnapshot)
			return false;
		const int  mode = useGetWindowRect ? 1 : 0;
		const auto it   = snapshot->mainWindowPositionsByMode.constFind(mode);
		if (it == snapshot->mainWindowPositionsByMode.constEnd())
			return false;
		rect = it.value();
		cacheCallbackMainWindowPosition(engine, useGetWindowRect, rect);
		return true;
	}

	bool tryResolveCallbackWorldWindowPositionFromDispatchSnapshot(const LuaCallbackEngine *engine,
	                                                               const WorldRuntime      *runtime,
	                                                               const int which, const bool screen,
	                                                               const bool useGetWindowRect, QRect &rect,
	                                                               bool &found)
	{
		found = false;
		if (const auto *context = activeCallbackContextConst(engine);
		    context && context->dirtyWorldWindowPositionOrdinals.contains(which))
		{
			return false;
		}
		const auto *snapshot = engine ? engine->currentDispatchMiniWindowSnapshot() : nullptr;
		if (!snapshot || !snapshot->hasUiSnapshot)
			return false;
		for (const LuaCallbackWorldWindowPositionSnapshot &position : snapshot->worldWindowPositionSnapshot)
		{
			if (position.runtime != runtime || position.ordinal != which)
				continue;
			if (screen)
				rect = useGetWindowRect ? position.screenFrameGeometry : position.screenNormalGeometry;
			else
				rect = useGetWindowRect ? position.frameGeometry : position.normalGeometry;
			found = true;
			cacheCallbackWorldWindowPosition(engine, which, screen, useGetWindowRect, true, rect);
			return true;
		}
		cacheCallbackWorldWindowPosition(engine, which, screen, useGetWindowRect, false, QRect());
		return true;
	}

	const LuaCallbackNotepadSnapshot *
	findCallbackNotepadSnapshot(const LuaCallbackMiniWindowSnapshot &snapshot, const QString &title,
	                            const WorldRuntime *runtime, const QString &worldId)
	{
		const auto                        ownerToken           = reinterpret_cast<quintptr>(runtime);
		const LuaCallbackNotepadSnapshot *unnamedOwnerFallback = nullptr;
		for (const LuaCallbackNotepadSnapshot &notepad : snapshot.notepadSnapshot)
		{
			if (notepad.title.compare(title, Qt::CaseInsensitive) != 0)
				continue;
			const auto relatedToken = reinterpret_cast<quintptr>(notepad.runtime);
			if (ownerToken != 0 && relatedToken == ownerToken)
				return &notepad;
			if (ownerToken != 0 && relatedToken != 0 && relatedToken != ownerToken)
				continue;
			if (worldId.isEmpty())
				return &notepad;
			if (notepad.worldId.compare(worldId, Qt::CaseInsensitive) == 0)
				return &notepad;
			if (notepad.worldId.isEmpty() && !unnamedOwnerFallback)
				unnamedOwnerFallback = &notepad;
		}
		return unnamedOwnerFallback;
	}

	bool tryResolveCallbackNotepadWindowPositionFromDispatchSnapshot(const LuaCallbackEngine *engine,
	                                                                 const WorldRuntime      *runtime,
	                                                                 const QString           &title,
	                                                                 const QString &worldId, QRect &rect,
	                                                                 bool &found)
	{
		found = false;
		if (const auto *context = activeCallbackContextConst(engine);
		    context && context->dirtyNotepadWindowPositionKeys.contains(
		                   makeCallbackNotepadWindowPositionKey(title, worldId)))
		{
			return false;
		}
		const auto *snapshot = engine ? engine->currentDispatchMiniWindowSnapshot() : nullptr;
		if (!snapshot || !snapshot->hasUiSnapshot)
			return false;
		const LuaCallbackNotepadSnapshot *notepad =
		    findCallbackNotepadSnapshot(*snapshot, title, runtime, worldId);
		if (!notepad)
		{
			cacheCallbackNotepadWindowPosition(engine, title, worldId, false, QRect());
			return true;
		}
		rect  = notepad->geometry;
		found = true;
		cacheCallbackNotepadWindowPosition(engine, title, worldId, true, rect);
		return true;
	}

	bool tryResolveCallbackNotepadLengthFromDispatchSnapshot(const LuaCallbackEngine *engine,
	                                                         const WorldRuntime      *runtime,
	                                                         const QString &title, const QString &worldId,
	                                                         const QString &key, int &length)
	{
		const auto *snapshot = engine ? engine->currentDispatchMiniWindowSnapshot() : nullptr;
		if (!snapshot || !snapshot->hasUiSnapshot)
			return false;
		const LuaCallbackNotepadSnapshot *notepad =
		    findCallbackNotepadSnapshot(*snapshot, title, runtime, worldId);
		const bool found = notepad && notepad->hasEditor;
		length           = found ? sizeToInt(notepad->text.length()) : 0;
		cacheCallbackNotepadLength(engine, key, found, length);
		return true;
	}

