	const LuaCallbackDatabaseSnapshot *callbackDatabaseSnapshotForApi(const LuaCallbackEngine *engine,
	                                                                  const QString           &name,
	                                                                  bool &snapshotAvailable)
	{
		snapshotAvailable   = false;
		const auto *context = activeCallbackContextConst(engine);
		if (!context || !context->hasDatabaseSnapshot)
			return nullptr;
		if (context->dirtyDatabaseSnapshotNames.contains(name.trimmed().toLower()))
			return nullptr;
		snapshotAvailable = true;
		const auto it     = context->databaseSnapshotsByName.constFind(name);
		if (it == context->databaseSnapshotsByName.constEnd())
			return nullptr;
		return &it.value();
	}

	int callbackDatabaseColumnTypeFromSnapshot(const LuaCallbackDatabaseSnapshot &database, const int column)
	{
		if (!database.isOpen)
			return kDbErrorNotOpen;
		if (!database.stmtPrepared)
			return kDbErrorNoPreparedStatement;
		if (!database.validRow)
			return kDbErrorNoValidRow;
		if (column < 1 || column > database.columns || column > database.columnValues.size())
			return kDbErrorColumnOutOfRange;
		return mapCallbackDatabaseVariantTypeToSqlite(database.columnValues.at(column - 1));
	}

	void invalidateCallbackDatabaseSnapshotForName(const LuaCallbackEngine *engine, const QString &name)
	{
		auto *context = activeCallbackContext(engine);
		if (!context)
			return;
		context->databaseColumnsByName.remove(name);
		context->databaseErrorsByName.remove(name);
		context->databaseColumnNamesByName.remove(name);
		context->missingDatabaseColumnNamesByName.remove(name);
		context->databaseColumnValuesByName.remove(name);
		context->missingDatabaseColumnValuesByName.remove(name);
		context->databaseSnapshotsByName.remove(name);
		context->dirtyDatabaseSnapshotNames.insert(name.trimmed().toLower());
		context->databaseTotalChangesByName.remove(name);
		context->databaseChangesByName.remove(name);
		context->databaseLastInsertRowidByName.remove(name);
		const QString prefix           = name + QLatin1Char('\x1F');
		auto          removeWithPrefix = [&prefix](auto &container)
		{
			for (auto it = container.begin(); it != container.end();)
			{
				if (it.key().startsWith(prefix))
					it = container.erase(it);
				else
					++it;
			}
		};
		auto removeSetWithPrefix = [&prefix](QSet<QString> &container)
		{
			for (auto it = container.begin(); it != container.end();)
			{
				if (it->startsWith(prefix))
					it = container.erase(it);
				else
					++it;
			}
		};
		removeWithPrefix(context->databaseColumnNamesByKey);
		removeWithPrefix(context->databaseColumnTextByKey);
		removeWithPrefix(context->databaseColumnValuesByKey);
		removeWithPrefix(context->databaseColumnTypesByKey);
		removeWithPrefix(context->databaseInfoByKey);
		removeSetWithPrefix(context->missingDatabaseColumnNameKeys);
		removeSetWithPrefix(context->missingDatabaseColumnTextKeys);
		removeSetWithPrefix(context->missingDatabaseColumnValueKeys);
		removeSetWithPrefix(context->missingDatabaseInfoKeys);
	}

	void cacheCallbackDatabaseListAfterOpen(const LuaCallbackEngine *engine, const QString &name)
	{
		auto *context = activeCallbackContext(engine);
		if (!context)
			return;
		QStringList names;
		if (context->hasDatabaseListSnapshot || context->hasDatabaseSnapshot)
			names = context->databaseListSnapshot;
		else
			return;
		const bool alreadyPresent = std::ranges::any_of(
		    names, [&name](const QString &entry) { return entry.compare(name, Qt::CaseInsensitive) == 0; });
		if (!alreadyPresent)
			names.push_back(name);
		cacheCallbackDatabaseList(engine, names);
	}

	void cacheCallbackDatabaseListAfterClose(const LuaCallbackEngine *engine, const QString &name)
	{
		auto *context = activeCallbackContext(engine);
		if (!context)
			return;
		QStringList names;
		if (context->hasDatabaseListSnapshot || context->hasDatabaseSnapshot)
			names = context->databaseListSnapshot;
		else
			return;
		names.removeIf([&name](const QString &entry)
		               { return entry.compare(name, Qt::CaseInsensitive) == 0; });
		cacheCallbackDatabaseList(engine, names);
	}

	template <typename Item>
	bool tryResolveCallbackObjectSnapshotFromCache(const QString &pluginId, const QString &name,
	                                               const QHash<QString, Item> &snapshotsByKey,
	                                               const QSet<QString>        &missingSnapshotKeys,
	                                               const QSet<QString> &missingPluginIds, Item &item,
	                                               bool &pluginMissing, bool &cacheHit)
	{
		cacheHit      = false;
		pluginMissing = false;

		const QString key = makeCallbackObjectSnapshotKey(pluginId, name);
		if (!pluginId.isEmpty() && missingPluginIds.contains(pluginId))
		{
			cacheHit      = true;
			pluginMissing = true;
			return false;
		}
		if (const auto itemIt = snapshotsByKey.constFind(key); itemIt != snapshotsByKey.constEnd())
		{
			item     = itemIt.value();
			cacheHit = true;
			return true;
		}
		if (missingSnapshotKeys.contains(key))
		{
			cacheHit = true;
			return false;
		}
		return false;
	}

	template <typename Item>
	void cacheCallbackObjectSnapshot(const QString &pluginId, const QString &name, const bool found,
	                                 const Item &item, const bool pluginMissing,
	                                 QHash<QString, Item> &snapshotsByKey, QSet<QString> &missingSnapshotKeys,
	                                 QSet<QString> &missingPluginIds)
	{
		const QString key = makeCallbackObjectSnapshotKey(pluginId, name);
		if (!pluginId.isEmpty())
		{
			if (pluginMissing)
				missingPluginIds.insert(pluginId);
			else
				missingPluginIds.remove(pluginId);
		}
		if (found)
		{
			snapshotsByKey.insert(key, item);
			missingSnapshotKeys.remove(key);
			return;
		}
		snapshotsByKey.remove(key);
		missingSnapshotKeys.insert(key);
	}

	template <typename Item>
	void invalidateCallbackObjectSnapshotCacheForPlugin(const QString        &pluginId,
	                                                    QHash<QString, Item> &snapshotsByKey,
	                                                    QSet<QString>        &missingSnapshotKeys)
	{
		const QString prefix = pluginId + QLatin1Char('\x1F');
		for (auto it = snapshotsByKey.begin(); it != snapshotsByKey.end();)
		{
			if (it.key().startsWith(prefix))
				it = snapshotsByKey.erase(it);
			else
				++it;
		}
		for (auto it = missingSnapshotKeys.begin(); it != missingSnapshotKeys.end();)
		{
			if (it->startsWith(prefix))
				it = missingSnapshotKeys.erase(it);
			else
				++it;
		}
	}

	template <typename Item>
	bool tryResolveCallbackListSnapshotFromCache(const QString                     &pluginId,
	                                             const QHash<QString, QList<Item>> &listsByPluginId,
	                                             const QSet<QString> &missingPluginIds, QList<Item> &items,
	                                             bool &pluginMissing, bool &cacheHit)
	{
		cacheHit      = false;
		pluginMissing = false;
		if (!pluginId.isEmpty() && missingPluginIds.contains(pluginId))
		{
			items.clear();
			cacheHit      = true;
			pluginMissing = true;
			return false;
		}
		if (const auto listIt = listsByPluginId.constFind(pluginId); listIt != listsByPluginId.constEnd())
		{
			items    = listIt.value();
			cacheHit = true;
			return true;
		}
		return false;
	}

	template <typename Item>
	bool tryResolveCallbackListSnapshotViewFromCache(const QString                     &pluginId,
	                                                 const QHash<QString, QList<Item>> &listsByPluginId,
	                                                 const QSet<QString>               &missingPluginIds,
	                                                 const QList<Item> *&itemsView, bool &pluginMissing,
	                                                 bool &cacheHit)
	{
		cacheHit      = false;
		pluginMissing = false;
		itemsView     = nullptr;
		if (!pluginId.isEmpty() && missingPluginIds.contains(pluginId))
		{
			cacheHit      = true;
			pluginMissing = true;
			return false;
		}
		if (const auto listIt = listsByPluginId.constFind(pluginId); listIt != listsByPluginId.constEnd())
		{
			itemsView = &listIt.value();
			cacheHit  = true;
			return true;
		}
		return false;
	}

	template <typename Item>
	void cacheCallbackListSnapshot(const QString &pluginId, const bool found, const QList<Item> &items,
	                               const bool pluginMissing, QHash<QString, QList<Item>> &listsByPluginId,
	                               QSet<QString> &missingPluginIds)
	{
		if (!pluginId.isEmpty())
		{
			if (pluginMissing)
			{
				missingPluginIds.insert(pluginId);
				listsByPluginId.remove(pluginId);
				return;
			}
			missingPluginIds.remove(pluginId);
		}
		if (found)
			listsByPluginId.insert(pluginId, items);
		else
			listsByPluginId.remove(pluginId);
	}

