	bool tryResolveCallbackPluginInfoValueFromCache(const LuaCallbackEngine *engine, const QString &pluginId,
	                                                const int infoType, QVariant &value, bool &cacheHit)
	{
		cacheHit            = false;
		const auto *context = activeCallbackContextConst(engine);
		if (!context)
			return false;
		const QString key = makeCallbackPluginInfoKey(pluginId, infoType);
		if (const auto valueIt = context->pluginInfoValuesByKey.constFind(key);
		    valueIt != context->pluginInfoValuesByKey.constEnd())
		{
			cacheHit = true;
			value    = valueIt.value();
			return true;
		}
		if (context->missingPluginInfoValueKeys.contains(key))
		{
			cacheHit = true;
			return false;
		}
		return false;
	}

	void cacheCallbackPluginInfoValue(const LuaCallbackEngine *engine, const QString &pluginId,
	                                  const int infoType, const QVariant &value, const bool hasValue)
	{
		auto *context = activeCallbackContext(engine);
		if (!context)
			return;
		const QString key = makeCallbackPluginInfoKey(pluginId, infoType);
		if (hasValue)
		{
			context->pluginInfoValuesByKey.insert(key, value);
			context->missingPluginInfoValueKeys.remove(key);
			return;
		}
		context->pluginInfoValuesByKey.remove(key);
		context->missingPluginInfoValueKeys.insert(key);
	}

