	bool tryResolveCallbackMiniWindowInfoFallback(const LuaCallbackEngine *engine, const QString &windowName,
	                                              const int infoType, QVariant &value)
	{
		if (infoType <= 0)
			return false;

		if (tryResolveCallbackMiniWindowInfoFromCache(engine, windowName, infoType, value))
			return true;

		bool exists = false;
		if (!tryResolveCallbackMiniWindowExistsFromCache(engine, windowName, exists))
			return false;
		if (!exists)
		{
			value = QVariant();
			return true;
		}
		// Window exists but info is missing in callback cache: do not synthesize sentinel coordinates
		// or dimensions. Let callers observe a real cache miss (`nil`) if no dispatch snapshot is present.
		return false;
	}

