	bool tryResolveCallbackMiniWindowInfoFromShadow(const LuaCallbackEngine *engine,
	                                                const QString &windowName, const int infoType,
	                                                QVariant &value)
	{
		const MiniWindow *window = callbackMiniWindowShadowConst(engine, windowName);
		if (!window)
			return false;
		switch (infoType)
		{
		case 1:
			value = window->location.x();
			return true;
		case 2:
			value = window->location.y();
			return true;
		case 3:
			value = window->width;
			return true;
		case 4:
			value = window->height;
			return true;
		case 5:
			value = window->show;
			return true;
		case 6:
			value = window->temporarilyHide;
			return true;
		case 7:
			value = window->position;
			return true;
		case 8:
			value = window->flags;
			return true;
		case 9:
			value = window->background.isValid()
			            ? QVariant::fromValue<qlonglong>(callbackMiniWindowColorValue(window->background))
			            : QVariant(0);
			return true;
		case 10:
			value = window->rect.left();
			return true;
		case 11:
			value = window->rect.top();
			return true;
		case 12:
			value = window->rect.right();
			return true;
		case 13:
			value = window->rect.bottom();
			return true;
		case 14:
			value = window->lastMousePosition.x();
			return true;
		case 15:
			value = window->lastMousePosition.y();
			return true;
		case 16:
			value = window->lastMouseUpdate;
			return true;
		case 17:
			value = window->clientMousePosition.x();
			return true;
		case 18:
			value = window->clientMousePosition.y();
			return true;
		case 19:
			value = window->mouseOverHotspot;
			return true;
		case 20:
			value = window->mouseDownHotspot;
			return true;
		case 21:
			value = window->installedAt.isValid()
			            ? QVariant(callbackMiniWindowToLuaSystemTime(window->installedAt))
			            : QVariant();
			return true;
		case 22:
			value = window->zOrder;
			return true;
		case 23:
			value = window->creatingPlugin;
			return true;
		default:
			return false;
		}
	}

	bool tryResolveCallbackMiniWindowFontInfoFromShadow(const LuaCallbackEngine *engine,
	                                                    const QString &windowName, const QString &fontId,
	                                                    const int infoType, QVariant &value)
	{
		const MiniWindow *window = callbackMiniWindowShadowConst(engine, windowName);
		if (!window)
			return false;
		value = MiniWindowUtils::fontInfo(*window, fontId, infoType);
		return value.isValid();
	}

	bool tryResolveCallbackMiniWindowTextWidthFromShadow(const LuaCallbackEngine *engine,
	                                                     const QString &windowName, const QString &fontId,
	                                                     const QString &text, int &width)
	{
		const MiniWindow *window = callbackMiniWindowShadowConst(engine, windowName);
		if (!window)
			return false;
		const auto it = window->fonts.constFind(fontId);
		if (it == window->fonts.constEnd())
			return false;
		width = qMax(0, it.value().metrics.horizontalAdvance(text));
		return true;
	}

	int drawCallbackMiniWindowShadowTextForApi(const LuaCallbackEngine *engine, const QString &windowName,
	                                           const QString &fontId, const QString &text, const int left,
	                                           const int top, const int right, const int bottom,
	                                           const long colour)
	{
		MiniWindow *window = callbackMiniWindowShadow(engine, windowName);
		if (!window)
			return eNoSuchWindow;
		const int width = MiniWindowUtils::text(*window, fontId, text, left, top, right, bottom, colour);
		if (width >= 0)
			cacheCallbackMiniWindowTextWidth(engine, windowName, fontId, text, width);
		return width;
	}

	int renderCallbackMiniWindowShadowOutputTextForApi(const LuaCallbackEngine *engine,
	                                                   const QString &windowName, const QString &fontId,
	                                                   const QString &text, const int left, const int top,
	                                                   const int right, const int bottom, const long colour,
	                                                   const QString &mouseUp, const QString &hotspotPrefix,
	                                                   const QString                     &pluginId,
	                                                   WorldRuntime::WindowOutputMetrics *metrics)
	{
		MiniWindow *window = callbackMiniWindowShadow(engine, windowName);
		if (!window)
			return eNoSuchWindow;

		WorldRuntime::WindowOutputTextRenderContext renderContext;
		static_cast<void>(buildCallbackWindowOutputTextRenderContext(engine, renderContext));
		return WorldRuntime::renderWindowOutputText(*window, fontId, text, left, top, right, bottom, colour,
		                                            mouseUp, hotspotPrefix, pluginId,
		                                            std::move(renderContext), metrics);
	}

