	bool splitCallbackCompositeKey(const QString &key, QString &left, QString &right,
	                               const QChar separator = QLatin1Char('\x1F'))
	{
		const qsizetype separatorIndex = key.indexOf(separator);
		if (separatorIndex < 0)
			return false;
		left  = key.left(separatorIndex);
		right = key.mid(separatorIndex + 1);
		return !left.isEmpty();
	}

	void ensureSnapshotColumnCount(LuaCallbackDatabaseSnapshot &snapshot, const int column)
	{
		if (column <= 0)
			return;
		snapshot.columns = qMax(snapshot.columns, column);
		while (snapshot.columnNames.size() < column)
			snapshot.columnNames.push_back(QString());
		while (snapshot.columnValues.size() < column)
			snapshot.columnValues.push_back(QVariant());
	}

	template <typename Container>
	void removeSnapshotDatabaseEntriesWithPrefix(Container &container, const QString &prefix)
	{
		for (auto it = container.begin(); it != container.end();)
		{
			if (it.key().startsWith(prefix))
				it = container.erase(it);
			else
				++it;
		}
	}

	void removeSnapshotDatabaseSetEntriesWithPrefix(QSet<QString> &container, const QString &prefix)
	{
		for (auto it = container.begin(); it != container.end();)
		{
			if (it->startsWith(prefix))
				it = container.erase(it);
			else
				++it;
		}
	}

	void removeSnapshotDatabaseCachesForName(LuaCallbackMiniWindowSnapshot &snapshot, const QString &name)
	{
		const QString prefix = name + QLatin1Char('\x1F');
		snapshot.databaseColumnsByName.remove(name);
		snapshot.databaseErrorsByName.remove(name);
		snapshot.databaseColumnNamesByName.remove(name);
		snapshot.missingDatabaseColumnNamesByName.remove(name);
		snapshot.databaseColumnValuesByName.remove(name);
		snapshot.missingDatabaseColumnValuesByName.remove(name);
		snapshot.databaseTotalChangesByName.remove(name);
		snapshot.databaseChangesByName.remove(name);
		snapshot.databaseLastInsertRowidByName.remove(name);
		removeSnapshotDatabaseEntriesWithPrefix(snapshot.databaseColumnNamesByKey, prefix);
		removeSnapshotDatabaseEntriesWithPrefix(snapshot.databaseColumnTextByKey, prefix);
		removeSnapshotDatabaseEntriesWithPrefix(snapshot.databaseColumnValuesByKey, prefix);
		removeSnapshotDatabaseEntriesWithPrefix(snapshot.databaseColumnTypesByKey, prefix);
		removeSnapshotDatabaseEntriesWithPrefix(snapshot.databaseInfoByKey, prefix);
		removeSnapshotDatabaseSetEntriesWithPrefix(snapshot.missingDatabaseColumnNameKeys, prefix);
		removeSnapshotDatabaseSetEntriesWithPrefix(snapshot.missingDatabaseColumnTextKeys, prefix);
		removeSnapshotDatabaseSetEntriesWithPrefix(snapshot.missingDatabaseColumnValueKeys, prefix);
		removeSnapshotDatabaseSetEntriesWithPrefix(snapshot.missingDatabaseInfoKeys, prefix);
	}

	void overlayCallbackDatabaseCachesForCallPlugin(const LuaCallbackExecutionContext &context,
	                                                LuaCallbackMiniWindowSnapshot     &snapshot)
	{
		if (context.databaseListSnapshotDirty)
		{
			snapshot.hasDatabaseListSnapshot   = false;
			snapshot.databaseListSnapshotDirty = true;
			snapshot.databaseNamesSnapshot.clear();
		}
		else if (context.hasDatabaseListSnapshot)
		{
			snapshot.hasDatabaseListSnapshot = true;
			snapshot.databaseNamesSnapshot   = context.databaseListSnapshot;
		}
		if (context.hasDatabaseSnapshot)
		{
			snapshot.hasDatabaseSnapshot     = true;
			snapshot.databaseSnapshotsByName = context.databaseSnapshotsByName;
		}
		snapshot.databaseColumnsByName             = context.databaseColumnsByName;
		snapshot.databaseErrorsByName              = context.databaseErrorsByName;
		snapshot.databaseColumnNamesByKey          = context.databaseColumnNamesByKey;
		snapshot.missingDatabaseColumnNameKeys     = context.missingDatabaseColumnNameKeys;
		snapshot.databaseColumnTextByKey           = context.databaseColumnTextByKey;
		snapshot.missingDatabaseColumnTextKeys     = context.missingDatabaseColumnTextKeys;
		snapshot.databaseColumnValuesByKey         = context.databaseColumnValuesByKey;
		snapshot.missingDatabaseColumnValueKeys    = context.missingDatabaseColumnValueKeys;
		snapshot.databaseColumnTypesByKey          = context.databaseColumnTypesByKey;
		snapshot.databaseInfoByKey                 = context.databaseInfoByKey;
		snapshot.missingDatabaseInfoKeys           = context.missingDatabaseInfoKeys;
		snapshot.databaseColumnNamesByName         = context.databaseColumnNamesByName;
		snapshot.missingDatabaseColumnNamesByName  = context.missingDatabaseColumnNamesByName;
		snapshot.databaseColumnValuesByName        = context.databaseColumnValuesByName;
		snapshot.missingDatabaseColumnValuesByName = context.missingDatabaseColumnValuesByName;
		snapshot.databaseTotalChangesByName        = context.databaseTotalChangesByName;
		snapshot.databaseChangesByName             = context.databaseChangesByName;
		snapshot.databaseLastInsertRowidByName     = context.databaseLastInsertRowidByName;
		for (auto it = context.databaseColumnsByName.constBegin();
		     it != context.databaseColumnsByName.constEnd(); ++it)
		{
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(it.key());
			    databaseIt != snapshot.databaseSnapshotsByName.end())
				databaseIt->columnsStatus = it.value();
		}
		for (auto it = context.databaseErrorsByName.constBegin();
		     it != context.databaseErrorsByName.constEnd(); ++it)
		{
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(it.key());
			    databaseIt != snapshot.databaseSnapshotsByName.end())
				databaseIt->errorText = it.value();
		}
		for (auto it = context.databaseColumnNamesByName.constBegin();
		     it != context.databaseColumnNamesByName.constEnd(); ++it)
		{
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(it.key());
			    databaseIt != snapshot.databaseSnapshotsByName.end())
			{
				databaseIt->columnNames = it.value();
				databaseIt->columns = qMax(databaseIt->columns, sizeToInt(databaseIt->columnNames.size()));
			}
		}
		for (auto it = context.databaseColumnValuesByName.constBegin();
		     it != context.databaseColumnValuesByName.constEnd(); ++it)
		{
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(it.key());
			    databaseIt != snapshot.databaseSnapshotsByName.end())
			{
				databaseIt->columnValues = it.value();
				databaseIt->columns = qMax(databaseIt->columns, sizeToInt(databaseIt->columnValues.size()));
			}
		}
		for (auto it = context.databaseColumnNamesByKey.constBegin();
		     it != context.databaseColumnNamesByKey.constEnd(); ++it)
		{
			QString name;
			QString columnText;
			bool    ok = false;
			if (!splitCallbackCompositeKey(it.key(), name, columnText))
				continue;
			const int column = columnText.toInt(&ok);
			if (!ok || column <= 0)
				continue;
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(name);
			    databaseIt != snapshot.databaseSnapshotsByName.end())
			{
				ensureSnapshotColumnCount(databaseIt.value(), column);
				databaseIt->columnNames[column - 1] = it.value();
			}
		}
		for (auto it = context.databaseColumnValuesByKey.constBegin();
		     it != context.databaseColumnValuesByKey.constEnd(); ++it)
		{
			QString name;
			QString columnText;
			bool    ok = false;
			if (!splitCallbackCompositeKey(it.key(), name, columnText))
				continue;
			const int column = columnText.toInt(&ok);
			if (!ok || column <= 0)
				continue;
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(name);
			    databaseIt != snapshot.databaseSnapshotsByName.end())
			{
				ensureSnapshotColumnCount(databaseIt.value(), column);
				databaseIt->columnValues[column - 1] = it.value();
			}
		}
		for (auto it = context.databaseTotalChangesByName.constBegin();
		     it != context.databaseTotalChangesByName.constEnd(); ++it)
		{
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(it.key());
			    databaseIt != snapshot.databaseSnapshotsByName.end())
				databaseIt->totalChanges = it.value();
		}
		for (auto it = context.databaseChangesByName.constBegin();
		     it != context.databaseChangesByName.constEnd(); ++it)
		{
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(it.key());
			    databaseIt != snapshot.databaseSnapshotsByName.end())
				databaseIt->changes = it.value();
		}
		for (auto it = context.databaseLastInsertRowidByName.constBegin();
		     it != context.databaseLastInsertRowidByName.constEnd(); ++it)
		{
			if (auto databaseIt = snapshot.databaseSnapshotsByName.find(it.key());
			    databaseIt != snapshot.databaseSnapshotsByName.end())
				databaseIt->lastInsertRowid = it.value();
		}
		for (const QString &name : context.dirtyDatabaseSnapshotNames)
		{
			snapshot.databaseSnapshotsByName.remove(name);
			removeSnapshotDatabaseCachesForName(snapshot, name);
		}
	}

	void overlayCallbackPluginMetadataForCallPlugin(const LuaCallbackExecutionContext &context,
	                                                LuaCallbackMiniWindowSnapshot     &snapshot)
	{
		if (context.pluginMetadataSnapshotDirty)
		{
			snapshot.pluginIdsSnapshot.clear();
			snapshot.pluginIdsByLookupKey.clear();
			snapshot.pluginNamesById.clear();
			snapshot.pluginDirectoriesById.clear();
			snapshot.pluginEnabledById.clear();
			snapshot.pluginEnginesById.clear();
			snapshot.pluginInfoValuesById.clear();
		}
		else if (context.hasPluginIdListSnapshot)
		{
			snapshot.pluginIdsSnapshot = context.pluginIdListSnapshot;
		}
		for (const QString &pluginId : context.dirtyPluginMetadataIds)
		{
			snapshot.pluginIdsSnapshot.removeAll(pluginId);
			snapshot.pluginIdsByLookupKey.remove(pluginId);
			snapshot.pluginNamesById.remove(pluginId);
			snapshot.pluginDirectoriesById.remove(pluginId);
			snapshot.pluginEnabledById.remove(pluginId);
			snapshot.pluginEnginesById.remove(pluginId);
			snapshot.pluginInfoValuesById.remove(pluginId);
		}
		for (auto it = context.pluginInstalledById.constBegin(); it != context.pluginInstalledById.constEnd();
		     ++it)
		{
			if (it.value())
			{
				if (!snapshot.pluginIdsSnapshot.contains(it.key(), Qt::CaseInsensitive))
					snapshot.pluginIdsSnapshot.push_back(it.key());
			}
			else
			{
				snapshot.pluginIdsSnapshot.removeAll(it.key());
				snapshot.pluginNamesById.remove(it.key());
				snapshot.pluginDirectoriesById.remove(it.key());
				snapshot.pluginEnabledById.remove(it.key());
				snapshot.pluginEnginesById.remove(it.key());
				snapshot.pluginInfoValuesById.remove(it.key());
			}
		}
		for (auto it = context.pluginInfoValuesByKey.constBegin();
		     it != context.pluginInfoValuesByKey.constEnd(); ++it)
		{
			QString pluginId;
			QString infoTypeText;
			bool    ok = false;
			if (!splitCallbackCompositeKey(it.key(), pluginId, infoTypeText))
				continue;
			const int infoType = infoTypeText.toInt(&ok);
			if (!ok)
				continue;
			snapshot.pluginInfoValuesById[pluginId].insert(infoType, it.value());
			if (infoType == 17)
				snapshot.pluginEnabledById.insert(pluginId, it.value().toBool());
		}
		for (const QString &key : context.missingPluginInfoValueKeys)
		{
			QString pluginId;
			QString infoTypeText;
			bool    ok = false;
			if (!splitCallbackCompositeKey(key, pluginId, infoTypeText))
				continue;
			const int infoType = infoTypeText.toInt(&ok);
			if (ok)
				snapshot.pluginInfoValuesById[pluginId].insert(infoType, QVariant());
		}
	}

	void overlayCallbackContextSnapshotsForCallPlugin(const LuaCallbackExecutionContext &context,
	                                                  LuaCallbackMiniWindowSnapshot     &snapshot,
	                                                  const WorldRuntime                *runtime)
	{
		if (context.hasCommandUiSnapshot && !context.commandUiSnapshotDirty)
		{
			snapshot.hasCommandUiSnapshot        = true;
			snapshot.commandUiHasView            = context.commandUiSnapshot.hasView;
			snapshot.commandUiHasFrameData       = context.commandUiSnapshotHasFrameData;
			snapshot.commandUiOutputClientHeight = context.commandUiSnapshot.outputClientHeight;
			snapshot.commandUiOutputClientWidth  = context.commandUiSnapshot.outputClientWidth;
			snapshot.commandUiViewHeight         = context.commandUiSnapshot.viewHeight;
			snapshot.commandUiViewWidth          = context.commandUiSnapshot.viewWidth;
			snapshot.commandUiValues             = commandUiValuesFromSnapshot(context.commandUiSnapshot);
			if (!context.hasCommandHistorySnapshot)
				snapshot.commandUiValues.remove(QStringLiteral("commandHistory"));
		}
		else if (!context.commandUiSnapshotDirty && context.miniWindowLookupBaseSnapshot &&
		         context.miniWindowLookupBaseSnapshot->hasCommandUiSnapshot)
		{
			const auto *baseSnapshot             = context.miniWindowLookupBaseSnapshot;
			snapshot.hasCommandUiSnapshot        = true;
			snapshot.commandUiHasView            = baseSnapshot->commandUiHasView;
			snapshot.commandUiHasFrameData       = baseSnapshot->commandUiHasFrameData;
			snapshot.commandUiOutputClientHeight = baseSnapshot->commandUiOutputClientHeight;
			snapshot.commandUiOutputClientWidth  = baseSnapshot->commandUiOutputClientWidth;
			snapshot.commandUiViewHeight         = baseSnapshot->commandUiViewHeight;
			snapshot.commandUiViewWidth          = baseSnapshot->commandUiViewWidth;
			snapshot.commandUiValues             = baseSnapshot->commandUiValues;
			if (context.hasCommandHistorySnapshot)
				snapshot.commandUiValues.insert(QStringLiteral("commandHistory"),
				                                context.commandHistorySnapshot);
		}
		else if (context.commandUiSnapshotDirty)
		{
			snapshot.hasCommandUiSnapshot = false;
			snapshot.commandUiValues.clear();
		}

		if (!context.runtimeCountersSnapshotDirty &&
		    (context.hasRuntimeCountersSnapshot || context.hasRuntimeCountersSnapshotWithStrings))
		{
			const WorldRuntime::RuntimeCountersSnapshot counters =
			    context.hasRuntimeCountersSnapshotWithStrings ? context.runtimeCountersSnapshotWithStrings
			                                                  : context.runtimeCountersSnapshot;
			snapshot.hasRuntimeCountersSnapshot = true;
			snapshot.runtimeOutputFontHeight    = counters.outputFontHeight;
			snapshot.runtimeOutputFontWidth     = counters.outputFontWidth;
			snapshot.runtimeCounterValues       = runtimeCounterValuesFromSnapshot(counters);
		}
		else if (!context.runtimeCountersSnapshotDirty && context.miniWindowLookupBaseSnapshot &&
		         context.miniWindowLookupBaseSnapshot->hasRuntimeCountersSnapshot)
		{
			const auto *baseSnapshot            = context.miniWindowLookupBaseSnapshot;
			snapshot.hasRuntimeCountersSnapshot = true;
			snapshot.runtimeOutputFontHeight    = baseSnapshot->runtimeOutputFontHeight;
			snapshot.runtimeOutputFontWidth     = baseSnapshot->runtimeOutputFontWidth;
			snapshot.runtimeCounterValues       = baseSnapshot->runtimeCounterValues;
		}
		else if (context.runtimeCountersSnapshotDirty)
		{
			snapshot.hasRuntimeCountersSnapshot = false;
			snapshot.runtimeCounterValues.clear();
		}

		if (!context.worldAttributeValuesByKey.isEmpty() ||
		    !context.worldMultilineAttributeValuesByKey.isEmpty())
		{
			snapshot.hasWorldAttributeSnapshot = true;
			for (auto it = context.worldAttributeValuesByKey.constBegin();
			     it != context.worldAttributeValuesByKey.constEnd(); ++it)
			{
				snapshot.worldAttributesSnapshot.insert(it.key(), it.value());
			}
			for (auto it = context.worldMultilineAttributeValuesByKey.constBegin();
			     it != context.worldMultilineAttributeValuesByKey.constEnd(); ++it)
			{
				snapshot.worldMultilineAttributesSnapshot.insert(it.key(), it.value());
			}
		}
		if (context.hasActionSourceOverride)
		{
			snapshot.hasActionSourceOverride = true;
			snapshot.actionSourceOverride    = context.actionSourceOverride;
		}
		if (context.hasGuiSystemValues)
		{
			snapshot.hasUiSnapshot = true;
			for (auto it = context.guiSystemValues.constBegin(); it != context.guiSystemValues.constEnd();
			     ++it)
			{
				snapshot.guiSystemValues.insert(it.key(), it.value());
			}
		}

		if (context.hasWorldVariablesSnapshot)
		{
			snapshot.hasWorldVariablesSnapshot = true;
			snapshot.worldVariablesSnapshot    = context.worldVariablesSnapshot;
		}
		if (!context.boldAnsiColoursByIndex.isEmpty())
			snapshot.boldAnsiColoursByIndex = context.boldAnsiColoursByIndex;
		if (!context.normalAnsiColoursByIndex.isEmpty())
			snapshot.normalAnsiColoursByIndex = context.normalAnsiColoursByIndex;
		if (!context.customBackgroundColoursByIndex.isEmpty())
			snapshot.customBackgroundColoursByIndex = context.customBackgroundColoursByIndex;
		if (!context.customTextColoursByIndex.isEmpty())
			snapshot.customTextColoursByIndex = context.customTextColoursByIndex;
		if (!context.customColourNamesByIndex.isEmpty())
			snapshot.customColourNamesByIndex = context.customColourNamesByIndex;
		if (!context.pluginCallbackPresenceByName.isEmpty())
			snapshot.pluginCallbackPresenceByName = context.pluginCallbackPresenceByName;
		if (!context.entityValuesByName.isEmpty())
		{
			snapshot.hasEntitySnapshot  = true;
			snapshot.entityValuesByName = context.entityValuesByName;
		}
		if (context.hasClipboardText || context.mainWindowPositionsDirty ||
		    !context.mainWindowPositionsByMode.isEmpty() || !context.worldWindowPositionsByKey.isEmpty() ||
		    !context.missingWorldWindowPositionKeys.isEmpty() ||
		    !context.dirtyWorldWindowPositionOrdinals.isEmpty() ||
		    !context.notepadWindowPositionsByKey.isEmpty() ||
		    !context.missingNotepadWindowPositionKeys.isEmpty() ||
		    !context.dirtyNotepadWindowPositionKeys.isEmpty() ||
		    !context.dirtyNotepadDocumentKeys.isEmpty() || !context.notepadLengthByKey.isEmpty() ||
		    !context.missingNotepadLengthKeys.isEmpty() || !context.notepadTextByKey.isEmpty() ||
		    !context.missingNotepadTextKeys.isEmpty() || !context.dirtyNotepadListKeys.isEmpty() ||
		    !context.notepadListByKey.isEmpty() || !context.missingNotepadListKeys.isEmpty())
		{
			snapshot.hasUiSnapshot = true;
			if (context.hasClipboardText)
			{
				snapshot.hasClipboardText = true;
				snapshot.clipboardText    = context.clipboardText;
			}
			if (context.mainWindowPositionsDirty || !context.mainWindowPositionsByMode.isEmpty())
			{
				snapshot.mainWindowPositionsByMode = context.mainWindowPositionsByMode;
				snapshot.mainWindowPositionsDirty  = context.mainWindowPositionsDirty;
			}
			snapshot.worldWindowPositionsByKey        = context.worldWindowPositionsByKey;
			snapshot.missingWorldWindowPositionKeys   = context.missingWorldWindowPositionKeys;
			snapshot.dirtyWorldWindowPositionOrdinals = context.dirtyWorldWindowPositionOrdinals;
			snapshot.notepadWindowPositionsByKey      = context.notepadWindowPositionsByKey;
			snapshot.missingNotepadWindowPositionKeys = context.missingNotepadWindowPositionKeys;
			snapshot.dirtyNotepadWindowPositionKeys   = context.dirtyNotepadWindowPositionKeys;
			snapshot.dirtyNotepadDocumentKeys         = context.dirtyNotepadDocumentKeys;
			snapshot.notepadLengthByKey               = context.notepadLengthByKey;
			snapshot.missingNotepadLengthKeys         = context.missingNotepadLengthKeys;
			snapshot.notepadTextByKey                 = context.notepadTextByKey;
			snapshot.missingNotepadTextKeys           = context.missingNotepadTextKeys;
			snapshot.dirtyNotepadListKeys             = context.dirtyNotepadListKeys;
			snapshot.notepadListByKey                 = context.notepadListByKey;
			snapshot.missingNotepadListKeys           = context.missingNotepadListKeys;
		}
		for (auto it = context.pluginVariablesSnapshotById.constBegin();
		     it != context.pluginVariablesSnapshotById.constEnd(); ++it)
		{
			snapshot.pluginVariablesSnapshotById.insert(it.key(), it.value());
		}
		snapshot.unavailablePluginVariableSnapshotIds.unite(context.unavailablePluginVariableSnapshotIds);

		if (context.hasArrayNameListSnapshot)
		{
			snapshot.hasArraySnapshot   = true;
			snapshot.arrayNamesSnapshot = context.arrayNameListSnapshot;
		}
		for (auto it = context.arraySnapshotsByName.constBegin();
		     it != context.arraySnapshotsByName.constEnd(); ++it)
		{
			snapshot.hasArraySnapshot = true;
			snapshot.arraysByName.insert(it.key(), it.value());
		}
		for (const QString &name : context.missingArraySnapshotNames)
		{
			snapshot.hasArraySnapshot = true;
			snapshot.arraysByName.remove(name);
			snapshot.arrayNamesSnapshot.removeAll(name);
		}

		if (!context.chatConnectionIdsSnapshotDirty && context.hasChatConnectionIdsSnapshot)
		{
			snapshot.hasChatSnapshot           = true;
			snapshot.chatConnectionIdsSnapshot = context.chatConnectionIdsSnapshot;
		}
		else if (context.chatConnectionIdsSnapshotDirty)
		{
			snapshot.hasChatSnapshot = false;
			snapshot.chatConnectionIdsSnapshot.clear();
		}
		for (auto it = context.chatIdsByLookupKey.constBegin(); it != context.chatIdsByLookupKey.constEnd();
		     ++it)
		{
			snapshot.hasChatSnapshot = true;
			snapshot.chatIdsByLookupKey.insert(it.key(), it.value());
		}
		for (auto it = context.chatInfoValuesByKey.constBegin(); it != context.chatInfoValuesByKey.constEnd();
		     ++it)
		{
			const QStringList parts = it.key().split(QLatin1Char('|'));
			if (parts.size() != 2)
				continue;
			bool       ok = false;
			const long id = parts.at(0).toLong(&ok);
			if (!ok)
				continue;
			const int infoType = parts.at(1).toInt(&ok);
			if (!ok)
				continue;
			snapshot.hasChatSnapshot = true;
			snapshot.chatInfoValuesById[id].insert(infoType, it.value());
		}
		for (auto it = context.chatOptionValuesByKey.constBegin();
		     it != context.chatOptionValuesByKey.constEnd(); ++it)
		{
			const QStringList parts = it.key().split(QLatin1Char('|'));
			if (parts.size() != 2)
				continue;
			bool       ok = false;
			const long id = parts.at(0).toLong(&ok);
			if (!ok)
				continue;
			snapshot.hasChatSnapshot = true;
			snapshot.chatOptionValuesById[id].insert(parts.at(1), it.value());
		}

		if (context.hasMapColourListSnapshot)
		{
			snapshot.hasMapColourSnapshot = true;
			snapshot.mapColourSnapshot    = context.mapColourListSnapshot;
		}
		for (auto it = context.mapColoursByOriginal.constBegin();
		     it != context.mapColoursByOriginal.constEnd(); ++it)
		{
			snapshot.hasMapColourSnapshot = true;
			snapshot.mapColourSnapshot.insert(it.key(), it.value());
		}
		if (context.hasMappingEntriesSnapshot)
		{
			snapshot.hasMappingEntriesSnapshot = true;
			snapshot.mappingEntriesSnapshot    = context.mappingEntriesSnapshot;
		}

		if (context.hasUsedUdpPortsSnapshot)
		{
			snapshot.hasUsedUdpPortsSnapshot            = true;
			snapshot.usedUdpPortsSnapshot               = context.usedUdpPortsSnapshot;
			snapshot.usedUdpPortReferenceCountsSnapshot = context.usedUdpPortReferenceCountsSnapshot;
		}
		if (!context.udpPortListByRuntimeKey.isEmpty() || !context.udpListenerPluginIdsByRuntimeKey.isEmpty())
		{
			const QString runtimeKey         = makeCallbackRuntimeKey(runtime);
			QString       fallbackRuntimeKey = runtimeKey;
			if (fallbackRuntimeKey.isEmpty() && context.udpPortListByRuntimeKey.size() == 1)
				fallbackRuntimeKey = context.udpPortListByRuntimeKey.constBegin().key();
			if (fallbackRuntimeKey.isEmpty() && context.udpListenerPluginIdsByRuntimeKey.size() == 1)
				fallbackRuntimeKey = context.udpListenerPluginIdsByRuntimeKey.constBegin().key();
			if (!fallbackRuntimeKey.isEmpty() &&
			    (context.udpPortListByRuntimeKey.contains(fallbackRuntimeKey) ||
			     context.udpListenerPluginIdsByRuntimeKey.contains(fallbackRuntimeKey)))
			{
				snapshot.hasUdpPortSnapshot = true;
				snapshot.udpPortsSnapshot   = context.udpPortListByRuntimeKey.value(fallbackRuntimeKey);
				snapshot.udpListenerPluginIdsByPort =
				    context.udpListenerPluginIdsByRuntimeKey.value(fallbackRuntimeKey);
			}
		}
		if (context.hasMacroEntriesSnapshot)
		{
			snapshot.hasMacroEntriesSnapshot = true;
			snapshot.macroEntriesSnapshot.clear();
			for (const WorldRuntime::Macro &entry : context.macroEntriesSnapshot)
				snapshot.macroEntriesSnapshot.push_back(callbackAttributeChildrenSnapshotFromMacro(entry));
		}
		if (context.hasVariableEntriesSnapshot)
		{
			snapshot.hasVariableEntriesSnapshot = true;
			snapshot.variableEntriesSnapshot.clear();
			for (const WorldRuntime::Variable &entry : context.variableEntriesSnapshot)
				snapshot.variableEntriesSnapshot.push_back(
				    callbackAttributeContentSnapshotFromVariable(entry));
		}
		if (context.hasKeypadEntriesSnapshot)
		{
			snapshot.hasKeypadEntriesSnapshot = true;
			snapshot.keypadEntriesSnapshot.clear();
			for (const WorldRuntime::Keypad &entry : context.keypadEntriesSnapshot)
				snapshot.keypadEntriesSnapshot.push_back(callbackAttributeContentSnapshotFromKeypad(entry));
		}
		if (context.hasAcceleratorSnapshot)
		{
			snapshot.hasAcceleratorSnapshot = true;
			snapshot.acceleratorSnapshot.clear();
			for (const WorldRuntime::AcceleratorSnapshot &entry : context.acceleratorSnapshot)
				snapshot.acceleratorSnapshot.push_back(callbackAcceleratorSnapshotFromRuntimeSnapshot(entry));
		}
		if (context.hasLineBufferSnapshot)
		{
			snapshot.hasLineBufferSnapshot = true;
			snapshot.lineBufferCount       = context.bufferedLineCount;
			snapshot.lineBufferSnapshot    = context.lineBufferSnapshot;
			snapshot.lineEntriesByBufferIndex.clear();
			if (!snapshot.lineBufferSnapshot)
			{
				for (auto it = context.lineEntries.constBegin(); it != context.lineEntries.constEnd(); ++it)
				{
					snapshot.lineEntriesByBufferIndex.insert(it.key(),
					                                         callbackSnapshotFromLineEntry(it.value()));
				}
			}
		}
		if (context.hasLineBufferMutationSnapshot)
		{
			snapshot.hasLineBufferDeltaSnapshot = true;
			if (context.hasLineBufferCountMutation)
			{
				snapshot.hasLineBufferCountDelta = true;
				snapshot.lineBufferDeltaCount    = context.bufferedLineCount;
			}
			for (const int lineNumber : context.mutatedLineEntries)
			{
				snapshot.lineEntryDeltasByBufferIndex.remove(lineNumber);
				snapshot.missingLineEntryDeltasByBufferIndex.remove(lineNumber);
				if (context.lineEntries.contains(lineNumber))
				{
					snapshot.lineEntryDeltasByBufferIndex.insert(
					    lineNumber, callbackSnapshotFromLineEntry(context.lineEntries.value(lineNumber)));
				}
				else if (context.missingLineEntries.contains(lineNumber))
				{
					snapshot.missingLineEntryDeltasByBufferIndex.insert(lineNumber);
				}
			}
		}
		if (context.hasRecentLinesSnapshot)
		{
			snapshot.hasRecentLinesSnapshot = true;
			snapshot.recentLinesSnapshot    = context.recentLinesSnapshot;
		}
		for (auto it = context.soundStatusByBuffer.constBegin(); it != context.soundStatusByBuffer.constEnd();
		     ++it)
		{
			snapshot.soundStatusByBuffer.insert(it.key(), it.value());
		}

		overlayCallbackDatabaseCachesForCallPlugin(context, snapshot);
		overlayCallbackPluginMetadataForCallPlugin(context, snapshot);
	}

	bool callbackSnapshotHasDatabasePayload(const LuaCallbackMiniWindowSnapshot &snapshot)
	{
		return snapshot.databaseListSnapshotDirty || snapshot.hasDatabaseListSnapshot ||
		       !snapshot.databaseNamesSnapshot.isEmpty() || snapshot.hasDatabaseSnapshot ||
		       !snapshot.databaseSnapshotsByName.isEmpty() || !snapshot.databaseColumnsByName.isEmpty() ||
		       !snapshot.databaseErrorsByName.isEmpty() || !snapshot.databaseColumnNamesByKey.isEmpty() ||
		       !snapshot.missingDatabaseColumnNameKeys.isEmpty() ||
		       !snapshot.databaseColumnTextByKey.isEmpty() ||
		       !snapshot.missingDatabaseColumnTextKeys.isEmpty() ||
		       !snapshot.databaseColumnValuesByKey.isEmpty() ||
		       !snapshot.missingDatabaseColumnValueKeys.isEmpty() ||
		       !snapshot.databaseColumnTypesByKey.isEmpty() || !snapshot.databaseInfoByKey.isEmpty() ||
		       !snapshot.missingDatabaseInfoKeys.isEmpty() || !snapshot.databaseColumnNamesByName.isEmpty() ||
		       !snapshot.missingDatabaseColumnNamesByName.isEmpty() ||
		       !snapshot.databaseColumnValuesByName.isEmpty() ||
		       !snapshot.missingDatabaseColumnValuesByName.isEmpty() ||
		       !snapshot.databaseTotalChangesByName.isEmpty() || !snapshot.databaseChangesByName.isEmpty() ||
		       !snapshot.databaseLastInsertRowidByName.isEmpty();
	}

	bool callbackSnapshotHasPayload(const LuaCallbackMiniWindowSnapshot &snapshot)
	{
		return !snapshot.windowNames.isEmpty() || !snapshot.fontIdsByWindow.isEmpty() ||
		       !snapshot.imageIdsByWindow.isEmpty() || !snapshot.hotspotIdsByWindow.isEmpty() ||
		       !snapshot.imageHasAlphaByKey.isEmpty() || !snapshot.windowInfoByWindow.isEmpty() ||
		       !snapshot.miniWindowsByWindow.isEmpty() || snapshot.hasFramePointer ||
		       snapshot.hasCommandUiSnapshot || !snapshot.commandUiValues.isEmpty() ||
		       snapshot.hasRuntimeCountersSnapshot || !snapshot.runtimeCounterValues.isEmpty() ||
		       snapshot.hasWorldVariablesSnapshot || !snapshot.worldVariablesSnapshot.isEmpty() ||
		       !snapshot.pluginVariablesSnapshotById.isEmpty() ||
		       !snapshot.unavailablePluginVariableSnapshotIds.isEmpty() ||
		       !snapshot.triggerListsByPluginId.isEmpty() ||
		       !snapshot.missingTriggerListPluginIds.isEmpty() || !snapshot.aliasListsByPluginId.isEmpty() ||
		       !snapshot.missingAliasListPluginIds.isEmpty() || !snapshot.timerListsByPluginId.isEmpty() ||
		       !snapshot.missingTimerListPluginIds.isEmpty() || snapshot.hasWorldAttributeSnapshot ||
		       !snapshot.worldAttributesSnapshot.isEmpty() ||
		       !snapshot.worldMultilineAttributesSnapshot.isEmpty() || snapshot.hasArraySnapshot ||
		       !snapshot.arrayNamesSnapshot.isEmpty() || !snapshot.arraysByName.isEmpty() ||
		       snapshot.hasChatSnapshot || !snapshot.chatConnectionIdsSnapshot.isEmpty() ||
		       !snapshot.chatInfoValuesById.isEmpty() || !snapshot.chatOptionValuesById.isEmpty() ||
		       !snapshot.chatIdsByLookupKey.isEmpty() || snapshot.hasWindowOutputTextRenderSnapshot ||
		       !snapshot.windowOutputTextMxpStyleStack.isEmpty() ||
		       !snapshot.windowOutputTextMxpBlockStack.isEmpty() ||
		       !snapshot.windowOutputTextCustomElements.isEmpty() ||
		       !snapshot.boldAnsiColoursByIndex.isEmpty() || !snapshot.normalAnsiColoursByIndex.isEmpty() ||
		       !snapshot.customTextColoursByIndex.isEmpty() ||
		       !snapshot.customBackgroundColoursByIndex.isEmpty() ||
		       !snapshot.customColourNamesByIndex.isEmpty() || !snapshot.triggerWildcardsSnapshot.isEmpty() ||
		       !snapshot.triggerNamedWildcardsSnapshot.isEmpty() ||
		       !snapshot.aliasWildcardsSnapshot.isEmpty() ||
		       !snapshot.aliasNamedWildcardsSnapshot.isEmpty() ||
		       !snapshot.pluginTriggerWildcardsSnapshotById.isEmpty() ||
		       !snapshot.pluginTriggerNamedWildcardsSnapshotById.isEmpty() ||
		       !snapshot.pluginAliasWildcardsSnapshotById.isEmpty() ||
		       !snapshot.pluginAliasNamedWildcardsSnapshotById.isEmpty() || snapshot.hasMapColourSnapshot ||
		       !snapshot.mapColourSnapshot.isEmpty() || snapshot.hasMappingEntriesSnapshot ||
		       !snapshot.mappingEntriesSnapshot.isEmpty() || snapshot.hasUdpPortSnapshot ||
		       !snapshot.udpPortsSnapshot.isEmpty() || !snapshot.udpListenerPluginIdsByPort.isEmpty() ||
		       snapshot.hasUsedUdpPortsSnapshot || !snapshot.usedUdpPortsSnapshot.isEmpty() ||
		       !snapshot.usedUdpPortReferenceCountsSnapshot.isEmpty() ||
		       !snapshot.soundStatusByBuffer.isEmpty() || snapshot.hasLineBufferSnapshot ||
		       !snapshot.lineEntriesByBufferIndex.isEmpty() || snapshot.hasCallbackOutputAnchor ||
		       snapshot.hasLineBufferDeltaSnapshot || snapshot.hasLineBufferCountDelta ||
		       !snapshot.lineEntryDeltasByBufferIndex.isEmpty() ||
		       !snapshot.missingLineEntryDeltasByBufferIndex.isEmpty() || snapshot.hasRecentLinesSnapshot ||
		       !snapshot.recentLinesSnapshot.isEmpty() || callbackSnapshotHasDatabasePayload(snapshot) ||
		       snapshot.hasMacroEntriesSnapshot || !snapshot.macroEntriesSnapshot.isEmpty() ||
		       snapshot.hasVariableEntriesSnapshot || !snapshot.variableEntriesSnapshot.isEmpty() ||
		       snapshot.hasKeypadEntriesSnapshot || !snapshot.keypadEntriesSnapshot.isEmpty() ||
		       snapshot.hasAcceleratorSnapshot || !snapshot.acceleratorSnapshot.isEmpty() ||
		       snapshot.hasActionSourceOverride || !snapshot.pluginNamesById.isEmpty() ||
		       !snapshot.pluginDirectoriesById.isEmpty() || !snapshot.pluginEnabledById.isEmpty() ||
		       !snapshot.pluginEnginesById.isEmpty() || !snapshot.pluginIdsSnapshot.isEmpty() ||
		       snapshot.hasBroadcastPluginSnapshot || !snapshot.broadcastPluginIdsSnapshot.isEmpty() ||
		       !snapshot.broadcastPluginEnginesSnapshot.isEmpty() ||
		       !snapshot.pluginIdsByLookupKey.isEmpty() || !snapshot.pluginInfoValuesById.isEmpty() ||
		       !snapshot.pluginCallbackPresenceByName.isEmpty() || snapshot.hasEntitySnapshot ||
		       !snapshot.entityValuesByName.isEmpty() || snapshot.hasUiSnapshot ||
		       !snapshot.guiSystemValues.isEmpty() || snapshot.hasClipboardText ||
		       !snapshot.mainWindowPositionsByMode.isEmpty() || snapshot.mainWindowPositionsDirty ||
		       !snapshot.worldWindowPositionsByKey.isEmpty() ||
		       !snapshot.missingWorldWindowPositionKeys.isEmpty() ||
		       !snapshot.dirtyWorldWindowPositionOrdinals.isEmpty() ||
		       !snapshot.notepadWindowPositionsByKey.isEmpty() ||
		       !snapshot.missingNotepadWindowPositionKeys.isEmpty() ||
		       !snapshot.dirtyNotepadWindowPositionKeys.isEmpty() ||
		       !snapshot.dirtyNotepadDocumentKeys.isEmpty() || !snapshot.notepadLengthByKey.isEmpty() ||
		       !snapshot.missingNotepadLengthKeys.isEmpty() || !snapshot.notepadTextByKey.isEmpty() ||
		       !snapshot.missingNotepadTextKeys.isEmpty() || !snapshot.dirtyNotepadListKeys.isEmpty() ||
		       !snapshot.notepadListByKey.isEmpty() || !snapshot.missingNotepadListKeys.isEmpty() ||
		       !snapshot.worldRuntimeSnapshot.isEmpty() || !snapshot.worldWindowPositionSnapshot.isEmpty() ||
		       !snapshot.notepadSnapshot.isEmpty();
	}

	CallbackDispatchSnapshot buildActiveCallbackDispatchSnapshot(const LuaCallbackEngine *engine,
	                                                             WorldRuntime            *runtime)
	{
		CallbackDispatchSnapshot result;
		const auto              *context = activeCallbackContextConst(engine);
		if (!context)
			return result;

		auto snapshot               = QSharedPointer<LuaCallbackMiniWindowSnapshot>::create();
		bool copiedDispatchSnapshot = false;
		if (engine)
		{
			if (const auto *dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot(); dispatchSnapshot)
			{
				*snapshot              = *dispatchSnapshot;
				copiedDispatchSnapshot = true;
			}
		}
		if (!copiedDispatchSnapshot && context->miniWindowLookupBaseSnapshot)
			*snapshot = *context->miniWindowLookupBaseSnapshot;
		if (context->hasCallbackOutputAnchor)
		{
			snapshot->hasCallbackOutputAnchor         = true;
			snapshot->callbackOutputAnchorBufferIndex = context->callbackOutputAnchorBufferIndexAtDispatch;
			snapshot->callbackOutputAnchorAbsoluteNumber =
			    context->callbackOutputAnchorAbsoluteNumberAtDispatch;
		}

		const auto appendUniqueCaseInsensitive = [](QStringList &list, const QString &value)
		{
			if (value.trimmed().isEmpty())
				return;
			if (!std::ranges::any_of(list, [&value](const QString &item)
			                         { return item.compare(value, Qt::CaseInsensitive) == 0; }))
			{
				list.push_back(value);
			}
		};
		const auto removeCaseInsensitive = [](QStringList &list, const QString &value)
		{
			const QString normalized = value.trimmed();
			if (normalized.isEmpty())
				return;
			const auto removed = std::ranges::remove_if(
			    list, [&normalized](const QString &item)
			    { return item.trimmed().compare(normalized, Qt::CaseInsensitive) == 0; });
			list.erase(removed.begin(), removed.end());
		};

		if (context->hasMiniWindowListSnapshot)
			snapshot->windowNames = context->miniWindowListSnapshot;
		for (const QString &windowId : context->existingMiniWindowIds)
			appendUniqueCaseInsensitive(snapshot->windowNames, windowId);
		for (const QString &windowId : context->missingMiniWindowIds)
		{
			const QString windowKey = windowId.trimmed().toLower();
			if (windowKey.isEmpty())
				continue;
			removeCaseInsensitive(snapshot->windowNames, windowKey);
			snapshot->miniWindowsByWindow.remove(windowKey);
			snapshot->windowInfoByWindow.remove(windowKey);
			snapshot->fontIdsByWindow.remove(windowKey);
			snapshot->imageIdsByWindow.remove(windowKey);
			snapshot->hotspotIdsByWindow.remove(windowKey);
			for (auto alphaIt = snapshot->imageHasAlphaByKey.begin();
			     alphaIt != snapshot->imageHasAlphaByKey.end();)
			{
				if (alphaIt.key().startsWith(windowKey + QLatin1Char('|')))
					alphaIt = snapshot->imageHasAlphaByKey.erase(alphaIt);
				else
					++alphaIt;
			}
		}
		for (auto it = context->miniWindowShadowByWindow.constBegin();
		     it != context->miniWindowShadowByWindow.constEnd(); ++it)
		{
			const QString windowKey = it.key().trimmed().toLower();
			if (windowKey.isEmpty() || context->missingMiniWindowIds.contains(windowKey))
				continue;
			const MiniWindow &window = it.value();
			snapshot->miniWindowsByWindow.insert(windowKey, QSharedPointer<MiniWindow>::create(window));
			snapshot->fontIdsByWindow.insert(windowKey, window.fonts.keys());
			snapshot->imageIdsByWindow.insert(windowKey, window.images.keys());
			snapshot->hotspotIdsByWindow.insert(windowKey, window.hotspots.keys());
			for (auto imageIt = window.images.constBegin(); imageIt != window.images.constEnd(); ++imageIt)
			{
				const QString imageKey = imageIt.key().trimmed().toLower();
				if (!imageKey.isEmpty())
					snapshot->imageHasAlphaByKey.insert(callbackMiniWindowImageKey(windowKey, imageKey),
					                                    imageIt.value().hasAlpha);
			}
			snapshot->windowInfoByWindow.insert(windowKey, miniWindowInfoSnapshotFromWindow(window));
			appendUniqueCaseInsensitive(snapshot->windowNames,
			                            window.name.isEmpty() ? windowKey : window.name);
		}
		for (auto it = context->miniWindowFontListByWindow.constBegin();
		     it != context->miniWindowFontListByWindow.constEnd(); ++it)
		{
			snapshot->fontIdsByWindow.insert(it.key(), it.value());
			appendUniqueCaseInsensitive(snapshot->windowNames, it.key());
		}
		for (auto it = context->miniWindowImageListByWindow.constBegin();
		     it != context->miniWindowImageListByWindow.constEnd(); ++it)
		{
			snapshot->imageIdsByWindow.insert(it.key(), it.value());
			appendUniqueCaseInsensitive(snapshot->windowNames, it.key());
		}
		for (auto it = context->miniWindowHotspotListByWindow.constBegin();
		     it != context->miniWindowHotspotListByWindow.constEnd(); ++it)
		{
			snapshot->hotspotIdsByWindow.insert(it.key(), it.value());
			appendUniqueCaseInsensitive(snapshot->windowNames, it.key());
		}
		for (auto it = context->miniWindowImageHasAlphaByKey.constBegin();
		     it != context->miniWindowImageHasAlphaByKey.constEnd(); ++it)
		{
			snapshot->imageHasAlphaByKey.insert(it.key(), it.value());
		}
		if (context->hasFramePointer)
		{
			snapshot->framePointer    = context->framePointer;
			snapshot->hasFramePointer = true;
		}
		for (const QString &key : context->existingMiniWindowFonts)
		{
			QString windowKey;
			QString fontId;
			if (!decodeCallbackMiniWindowItemKey(key, windowKey, fontId))
				continue;
			QStringList &fontIds = snapshot->fontIdsByWindow[windowKey];
			appendUniqueCaseInsensitive(fontIds, fontId);
			appendUniqueCaseInsensitive(snapshot->windowNames, windowKey);
		}
		for (const QString &key : context->missingMiniWindowFonts)
		{
			QString windowKey;
			QString fontId;
			if (!decodeCallbackMiniWindowItemKey(key, windowKey, fontId))
				continue;
			if (auto it = snapshot->fontIdsByWindow.find(windowKey); it != snapshot->fontIdsByWindow.end())
				removeCaseInsensitive(it.value(), fontId);
		}
		for (const QString &key : context->existingMiniWindowImages)
		{
			QString windowKey;
			QString imageId;
			if (!decodeCallbackMiniWindowItemKey(key, windowKey, imageId))
				continue;
			QStringList &imageIds = snapshot->imageIdsByWindow[windowKey];
			appendUniqueCaseInsensitive(imageIds, imageId);
			appendUniqueCaseInsensitive(snapshot->windowNames, windowKey);
		}
		for (const QString &key : context->missingMiniWindowImages)
		{
			QString windowKey;
			QString imageId;
			if (!decodeCallbackMiniWindowItemKey(key, windowKey, imageId))
				continue;
			if (auto imageIt = snapshot->imageIdsByWindow.find(windowKey);
			    imageIt != snapshot->imageIdsByWindow.end())
				removeCaseInsensitive(imageIt.value(), imageId);
			snapshot->imageHasAlphaByKey.remove(callbackMiniWindowImageKey(windowKey, imageId));
		}
		for (const QString &key : context->existingMiniWindowHotspots)
		{
			QString windowKey;
			QString hotspotId;
			if (!decodeCallbackMiniWindowItemKey(key, windowKey, hotspotId))
				continue;
			QStringList &hotspotIds = snapshot->hotspotIdsByWindow[windowKey];
			appendUniqueCaseInsensitive(hotspotIds, hotspotId);
			appendUniqueCaseInsensitive(snapshot->windowNames, windowKey);
		}
		for (const QString &key : context->missingMiniWindowHotspots)
		{
			QString windowKey;
			QString hotspotId;
			if (!decodeCallbackMiniWindowItemKey(key, windowKey, hotspotId))
				continue;
			if (auto it = snapshot->hotspotIdsByWindow.find(windowKey);
			    it != snapshot->hotspotIdsByWindow.end())
				removeCaseInsensitive(it.value(), hotspotId);
		}
		buildMiniWindowInfoSnapshotFromCallbackContext(*context, *snapshot);
		overlayCallbackContextSnapshotsForCallPlugin(*context, *snapshot, runtime);
		snapshot->rebuildMiniWindowLookupCaches();
		result.miniWindowNames = snapshot->windowNames;
		if (callbackSnapshotHasPayload(*snapshot))
			result.snapshot = snapshot;
		return result;
	}

	void seedCallbackMiniWindowSnapshot(const LuaCallbackEngine             *engine,
	                                    const LuaCallbackMiniWindowSnapshot *snapshot)
	{
		if (!engine || !snapshot)
			return;
		auto *context = activeCallbackContext(engine);
		if (!context)
			return;

		context->miniWindowListSnapshot.clear();
		context->hasMiniWindowListSnapshot    = false;
		context->miniWindowLookupBaseSnapshot = snapshot;
		context->existingMiniWindowIds.clear();
		context->missingMiniWindowIds.clear();
		if (!snapshot->miniWindowLookupCacheValid)
		{
			for (const QString &windowName : snapshot->windowNames)
			{
				const QString windowKey = windowName.trimmed().toLower();
				if (windowKey.isEmpty())
					continue;
				context->existingMiniWindowIds.insert(windowKey);
			}
		}

		context->miniWindowFontListByWindow.clear();
		context->miniWindowImageListByWindow.clear();
		context->miniWindowHotspotListByWindow.clear();
		context->existingMiniWindowFonts.clear();
		context->missingMiniWindowFonts.clear();
		if (!snapshot->miniWindowLookupCacheValid)
		{
			for (auto it = snapshot->fontIdsByWindow.constBegin(); it != snapshot->fontIdsByWindow.constEnd();
			     ++it)
			{
				const QString windowKey = it.key().trimmed().toLower();
				if (windowKey.isEmpty())
					continue;
				for (const QString &fontId : it.value())
				{
					const QString key = callbackMiniWindowFontKey(windowKey, fontId);
					if (key == QStringLiteral("|"))
						continue;
					context->existingMiniWindowFonts.insert(key);
				}
			}
		}

		context->existingMiniWindowImages.clear();
		context->missingMiniWindowImages.clear();
		if (!snapshot->miniWindowLookupCacheValid)
		{
			for (auto it = snapshot->imageIdsByWindow.constBegin();
			     it != snapshot->imageIdsByWindow.constEnd(); ++it)
			{
				const QString windowKey = it.key().trimmed().toLower();
				if (windowKey.isEmpty())
					continue;
				for (const QString &imageId : it.value())
				{
					const QString key = callbackMiniWindowImageKey(windowKey, imageId);
					if (key == QStringLiteral("|"))
						continue;
					context->existingMiniWindowImages.insert(key);
				}
			}
		}

		context->existingMiniWindowHotspots.clear();
		context->missingMiniWindowHotspots.clear();
		if (!snapshot->miniWindowLookupCacheValid)
		{
			for (auto it = snapshot->hotspotIdsByWindow.constBegin();
			     it != snapshot->hotspotIdsByWindow.constEnd(); ++it)
			{
				const QString windowKey = it.key().trimmed().toLower();
				if (windowKey.isEmpty())
					continue;
				for (const QString &hotspotId : it.value())
				{
					const QString key = callbackMiniWindowHotspotKey(windowKey, hotspotId);
					if (key == QStringLiteral("|"))
						continue;
					context->existingMiniWindowHotspots.insert(key);
				}
			}
		}

		context->miniWindowImageHasAlphaByKey = snapshot->imageHasAlphaByKey;
		if (snapshot->hasFramePointer)
			cacheCallbackFrame(engine, static_cast<MainWindow *>(snapshot->framePointer));
		context->triggerWildcardsSnapshot                = snapshot->triggerWildcardsSnapshot;
		context->triggerNamedWildcardsSnapshot           = snapshot->triggerNamedWildcardsSnapshot;
		context->aliasWildcardsSnapshot                  = snapshot->aliasWildcardsSnapshot;
		context->aliasNamedWildcardsSnapshot             = snapshot->aliasNamedWildcardsSnapshot;
		context->pluginTriggerWildcardsSnapshotById      = snapshot->pluginTriggerWildcardsSnapshotById;
		context->pluginTriggerNamedWildcardsSnapshotById = snapshot->pluginTriggerNamedWildcardsSnapshotById;
		context->pluginAliasWildcardsSnapshotById        = snapshot->pluginAliasWildcardsSnapshotById;
		context->pluginAliasNamedWildcardsSnapshotById   = snapshot->pluginAliasNamedWildcardsSnapshotById;
		context->miniWindowShadowByWindow.clear();

		context->miniWindowInfoByKey.clear();

		context->commandUiSnapshot    = {};
		context->hasCommandUiSnapshot = false;
		context->commandUiSnapshotHasFrameData =
		    snapshot->hasCommandUiSnapshot && snapshot->commandUiHasFrameData;
		context->commandUiSnapshotDirty = false;
		context->commandHistorySnapshot.clear();
		context->hasCommandHistorySnapshot = false;

		context->runtimeCountersSnapshot               = {};
		context->hasRuntimeCountersSnapshot            = false;
		context->runtimeCountersSnapshotWithStrings    = {};
		context->hasRuntimeCountersSnapshotWithStrings = false;
		context->runtimeCountersSnapshotDirty          = false;

		if (snapshot->hasWorldVariablesSnapshot)
		{
			context->worldVariablesSnapshot    = snapshot->worldVariablesSnapshot;
			context->hasWorldVariablesSnapshot = true;
		}
		context->pluginVariablesSnapshotById          = snapshot->pluginVariablesSnapshotById;
		context->unavailablePluginVariableSnapshotIds = snapshot->unavailablePluginVariableSnapshotIds;
		context->triggerListsByPluginId.clear();
		for (auto it = snapshot->triggerListsByPluginId.constBegin();
		     it != snapshot->triggerListsByPluginId.constEnd(); ++it)
		{
			context->triggerListsByPluginId.insert(it.key(), triggersFromCallbackSnapshots(it.value()));
		}
		context->missingTriggerListPluginIds = snapshot->missingTriggerListPluginIds;
		context->aliasListsByPluginId.clear();
		for (auto it = snapshot->aliasListsByPluginId.constBegin();
		     it != snapshot->aliasListsByPluginId.constEnd(); ++it)
		{
			context->aliasListsByPluginId.insert(it.key(), aliasesFromCallbackSnapshots(it.value()));
		}
		context->missingAliasListPluginIds = snapshot->missingAliasListPluginIds;
		context->timerListsByPluginId.clear();
		for (auto it = snapshot->timerListsByPluginId.constBegin();
		     it != snapshot->timerListsByPluginId.constEnd(); ++it)
		{
			context->timerListsByPluginId.insert(it.key(), timersFromCallbackSnapshots(it.value()));
		}
		context->missingTimerListPluginIds = snapshot->missingTimerListPluginIds;

		if (snapshot->hasLineBufferSnapshot)
		{
			context->lineBufferSnapshot = snapshot->lineBufferSnapshot;
			context->lineEntries.clear();
			context->missingLineEntries.clear();
			if (snapshot->lineBufferSnapshot)
			{
				context->bufferedLineCount     = snapshot->lineBufferSnapshot->lineBufferCount;
				context->hasBufferedLineCount  = true;
				context->hasLineBufferSnapshot = true;
			}
			else
			{
				for (auto it = snapshot->lineEntriesByBufferIndex.constBegin();
				     it != snapshot->lineEntriesByBufferIndex.constEnd(); ++it)
				{
					context->lineEntries.insert(it.key(), lineEntryFromCallbackSnapshot(it.value()));
				}
				context->bufferedLineCount     = snapshot->lineBufferCount;
				context->hasBufferedLineCount  = true;
				context->hasLineBufferSnapshot = true;
			}
		}
		if (snapshot->hasCallbackOutputAnchor)
		{
			context->hasCallbackOutputAnchor                   = true;
			context->callbackOutputAnchorBufferIndexAtDispatch = snapshot->callbackOutputAnchorBufferIndex;
			context->callbackOutputAnchorAbsoluteNumberAtDispatch =
			    snapshot->callbackOutputAnchorAbsoluteNumber;
		}
		if (snapshot->hasLineBufferDeltaSnapshot)
		{
			if (snapshot->hasLineBufferCountDelta)
			{
				const int oldLineCount     = context->hasBufferedLineCount ? context->bufferedLineCount
				                                                           : snapshot->lineBufferDeltaCount;
				context->bufferedLineCount = qMax(0, snapshot->lineBufferDeltaCount);
				context->hasBufferedLineCount = true;
				for (int lineNumber = context->bufferedLineCount + 1; lineNumber <= oldLineCount;
				     ++lineNumber)
				{
					context->lineEntries.remove(lineNumber);
					context->missingLineEntries.insert(lineNumber);
				}
			}
			for (const int lineNumber : snapshot->missingLineEntryDeltasByBufferIndex)
			{
				context->lineEntries.remove(lineNumber);
				context->missingLineEntries.insert(lineNumber);
			}
			for (auto it = snapshot->lineEntryDeltasByBufferIndex.constBegin();
			     it != snapshot->lineEntryDeltasByBufferIndex.constEnd(); ++it)
			{
				context->missingLineEntries.remove(it.key());
				context->lineEntries.insert(it.key(), lineEntryFromCallbackSnapshot(it.value()));
			}
		}
		if (snapshot->hasRecentLinesSnapshot)
		{
			context->recentLinesSnapshot    = snapshot->recentLinesSnapshot;
			context->hasRecentLinesSnapshot = true;
			context->recentLinesByCount.clear();
		}
		if (snapshot->databaseListSnapshotDirty)
		{
			context->databaseListSnapshot.clear();
			context->hasDatabaseListSnapshot   = false;
			context->databaseListSnapshotDirty = true;
		}
		else if (snapshot->hasDatabaseListSnapshot || snapshot->hasDatabaseSnapshot)
		{
			context->databaseListSnapshot      = snapshot->databaseNamesSnapshot;
			context->hasDatabaseListSnapshot   = true;
			context->databaseListSnapshotDirty = false;
		}
		if (snapshot->hasDatabaseSnapshot)
		{
			context->databaseSnapshotsByName = snapshot->databaseSnapshotsByName;
			context->hasDatabaseSnapshot     = true;
			context->dirtyDatabaseSnapshotNames.clear();
		}
		context->databaseColumnsByName             = snapshot->databaseColumnsByName;
		context->databaseErrorsByName              = snapshot->databaseErrorsByName;
		context->databaseColumnNamesByKey          = snapshot->databaseColumnNamesByKey;
		context->missingDatabaseColumnNameKeys     = snapshot->missingDatabaseColumnNameKeys;
		context->databaseColumnTextByKey           = snapshot->databaseColumnTextByKey;
		context->missingDatabaseColumnTextKeys     = snapshot->missingDatabaseColumnTextKeys;
		context->databaseColumnValuesByKey         = snapshot->databaseColumnValuesByKey;
		context->missingDatabaseColumnValueKeys    = snapshot->missingDatabaseColumnValueKeys;
		context->databaseColumnTypesByKey          = snapshot->databaseColumnTypesByKey;
		context->databaseInfoByKey                 = snapshot->databaseInfoByKey;
		context->missingDatabaseInfoKeys           = snapshot->missingDatabaseInfoKeys;
		context->databaseColumnNamesByName         = snapshot->databaseColumnNamesByName;
		context->missingDatabaseColumnNamesByName  = snapshot->missingDatabaseColumnNamesByName;
		context->databaseColumnValuesByName        = snapshot->databaseColumnValuesByName;
		context->missingDatabaseColumnValuesByName = snapshot->missingDatabaseColumnValuesByName;
		context->databaseTotalChangesByName        = snapshot->databaseTotalChangesByName;
		context->databaseChangesByName             = snapshot->databaseChangesByName;
		context->databaseLastInsertRowidByName     = snapshot->databaseLastInsertRowidByName;
		if (snapshot->hasUdpPortSnapshot)
		{
			const QString runtimeKey = makeCallbackRuntimeKey(engine->worldRuntimeForBridgedCall());
			if (!runtimeKey.isEmpty())
			{
				context->udpPortListByRuntimeKey.insert(runtimeKey, snapshot->udpPortsSnapshot);
				context->udpListenerPluginIdsByRuntimeKey.insert(runtimeKey,
				                                                 snapshot->udpListenerPluginIdsByPort);
			}
		}
		if (snapshot->hasUsedUdpPortsSnapshot)
		{
			context->usedUdpPortsSnapshot               = snapshot->usedUdpPortsSnapshot;
			context->usedUdpPortReferenceCountsSnapshot = snapshot->usedUdpPortReferenceCountsSnapshot;
			context->hasUsedUdpPortsSnapshot            = true;
		}
		for (auto it = snapshot->pluginCallbackPresenceByName.constBegin();
		     it != snapshot->pluginCallbackPresenceByName.constEnd(); ++it)
		{
			context->pluginCallbackPresenceByName.insert(it.key(), it.value());
		}
		if (snapshot->hasEntitySnapshot)
		{
			for (auto it = snapshot->entityValuesByName.constBegin();
			     it != snapshot->entityValuesByName.constEnd(); ++it)
			{
				cacheCallbackEntityValue(engine, it.key(), it.value());
			}
		}
		if (snapshot->hasUiSnapshot)
		{
			if (!snapshot->guiSystemValues.isEmpty())
			{
				context->guiSystemValues    = snapshot->guiSystemValues;
				context->hasGuiSystemValues = true;
			}
			if (snapshot->hasClipboardText)
				cacheCallbackClipboardText(engine, snapshot->clipboardText);
			context->mainWindowPositionsDirty = snapshot->mainWindowPositionsDirty;
			for (auto it = snapshot->mainWindowPositionsByMode.constBegin();
			     it != snapshot->mainWindowPositionsByMode.constEnd(); ++it)
			{
				cacheCallbackMainWindowPosition(engine, it.key() != 0, it.value());
			}
			context->mainWindowPositionsDirty         = snapshot->mainWindowPositionsDirty;
			context->worldWindowPositionsByKey        = snapshot->worldWindowPositionsByKey;
			context->missingWorldWindowPositionKeys   = snapshot->missingWorldWindowPositionKeys;
			context->dirtyWorldWindowPositionOrdinals = snapshot->dirtyWorldWindowPositionOrdinals;
			context->notepadWindowPositionsByKey      = snapshot->notepadWindowPositionsByKey;
			context->missingNotepadWindowPositionKeys = snapshot->missingNotepadWindowPositionKeys;
			context->dirtyNotepadWindowPositionKeys   = snapshot->dirtyNotepadWindowPositionKeys;
			context->dirtyNotepadDocumentKeys         = snapshot->dirtyNotepadDocumentKeys;
			context->notepadLengthByKey               = snapshot->notepadLengthByKey;
			context->missingNotepadLengthKeys         = snapshot->missingNotepadLengthKeys;
			context->notepadTextByKey                 = snapshot->notepadTextByKey;
			context->missingNotepadTextKeys           = snapshot->missingNotepadTextKeys;
			context->dirtyNotepadListKeys             = snapshot->dirtyNotepadListKeys;
			context->notepadListByKey                 = snapshot->notepadListByKey;
			context->missingNotepadListKeys           = snapshot->missingNotepadListKeys;
		}
		if (snapshot->hasActionSourceOverride)
		{
			context->actionSourceOverride    = snapshot->actionSourceOverride;
			context->hasActionSourceOverride = true;
		}
	}

	void seedCallbackMiniWindowExistsSnapshot(const LuaCallbackEngine *engine, const QStringList &windowNames)
	{
		if (!engine)
			return;
		auto *context = activeCallbackContext(engine);
		if (!context)
			return;
		context->miniWindowLookupBaseSnapshot = nullptr;
		context->existingMiniWindowIds.clear();
		context->missingMiniWindowIds.clear();
		for (const QString &windowName : windowNames)
		{
			const QString key = windowName.trimmed().toLower();
			if (!key.isEmpty())
				context->existingMiniWindowIds.insert(key);
		}
	}

	bool tryBackfillCallbackVariableSnapshotFromDispatch(const LuaCallbackEngine *engine,
	                                                     const QString           &pluginId,
	                                                     QMap<QString, QString>  &values,
	                                                     bool                    &pluginAvailable)
	{
		auto *context = activeCallbackContext(engine);
		if (!context || !engine)
			return false;
		const auto *snapshot = engine->currentDispatchMiniWindowSnapshot();
		if (!snapshot)
			return false;

		if (pluginId.isEmpty())
		{
			if (!context->hasWorldVariablesSnapshot && snapshot->hasWorldVariablesSnapshot)
			{
				context->worldVariablesSnapshot    = snapshot->worldVariablesSnapshot;
				context->hasWorldVariablesSnapshot = true;
			}
			if (!context->hasWorldVariablesSnapshot)
				return false;
			values          = context->worldVariablesSnapshot;
			pluginAvailable = true;
			return true;
		}

		const QString pluginKey = pluginId.trimmed().toLower();
		if (pluginKey.isEmpty())
			return false;
		if (context->unavailablePluginVariableSnapshotIds.contains(pluginKey))
		{
			values.clear();
			pluginAvailable = false;
			return true;
		}
		if (const auto cachedIt = context->pluginVariablesSnapshotById.constFind(pluginKey);
		    cachedIt != context->pluginVariablesSnapshotById.constEnd())
		{
			values          = cachedIt.value();
			pluginAvailable = true;
			return true;
		}
		const auto snapshotIt = snapshot->pluginVariablesSnapshotById.constFind(pluginKey);
		if (snapshotIt == snapshot->pluginVariablesSnapshotById.constEnd())
			return false;
		context->pluginVariablesSnapshotById.insert(pluginKey, snapshotIt.value());
		context->unavailablePluginVariableSnapshotIds.remove(pluginKey);
		values          = snapshotIt.value();
		pluginAvailable = true;
		return true;
	}

	bool tryBackfillCallbackCommandUiSnapshotFromDispatch(const LuaCallbackEngine         *engine,
	                                                      WorldRuntime::CommandUiSnapshot &snapshot,
	                                                      const bool                       requireFrameData,
	                                                      const bool requireSelectedWordResolved = false)
	{
		auto *context = activeCallbackContext(engine);
		if (!context || !engine)
			return false;
		if (tryResolveCallbackCommandUiSnapshotFromCache(engine, snapshot, requireFrameData,
		                                                 requireSelectedWordResolved))
			return true;
		if (context->commandUiSnapshotDirty)
			return false;
		const auto *dispatchSnapshot = context->miniWindowLookupBaseSnapshot;
		if (!dispatchSnapshot)
			dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot();
		if (!dispatchSnapshot || !dispatchSnapshot->hasCommandUiSnapshot)
			return false;
		if (requireFrameData && !dispatchSnapshot->commandUiHasFrameData)
			return false;

		context->commandUiSnapshot = commandUiSnapshotFromDispatch(*dispatchSnapshot);
		if (requireSelectedWordResolved && !context->commandUiSnapshot.selectedWordResolved)
		{
			context->commandUiSnapshot = {};
			return false;
		}
		if (commandUiDispatchHasCommandHistory(*dispatchSnapshot))
		{
			context->commandHistorySnapshot    = context->commandUiSnapshot.commandHistory;
			context->hasCommandHistorySnapshot = true;
		}
		context->hasCommandUiSnapshot          = true;
		context->commandUiSnapshotHasFrameData = dispatchSnapshot->commandUiHasFrameData;
		context->commandUiSnapshotDirty        = false;
		snapshot                               = context->commandUiSnapshot;
		return true;
	}

	bool
	tryBackfillCallbackRuntimeCountersSnapshotFromDispatch(const LuaCallbackEngine               *engine,
	                                                       WorldRuntime::RuntimeCountersSnapshot &snapshot,
	                                                       const bool                             withStrings)
	{
		auto *context = activeCallbackContext(engine);
		if (!context || !engine)
			return false;
		if (withStrings ? tryResolveCallbackRuntimeCountersSnapshotWithStringsFromCache(engine, snapshot)
		                : tryResolveCallbackRuntimeCountersSnapshotFromCache(engine, snapshot))
		{
			return true;
		}

		const auto *dispatchSnapshot = context->miniWindowLookupBaseSnapshot;
		if (!dispatchSnapshot)
			dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot();
		if (!dispatchSnapshot || !dispatchSnapshot->hasRuntimeCountersSnapshot)
			return false;
		if (context->runtimeCountersSnapshotDirty)
			return false;

		if (!context->hasRuntimeCountersSnapshot)
		{
			context->runtimeCountersSnapshot    = runtimeCountersSnapshotFromDispatch(*dispatchSnapshot);
			context->hasRuntimeCountersSnapshot = true;
		}
		if (!context->hasRuntimeCountersSnapshotWithStrings)
		{
			context->runtimeCountersSnapshotWithStrings    = context->runtimeCountersSnapshot;
			context->hasRuntimeCountersSnapshotWithStrings = true;
		}

		snapshot =
		    withStrings ? context->runtimeCountersSnapshotWithStrings : context->runtimeCountersSnapshot;
		return true;
	}

	bool tryBackfillCallbackMiniWindowInfoFromDispatch(const LuaCallbackEngine *engine,
	                                                   const QString &windowName, int infoType,
	                                                   QVariant &value)
	{
		if (infoType <= 0)
			return false;
		if (tryResolveCallbackMiniWindowInfoFromCache(engine, windowName, infoType, value))
			return true;

		auto *context = activeCallbackContext(engine);
		if (!context)
			return false;
		const auto *snapshot = callbackMiniWindowSnapshotForBackfill(engine, *context);
		if (!snapshot)
			return false;

		const QString windowKey = windowName.trimmed().toLower();
		if (windowKey.isEmpty())
			return false;
		const auto infoIt = snapshot->windowInfoByWindow.constFind(windowKey);
		if (infoIt == snapshot->windowInfoByWindow.constEnd())
			return false;

		if (!tryResolveCallbackMiniWindowInfoSnapshotValue(infoIt.value(), infoType, value))
			return false;

		context->existingMiniWindowIds.insert(windowKey);
		context->missingMiniWindowIds.remove(windowKey);
		cacheCallbackMiniWindowInfo(engine, windowKey, infoType, value);
		return true;
	}

	bool stringListContainsCaseInsensitive(const QStringList &items, const QString &value)
	{
		return std::ranges::any_of(items, [&value](const QString &item)
		                           { return item.compare(value, Qt::CaseInsensitive) == 0; });
	}

	bool dispatchSnapshotContainsWindow(const LuaCallbackMiniWindowSnapshot &snapshot,
	                                    const QString                       &windowKey)
	{
		if (windowKey.isEmpty())
			return false;
		if (snapshot.miniWindowLookupCacheValid)
			return snapshot.normalizedMiniWindowIds.contains(windowKey);
		if (snapshot.windowInfoByWindow.contains(windowKey))
			return true;
		return std::ranges::any_of(snapshot.windowNames, [&windowKey](const QString &name)
		                           { return name.trimmed().compare(windowKey, Qt::CaseInsensitive) == 0; });
	}

	bool tryBackfillCallbackMiniWindowListFromDispatch(const LuaCallbackEngine *engine, QStringList &names)
	{
		if (tryResolveCallbackMiniWindowListFromCache(engine, names))
			return true;
		auto *context = activeCallbackContext(engine);
		if (!context)
			return false;
		const auto *snapshot = callbackMiniWindowSnapshotForBackfill(engine, *context);
		if (!snapshot)
			return false;

		if (!snapshot->windowNames.isEmpty())
			context->miniWindowListSnapshot = snapshot->windowNames;
		else if (!snapshot->windowInfoByWindow.isEmpty())
			context->miniWindowListSnapshot = snapshot->windowInfoByWindow.keys();
		else
			context->miniWindowListSnapshot.clear();

		context->hasMiniWindowListSnapshot = true;
		for (const QString &windowName : context->miniWindowListSnapshot)
		{
			const QString normalized = windowName.trimmed().toLower();
			if (!normalized.isEmpty())
				context->existingMiniWindowIds.insert(normalized);
		}

		names = context->miniWindowListSnapshot;
		return true;
	}

	bool tryBackfillCallbackMiniWindowExistsFromDispatch(const LuaCallbackEngine *engine,
	                                                     const QString &windowName, bool &exists)
	{
		if (tryResolveCallbackMiniWindowExistsFromCache(engine, windowName, exists))
			return true;
		auto *context = activeCallbackContext(engine);
		if (!context)
			return false;
		const auto *snapshot = callbackMiniWindowSnapshotForBackfill(engine, *context);
		if (!snapshot)
			return false;

		const QString windowKey = windowName.trimmed().toLower();
		if (windowKey.isEmpty())
		{
			exists = false;
			return true;
		}
		exists = dispatchSnapshotContainsWindow(*snapshot, windowKey);
		cacheCallbackMiniWindowExists(engine, windowKey, exists);
		return true;
	}

	bool tryBackfillCallbackMiniWindowFontListFromDispatch(const LuaCallbackEngine *engine,
	                                                       const QString &windowName, QStringList &fontIds)
	{
		if (tryResolveCallbackMiniWindowFontListFromCache(engine, windowName, fontIds))
			return true;
		auto *context = activeCallbackContext(engine);
		if (!context)
			return false;
		const auto *snapshot = callbackMiniWindowSnapshotForBackfill(engine, *context);
		if (!snapshot)
			return false;

		const QString windowKey = windowName.trimmed().toLower();
		if (windowKey.isEmpty())
			return false;
		const bool windowExists = dispatchSnapshotContainsWindow(*snapshot, windowKey);
		if (const auto it = snapshot->fontIdsByWindow.constFind(windowKey);
		    it != snapshot->fontIdsByWindow.constEnd())
		{
			fontIds = it.value();
		}
		else if (windowExists)
		{
			fontIds.clear();
		}
		else
		{
			return false;
		}

		cacheCallbackMiniWindowFontList(engine, windowKey, fontIds);
		for (const QString &fontId : fontIds)
			cacheCallbackMiniWindowFontExists(engine, windowKey, fontId, true);
		return true;
	}

