static int luaChatDisconnect(lua_State *L)
{
	const auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eChatIDNotFound);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eChatIDNotFound);
		return 1;
	}
	const long id = luaL_checkinteger(L, 1);
	if (activeCallbackContextConst(engine))
	{
		QList<long> ids;
		if (!resolveChatConnectionIdsForApi(engine, runtime, ids))
		{
			lua_pushnumber(L, eChatIDNotFound);
			return 1;
		}
		if (!ids.contains(id))
		{
			lua_pushnumber(L, eChatIDNotFound);
			return 1;
		}
		const int results = enqueueRuntimeThreadAsyncOkStatusResult(
		    L, engine, runtime, QStringLiteral("ChatDisconnect"), eChatIDNotFound,
		    [id](WorldRuntime &targetRuntime) -> int { return targetRuntime.chatDisconnect(id); });
		if (lua_tointeger(L, -results) != eOK)
			return results;
		QString remoteUser;
		if (resolveCallbackChatUserName(engine, runtime, id, remoteUser))
			appendCallbackChatNoteOutputLine(engine, runtime, 0,
			                                 QStringLiteral("Connection to %1 dropped.").arg(remoteUser));
		ids.removeAll(id);
		cacheCallbackChatConnectionIds(engine, ids);
		clearCallbackChatInfoValues(engine, id);
		return results;
	}
	lua_pushnumber(
	    L, runOnRuntimeThreadDeferredMutation(
	           engine, runtime, [=]() -> int { return runtime->chatDisconnect(id); }, eChatIDNotFound));
	return 1;
}

