static int luaChatEverybody(lua_State *L)
{
	const auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eNoChatConnections);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eNoChatConnections);
		return 1;
	}
	const QString message = QString::fromUtf8(luaL_checkstring(L, 1));
	const bool    emote   = optBool(L, 2, false);
	if (activeCallbackContextConst(engine))
	{
		const CallbackChatRecipients recipients = callbackRelevantChatRecipients(engine, runtime);
		if (!recipients.resolved || recipients.ids.isEmpty())
		{
			lua_pushnumber(L, eNoChatConnections);
			return 1;
		}
		const int results = enqueueRuntimeThreadAsyncOkStatusResult(
		    L, engine, runtime, QStringLiteral("ChatEverybody"), eNoChatConnections,
		    [message, emote](WorldRuntime &targetRuntime) -> int
		    { return targetRuntime.chatEverybody(message, emote); });
		if (lua_tointeger(L, -results) != eOK)
			return results;
		const QString bold    = callbackAnsiCode(kAnsiBold);
		const QString cyan    = callbackAnsiCode(kAnsiTextCyan);
		const QString red     = callbackAnsiCode(kAnsiTextRed);
		const QString ourName = callbackChatOurName(engine, runtime);
		appendCallbackChatNoteOutputLine(
		    engine, runtime, 8,
		    emote
		        ? QStringLiteral("You emote to everybody: %1%2%3 %4%5").arg(bold, cyan, ourName, message, red)
		        : QStringLiteral("You chat to everybody, '%1%2%3%4'").arg(bold, cyan, message, red));
		return results;
	}
	lua_pushnumber(L, runOnRuntimeThreadDeferredMutation(
	                      engine, runtime, [=]() -> int { return runtime->chatEverybody(message, emote); },
	                      eNoChatConnections));
	return 1;
}

