		const QString bold    = callbackAnsiCode(kAnsiBold);
		const QString cyan    = callbackAnsiCode(kAnsiTextCyan);
		const QString red     = callbackAnsiCode(kAnsiTextRed);
		const QString ourName = callbackChatOurName(engine, runtime);
