static int luaChatPersonal(lua_State *L)
{
	const auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eChatPersonNotFound);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eChatPersonNotFound);
		return 1;
	}
	const QString who     = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString message = QString::fromUtf8(luaL_checkstring(L, 2));
	const bool    emote   = optBool(L, 3, false);
	if (activeCallbackContextConst(engine))
	{
		if (who.trimmed().isEmpty())
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		QList<long> ids;
		if (!resolveChatConnectionIdsForApi(engine, runtime, ids) || ids.isEmpty())
		{
			lua_pushnumber(L, eChatPersonNotFound);
			return 1;
		}
		const QString trimmed = who.trimmed();
		QStringList   matchedNames;
		bool          allNamesResolved = true;
		for (const long candidateId : std::as_const(ids))
		{
			QString remoteUser;
			if (!resolveCallbackChatUserName(engine, runtime, candidateId, remoteUser))
			{
				allNamesResolved = false;
				break;
			}
			if (remoteUser.compare(trimmed, Qt::CaseInsensitive) == 0)
				matchedNames.push_back(remoteUser);
		}
		if (allNamesResolved)
		{
			if (matchedNames.isEmpty())
			{
				appendCallbackChatNoteOutputLine(engine, runtime, 7,
				                                 QStringLiteral("%1 is not connected.").arg(trimmed));
				lua_pushnumber(L, eChatPersonNotFound);
				return 1;
			}
		}
		const int results = enqueueRuntimeThreadAsyncOkStatusResult(
		    L, engine, runtime, QStringLiteral("ChatPersonal"), eChatPersonNotFound,
		    [who, message, emote](WorldRuntime &targetRuntime) -> int
		    { return targetRuntime.chatPersonal(who, message, emote); });
		if (lua_tointeger(L, -results) != eOK)
			return results;
		if (allNamesResolved)
		{
			const QString bold    = callbackAnsiCode(kAnsiBold);
			const QString cyan    = callbackAnsiCode(kAnsiTextCyan);
			const QString red     = callbackAnsiCode(kAnsiTextRed);
			const QString ourName = callbackChatOurName(engine, runtime);
			for (const QString &remoteUser : std::as_const(matchedNames))
			{
				appendCallbackChatNoteOutputLine(engine, runtime, 7,
				                                 emote
				                                     ? QStringLiteral("You emote to %1: %2%3%4 %5%6")
				                                           .arg(remoteUser, bold, cyan, ourName, message, red)
				                                     : QStringLiteral("You chat to %1, '%2%3%4%5'")
				                                           .arg(remoteUser, bold, cyan, message, red));
			}
			if (matchedNames.size() > 1)
				appendCallbackChatNoteOutputLine(engine, runtime, 7,
				                                 QStringLiteral("%1 matches.").arg(matchedNames.size()));
		}
		return results;
	}
	lua_pushnumber(L, runOnRuntimeThreadDeferredMutation(
	                      engine, runtime, [=]() -> int
	                      { return runtime->chatPersonal(who, message, emote); }, eChatPersonNotFound));
	return 1;
}

