static int luaDebug(lua_State *L)
{
	const auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnil(L);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	const QString command = QString::fromUtf8(luaL_optstring(L, 1, ""));
	if (activeCallbackContextConst(engine))
	{
		enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime, [command](WorldRuntime &targetRuntime)
		    { static_cast<void>(targetRuntime.debugCommand(command)); });
		lua_pushnil(L);
		return 1;
	}
	const QVariant value =
	    runOnRuntimeThread(runtime, [&]() -> QVariant { return runtime->debugCommand(command); }, QVariant());
	if (!value.isValid())
	{
		lua_pushnil(L);
		return 1;
	}
	pushVariant(L, value);
	return 1;
}

static int luaDeleteAllMapItems(lua_State *L)
{
	const auto   *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::RuntimeCountersSnapshot snapshot;
		if (!resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot))
		{
			lua_pushnumber(L, eWorldClosed);
			return 1;
		}
		if (snapshot.mappingCount <= 0)
		{
			lua_pushnumber(L, eNoMapItems);
			return 1;
		}
		enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [](WorldRuntime &targetRuntime) { static_cast<void>(targetRuntime.deleteAllMapItems()); });
		adjustCallbackMappingCountSnapshot(engine, runtime, -snapshot.mappingCount);
		clearCallbackMappingEntries(engine, runtime);
		lua_pushnumber(L, eOK);
		return 1;
	}
	lua_pushnumber(L,
	               runOnRuntimeThreadDeferredMutation(
	                   engine, runtime, [=]() -> int { return runtime->deleteAllMapItems(); }, eWorldClosed));
	return 1;
}

