static std::optional<bool> resolvePluginCallbackPresenceForApi(const LuaCallbackEngine *engine,
                                                               WorldRuntime            *runtime,
                                                               const QString           &functionName)
{
	if (!engine || !runtime || functionName.isEmpty())
		return std::nullopt;
	bool present = false;
	if (tryResolveCallbackPluginCallbackPresenceFromCache(engine, functionName, present))
		return present;
	const bool inCallback      = activeCallbackContextConst(engine) != nullptr;
	const auto resolvePresence = [&]() -> bool
	{
		present = runtime->hasPluginCallbackRecipient(functionName);
		return true;
	};
	bool resolved = false;
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
	{
		resolved = false;
	}
	else
	{
		resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(runtime, resolvePresence, false)
		                      : runOnRuntimeThread(runtime, resolvePresence, false);
	}
	if (!resolved)
		return std::nullopt;
	cacheCallbackPluginCallbackPresence(engine, functionName, present);
	return present;
}

