static bool resolveWorldWindowPositionForApi(const LuaCallbackEngine *engine, const WorldRuntime *runtime,
                                             const int which, const bool screen, const bool useGetWindowRect,
                                             QRect &rect)
{
	if (!engine || !runtime)
		return false;
	bool cacheHit = false;
	if (tryResolveCallbackWorldWindowPositionFromCache(engine, which, screen, useGetWindowRect, rect,
	                                                   cacheHit))
	{
		return true;
	}
	if (cacheHit)
		return false;
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		bool found = false;
		if (tryResolveCallbackWorldWindowPositionFromDispatchSnapshot(engine, runtime, which, screen,
		                                                              useGetWindowRect, rect, found))
		{
			return found;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	const bool resolved = runOnMainWindowThread(
	    [&](MainWindow *frame) -> bool
	    {
		    MainWindowHost *host = resolveMainWindowHost(frame);
		    if (!host)
			    host = frame;
		    WorldChildWindow *window = findWorldWindowByOrdinal(*host, *runtime, which);
		    if (!window)
			    return false;

		    rect = useGetWindowRect ? window->frameGeometry() : window->normalGeometry();
		    if (!rect.isValid())
			    rect = window->geometry();
		    if (screen)
			    rect.moveTopLeft(window->mapToGlobal(rect.topLeft()));
		    return true;
	    },
	    false);
	cacheCallbackWorldWindowPosition(engine, which, screen, useGetWindowRect, resolved, rect);
	return resolved;
}

