static bool resolveMappingEntriesSnapshotForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                                QStringList &entries)
{
	if (!engine || !runtime)
		return false;
	if (tryResolveCallbackMappingEntriesSnapshotFromCache(engine, entries))
		return true;
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		if (const auto *dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot();
		    dispatchSnapshot && dispatchSnapshot->hasMappingEntriesSnapshot)
		{
			entries = dispatchSnapshot->mappingEntriesSnapshot;
			cacheCallbackMappingEntriesSnapshot(engine, entries);
			return true;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	const bool resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       entries.clear();
		                                       const int count = runtime->mappingCount();
		                                       for (int i = 0; i < count; ++i)
		                                       {
			                                       const QString entry = runtime->mappingItem(i);
			                                       if (!entry.isEmpty())
				                                       entries.push_back(entry);
		                                       }
		                                       return true;
	                                       },
	                                       false)
	                                 : runOnRuntimeThread(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       entries.clear();
		                                       const int count = runtime->mappingCount();
		                                       for (int i = 0; i < count; ++i)
		                                       {
			                                       const QString entry = runtime->mappingItem(i);
			                                       if (!entry.isEmpty())
				                                       entries.push_back(entry);
		                                       }
		                                       return true;
	                                       },
	                                       false);
	if (!resolved)
		return false;
	cacheCallbackMappingEntriesSnapshot(engine, entries);
	return true;
}

static bool resolveMappingItemForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime, const int index,
                                     QString &entry, bool &found)
{
	entry.clear();
	found = false;
	if (!engine || !runtime)
		return false;
	QStringList entries;
	if (!resolveMappingEntriesSnapshotForApi(engine, runtime, entries))
		return false;
	if (index < 0 || index >= entries.size())
		return true;
	entry = entries.at(index);
	found = !entry.isEmpty();
	return true;
}

