static bool resolveNotepadLengthForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                       const QString &title, const QString &worldId, int &length)
{
	length = 0;
	if (!engine || !runtime || title.isEmpty())
		return false;
	const QString key = makeCallbackNotepadDocumentKey(title, worldId, runtime);
	bool          cacheHit{false};
	if (tryResolveCallbackNotepadLengthFromCache(engine, key, length, cacheHit))
		return true;
	if (cacheHit)
		return true;
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (const auto *context = activeCallbackContextConst(engine);
	    context && context->dirtyNotepadDocumentKeys.contains(key))
	{
		return false;
	}
	if (inCallback &&
	    tryResolveCallbackNotepadLengthFromDispatchSnapshot(engine, runtime, title, worldId, key, length))
	{
		return true;
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	const bool found = runOnMainWindowThread(
	    [&](MainWindow *) -> bool
	    {
		    TextChildWindow *text = findNotepadWindow(title, runtime, worldId);
		    if (!text || !text->editor())
			    return false;
		    length = sizeToInt(text->editor()->toPlainText().length());
		    return true;
	    },
	    false);
	cacheCallbackNotepadLength(engine, key, found, length);
	return true;
}

static bool resolveNotepadListForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime, const bool all,
                                     const QString &worldId, QStringList &titles)
{
	titles.clear();
	if (!engine || !runtime)
		return false;
	const QString key = makeCallbackNotepadListKey(all, worldId, runtime);
	bool          cacheHit{false};
	if (tryResolveCallbackNotepadListFromCache(engine, key, titles, cacheHit))
		return true;
	if (cacheHit)
		return true;
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (const auto *context = activeCallbackContextConst(engine);
	    context && context->dirtyNotepadListKeys.contains(key))
	{
		return false;
	}
	if (inCallback &&
	    tryResolveCallbackNotepadListFromDispatchSnapshot(engine, runtime, all, worldId, key, titles))
	{
		return true;
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	const auto ownerToken = reinterpret_cast<quintptr>(runtime);
	const bool resolved   = runOnMainWindowThread(
	    [&](const MainWindow *frame) -> bool
	    {
		    auto *mdi = frame->findChild<QMdiArea *>();
		    if (!mdi)
			    return true;

		    for (const QList<QMdiSubWindow *> windows = mdi->subWindowList(QMdiArea::CreationOrder);
		         QMdiSubWindow *sub : windows)
		    {
			    auto *text = qobject_cast<TextChildWindow *>(sub);
			    if (!text)
				    continue;
			    if (!all)
			    {
				    if (const auto relatedToken = text->property("worldRuntimeToken").toULongLong();
				        relatedToken == ownerToken)
				    {
					    // Matched this runtime instance.
				    }
				    else
				    {
					    if (relatedToken != 0)
						    continue;
					    if (const QString related = text->property("worldId").toString();
					        related.isEmpty() || related.compare(worldId, Qt::CaseInsensitive) != 0)
						    continue;
				    }
			    }
			    titles.push_back(text->windowTitle());
		    }
		    return true;
	    },
	    false);
	if (!resolved)
		return false;
	cacheCallbackNotepadList(engine, key, !titles.isEmpty(), titles);
	return true;
}

