static bool resolveUdpPortListForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                     QList<int> &ports)
{
	ports.clear();
	if (!engine || !runtime)
		return false;
	if (tryResolveCallbackUdpPortListFromCache(engine, runtime, ports))
		return true;

	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		const auto   *context    = activeCallbackContextConst(engine);
		const QString runtimeKey = makeCallbackRuntimeKey(runtime);
		if (context && !runtimeKey.isEmpty() && context->dirtyUdpSnapshotRuntimeKeys.contains(runtimeKey))
		{
			if (callbackScopeSyncBridgeForbidden())
				return false;
		}
		else if (const auto *dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot();
		         dispatchSnapshot && dispatchSnapshot->hasUdpPortSnapshot)
		{
			ports = dispatchSnapshot->udpPortsSnapshot;
			cacheCallbackUdpPortList(engine, runtime, ports);
			return true;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;

	const bool resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       ports = runtime->udpPortList();
		                                       return true;
	                                       },
	                                       false)
	                                 : runOnRuntimeThread(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       ports = runtime->udpPortList();
		                                       return true;
	                                       },
	                                       false);
	if (!resolved)
		return false;

	cacheCallbackUdpPortList(engine, runtime, ports);
	return true;
}

static bool resolveUsedUdpPortsForApi(const LuaCallbackEngine *engine, QSet<int> &usedPorts)
{
	usedPorts.clear();
	if (!engine)
		return false;
	if (tryResolveCallbackUsedUdpPortsSnapshotFromCache(engine, usedPorts))
		return true;

	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (const auto *context = activeCallbackContextConst(engine);
	    context && context->usedUdpPortsSnapshotDirty && callbackScopeSyncBridgeForbidden())
		return false;
	if (inCallback && callbackScopeSyncBridgeForbidden())
	{
		if (const auto *dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot();
		    dispatchSnapshot && dispatchSnapshot->hasUsedUdpPortsSnapshot)
		{
			usedPorts = dispatchSnapshot->usedUdpPortsSnapshot;
			cacheCallbackUsedUdpPortsSnapshot(engine, usedPorts);
			return true;
		}
		return false;
	}

	const QList<QPointer<WorldRuntime>> runtimes = snapshotWorldRuntimesFromMainWindow();
	if (runtimes.isEmpty())
	{
		cacheCallbackUsedUdpPortsSnapshot(engine, usedPorts);
		return true;
	}

	for (const QPointer<WorldRuntime> &runtimeEntry : runtimes)
	{
		if (!runtimeEntry)
			continue;
		QList<int> ports;
		if (!resolveUdpPortListForApi(engine, runtimeEntry.data(), ports))
		{
			if (inCallback)
				return false;
			continue;
		}
		for (const int port : ports)
			usedPorts.insert(port);
	}

	cacheCallbackUsedUdpPortsSnapshot(engine, usedPorts);
	return true;
}

static bool resolveMacroEntriesSnapshotForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                              QList<WorldRuntime::Macro> &entries)
{
	if (!engine || !runtime)
		return false;
	if (const auto *context = activeCallbackContextConst(engine); context && context->hasMacroEntriesSnapshot)
	{
		entries = context->macroEntriesSnapshot;
		return true;
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		if (const auto *dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot();
		    dispatchSnapshot && dispatchSnapshot->hasMacroEntriesSnapshot)
		{
			entries.clear();
			for (const LuaCallbackAttributeChildrenSnapshot &row : dispatchSnapshot->macroEntriesSnapshot)
			{
				WorldRuntime::Macro entry;
				entry.attributes = row.attributes;
				entry.children   = row.children;
				entries.push_back(entry);
			}
			if (auto *context = activeCallbackContext(engine))
			{
				context->macroEntriesSnapshot    = entries;
				context->hasMacroEntriesSnapshot = true;
			}
			return true;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	const bool resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       entries = runtime->macros();
		                                       return true;
	                                       },
	                                       false)
	                                 : runOnRuntimeThread(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       entries = runtime->macros();
		                                       return true;
	                                       },
	                                       false);
	if (!resolved)
		return false;
	if (auto *context = activeCallbackContext(engine))
	{
		context->macroEntriesSnapshot    = entries;
		context->hasMacroEntriesSnapshot = true;
	}
	return true;
}

static bool resolveVariableEntriesSnapshotForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                                 QList<WorldRuntime::Variable> &entries)
{
	if (!engine || !runtime)
		return false;
	if (const auto *context = activeCallbackContextConst(engine);
	    context && context->hasVariableEntriesSnapshot)
	{
		entries = context->variableEntriesSnapshot;
		return true;
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		if (const auto *dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot();
		    dispatchSnapshot && dispatchSnapshot->hasVariableEntriesSnapshot)
		{
			entries.clear();
			for (const LuaCallbackAttributeContentSnapshot &row : dispatchSnapshot->variableEntriesSnapshot)
			{
				WorldRuntime::Variable entry;
				entry.attributes = row.attributes;
				entry.content    = row.content;
				entries.push_back(entry);
			}
			if (auto *context = activeCallbackContext(engine))
			{
				context->variableEntriesSnapshot    = entries;
				context->hasVariableEntriesSnapshot = true;
			}
			return true;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	const bool resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       entries = runtime->variables();
		                                       return true;
	                                       },
	                                       false)
	                                 : runOnRuntimeThread(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       entries = runtime->variables();
		                                       return true;
	                                       },
	                                       false);
	if (!resolved)
		return false;
	if (auto *context = activeCallbackContext(engine))
	{
		context->variableEntriesSnapshot    = entries;
		context->hasVariableEntriesSnapshot = true;
	}
	return true;
}

static void cacheCallbackVariableEntryAfterSet(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                               const QString &name, const QString &value)
{
	auto *context = activeCallbackContext(engine);
	if (!context)
		return;
	QList<WorldRuntime::Variable> entries;
	if (!resolveVariableEntriesSnapshotForApi(engine, runtime, entries))
		return;
	const QString normalized = name.trimmed();
	for (WorldRuntime::Variable &entry : entries)
	{
		const QString entryName = entry.attributes.value(QStringLiteral("name"));
		if (entryName.compare(normalized, Qt::CaseInsensitive) != 0)
			continue;
		entry.attributes.insert(QStringLiteral("name"), entryName.isEmpty() ? name : entryName);
		entry.content                       = value;
		context->variableEntriesSnapshot    = entries;
		context->hasVariableEntriesSnapshot = true;
		return;
	}
	WorldRuntime::Variable entry;
	entry.attributes.insert(QStringLiteral("name"), name);
	entry.content = value;
	entries.push_back(entry);
	context->variableEntriesSnapshot    = entries;
	context->hasVariableEntriesSnapshot = true;
}

static void cacheCallbackVariableEntryAfterDelete(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                                  const QString &name)
{
	auto *context = activeCallbackContext(engine);
	if (!context)
		return;
	QList<WorldRuntime::Variable> entries;
	if (!resolveVariableEntriesSnapshotForApi(engine, runtime, entries))
		return;
	const QString normalized = name.trimmed();
	entries.removeIf(
	    [&normalized](const WorldRuntime::Variable &entry)
	    {
		    return entry.attributes.value(QStringLiteral("name")).compare(normalized, Qt::CaseInsensitive) ==
		           0;
	    });
	context->variableEntriesSnapshot    = entries;
	context->hasVariableEntriesSnapshot = true;
}

static bool resolveKeypadEntriesSnapshotForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                               QList<WorldRuntime::Keypad> &entries)
{
	if (!engine || !runtime)
		return false;
	if (const auto *context = activeCallbackContextConst(engine);
	    context && context->hasKeypadEntriesSnapshot)
	{
		entries = context->keypadEntriesSnapshot;
		return true;
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		if (const auto *dispatchSnapshot = engine->currentDispatchMiniWindowSnapshot();
		    dispatchSnapshot && dispatchSnapshot->hasKeypadEntriesSnapshot)
		{
			entries.clear();
			for (const LuaCallbackAttributeContentSnapshot &row : dispatchSnapshot->keypadEntriesSnapshot)
			{
				WorldRuntime::Keypad entry;
				entry.attributes = row.attributes;
				entry.content    = row.content;
				entries.push_back(entry);
			}
			if (auto *context = activeCallbackContext(engine))
			{
				context->keypadEntriesSnapshot    = entries;
				context->hasKeypadEntriesSnapshot = true;
			}
			return true;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	const bool resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       entries = runtime->keypadEntries();
		                                       return true;
	                                       },
	                                       false)
	                                 : runOnRuntimeThread(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       entries = runtime->keypadEntries();
		                                       return true;
	                                       },
	                                       false);
	if (!resolved)
		return false;
	if (auto *context = activeCallbackContext(engine))
	{
		context->keypadEntriesSnapshot    = entries;
		context->hasKeypadEntriesSnapshot = true;
	}
	return true;
}

static bool resolveSpeedwalkForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                   const QString &input, QString &result)
{
	if (!engine || !runtime)
		return false;

	QHash<QString, QString> directions;
	if (const auto *context = activeCallbackContextConst(engine);
	    context && context->hasSpeedwalkDirectionSnapshot)
	{
		directions = context->speedwalkDirectionsToSendByCode;
	}
	else
	{
		if (const auto *app = AppController::instance())
		{
			const QHash<QString, AppController::MapDirection> snapshot = app->mapDirectionSnapshot();
			for (auto it = snapshot.constBegin(); it != snapshot.constEnd(); ++it)
				directions.insert(it.key(), it.value().toSend.isEmpty() ? it.key() : it.value().toSend);
		}
		for (const QString &code : {QStringLiteral("n"), QStringLiteral("s"), QStringLiteral("e"),
		                            QStringLiteral("w"), QStringLiteral("u"), QStringLiteral("d")})
		{
			if (!directions.contains(code))
				directions.insert(code, code);
		}
		if (auto *callbackContext = activeCallbackContext(engine))
		{
			callbackContext->speedwalkDirectionsToSendByCode = directions;
			callbackContext->hasSpeedwalkDirectionSnapshot   = true;
		}
	}

	QString filler;
	if (const auto *context = activeCallbackContextConst(engine); context && context->hasSpeedwalkFiller)
	{
		filler = context->speedwalkFiller;
	}
	else
	{
		filler = resolveWorldAttributeValueForApi(engine, runtime, QStringLiteral("speed_walk_filler"));
		if (auto *callbackContext = activeCallbackContext(engine))
		{
			callbackContext->speedwalkFiller    = filler;
			callbackContext->hasSpeedwalkFiller = true;
		}
	}

	const auto resolver = [directions](const QString &direction) -> QString
	{
		const QString key = direction.trimmed().toLower();
		if (const auto it = directions.constFind(key); it != directions.constEnd())
			return it.value();
		return {};
	};
	result = QMudSpeedwalk::evaluateSpeedwalk(input, filler, resolver);
	return true;
}

static bool resolveRuntimeCountersSnapshotForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                                 WorldRuntime::RuntimeCountersSnapshot &snapshot)
{
	if (tryResolveCallbackRuntimeCountersSnapshotFromCache(engine, snapshot))
	{
		if (const auto *context = activeCallbackContextConst(engine);
		    context && context->hasActionSourceOverride)
			snapshot.currentActionSource = context->actionSourceOverride;
		return true;
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback && tryBackfillCallbackRuntimeCountersSnapshotFromDispatch(engine, snapshot, false))
	{
		if (const auto *context = activeCallbackContextConst(engine);
		    context && context->hasActionSourceOverride)
			snapshot.currentActionSource = context->actionSourceOverride;
		return true;
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	const bool resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       snapshot = runtime->runtimeCountersSnapshot(false);
		                                       return true;
	                                       },
	                                       false)
	                                 : runOnRuntimeThread(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       snapshot = runtime->runtimeCountersSnapshot(false);
		                                       return true;
	                                       },
	                                       false);
	if (resolved)
	{
		if (const auto *context = activeCallbackContextConst(engine);
		    context && context->hasActionSourceOverride)
			snapshot.currentActionSource = context->actionSourceOverride;
		cacheCallbackRuntimeCountersSnapshot(engine, snapshot);
	}
	return resolved;
}

