static int luaGetNoteColour(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, -1);
		return 1;
	}
	WorldRuntime::RuntimeCountersSnapshot snapshot;
	if (!resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot))
	{
		lua_pushnumber(L, -1);
		return 1;
	}
	if (snapshot.notesInRgb)
	{
		lua_pushnumber(L, -1);
		return 1;
	}
	if (const int noteColour = snapshot.noteTextColour;
	    noteColour == WorldRuntime::kSameColour || noteColour < 0)
		lua_pushnumber(L, 0);
	else
		lua_pushnumber(L, noteColour + 1);
	return 1;
}

