static int luaOpen(lua_State *L)
{
	auto          *engine     = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime  *runtime    = runtimeFromLuaUpvalue(L);
	const QString  path       = QString::fromUtf8(luaL_checkstring(L, 1));
	AppController *controller = AppController::instance();
	if (!controller)
	{
		lua_pushboolean(L, false);
		return 1;
	}

	if (!path.isEmpty())
	{
		if (const QFileInfo info(path); !info.exists())
		{
			lua_pushboolean(L, false);
			return 1;
		}
	}

	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		const bool    accepted         = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [path, callbackPluginId, requestId](WorldRuntime &targetRuntime)
		    {
			    const QPointer<WorldRuntime> runtimeGuard(&targetRuntime);
			    const bool                   queued = enqueueOnMainThread(
			        [runtimeGuard, path, callbackPluginId, requestId]
			        {
				        WorldRuntime *targetRuntimeOnMain = runtimeGuard.data();
				        if (!targetRuntimeOnMain)
					        return;
				        const bool opened =
				            AppController::instance() && AppController::instance()->openDocumentFile(path);
				        emitPluginAsyncResult(*targetRuntimeOnMain, callbackPluginId, requestId,
				                              QStringLiteral("Open"), opened, opened ? eOK : -1, path);
			        });
			    if (!queued)
			    {
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId, QStringLiteral("Open"),
				                          false, -1, path);
			    }
		    });
		lua_pushboolean(L, accepted);
		if (accepted && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}

	const bool opened = runOnMainWindowThreadAllowNestedEvents(
	    [controller, path](MainWindow *) -> bool { return controller->openDocumentFile(path); }, false);
	lua_pushboolean(L, opened);
	return 1;
}

static int luaOpenBrowser(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	const QString urlText = QString::fromUtf8(luaL_checkstring(L, 1));
	if (urlText.isEmpty())
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	if (!urlText.startsWith(QStringLiteral("http://"), Qt::CaseInsensitive) &&
	    !urlText.startsWith(QStringLiteral("https://"), Qt::CaseInsensitive) &&
	    !urlText.startsWith(QStringLiteral("mailto:"), Qt::CaseInsensitive))
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		QPointer<QCoreApplication> app = QCoreApplication::instance();
		QPointer<WorldRuntime>     runtimeGuard(runtime);
		const bool                 queued = app && QMetaObject::invokeMethod(
		                                               app.data(),
		                                               [runtimeGuard, urlText, callbackPluginId, requestId]
		                                               {
			                               WorldRuntime *targetRuntime = runtimeGuard.data();
			                               if (!targetRuntime)
				                               return;
			                               const bool ok = QDesktopServices::openUrl(QUrl(urlText));
			                               emitPluginAsyncResult(*targetRuntime, callbackPluginId, requestId,
			                                                     QStringLiteral("OpenBrowser"), ok,
			                                                     ok ? eOK : eCouldNotOpenFile);
		                                               },
		                                               Qt::QueuedConnection);
		lua_pushnumber(L, queued ? eOK : eCouldNotOpenFile);
		if (queued && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}
	const bool ok = runOnMainWindowThread([&urlText](MainWindow *) -> bool
	                                      { return QDesktopServices::openUrl(QUrl(urlText)); }, false, true);
	lua_pushnumber(L, ok ? eOK : eCouldNotOpenFile);
	return 1;
}

static int luaPasteCommand(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushstring(L, "");
		return 1;
	}
	const QString text = QString::fromUtf8(luaL_checkstring(L, 1));
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::CommandUiSnapshot snapshot;
		if (!resolveCommandUiSnapshotLightForApi(engine, runtime, snapshot) || !snapshot.hasView)
		{
			lua_pushstring(L, "");
			return 1;
		}
		const QString expectedInput  = snapshot.commandInputText;
		const int     inputLength    = expectedInput.size() > std::numeric_limits<int>::max()
		                                   ? std::numeric_limits<int>::max()
		                                   : static_cast<int>(expectedInput.size());
		const int     selectionStart = std::clamp(snapshot.inputSelectionStartColumn - 1, 0, inputLength);
		const int     selectionEnd =
		    snapshot.inputSelectionEndColumn <= selectionStart
		        ? selectionStart
		        : std::clamp(snapshot.inputSelectionEndColumn, selectionStart, inputLength);
		const QString replaced = selectionEnd > selectionStart
		                             ? expectedInput.mid(selectionStart, selectionEnd - selectionStart)
		                             : QString();
		if (!text.isEmpty())
		{
			enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime,
			                                             [text](const WorldRuntime &targetRuntime)
			                                             {
				                                             if (WorldView *view = targetRuntime.view())
					                                             view->pasteCommand(text);
			                                             });
			replaceCallbackCommandSelectionSnapshot(engine, selectionStart, selectionEnd, text);
		}
		lua_pushstring(L, replaced.toLocal8Bit().constData());
		return 1;
	}
	const QString replaced = runOnRuntimeThread(
	    runtime,
	    [runtime, text]() -> QString
	    {
		    if (WorldView *view = runtime->view())
			    return view->pasteCommand(text);
		    return {};
	    },
	    QString());
	lua_pushstring(L, replaced.toLocal8Bit().constData());
	return 1;
}

