static int luaPickColour(lua_State *L)
{
	auto         *engine    = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime   = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	const long    suggested = luaL_checkinteger(L, 1);
	QColor        initial;
	if (suggested != -1)
	{
		const auto packed = static_cast<QMudColorRef>(suggested);
		initial           = QColor(qmudRed(packed), qmudGreen(packed), qmudBlue(packed));
	}
	const auto pickColour = [initial](MainWindow *frame) -> QColor
	{ return QColorDialog::getColor(initial, frame, QStringLiteral("Pick Colour")); };
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		quint64    requestId = 0;
		const bool accepted  = enqueueMainWindowAsyncResult(
		    engine, runtime, QStringLiteral("PickColour"),
		    [pickColour](MainWindow *frame) -> PluginAsyncDialogResult
		    {
			    const QColor chosen = pickColour(frame);
			    return {true, eOK,
			            QString::number(chosen.isValid() ? static_cast<lua_Number>(colorValue(chosen)) : -1)};
		    },
		    requestId);
		lua_pushnumber(L, -1);
		if (accepted && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}
	const QColor chosen = runOnMainWindowThreadAllowNestedEvents([&](MainWindow *frame) -> QColor
	                                                             { return pickColour(frame); }, {});
	if (!chosen.isValid())
	{
		lua_pushnumber(L, -1);
		return 1;
	}
	lua_pushnumber(L, static_cast<lua_Number>(colorValue(chosen)));
	return 1;
}

static int luaPlaySound(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	const int     buffer   = static_cast<int>(luaL_checkinteger(L, 1));
	const QString fileName = QString::fromUtf8(luaL_optstring(L, 2, ""));
	const bool    loop     = optBool(L, 3, false);
	const double  volume   = luaL_optnumber(L, 4, 0.0);
	const double  pan      = luaL_optnumber(L, 5, 0.0);
	if (activeCallbackContextConst(engine))
	{
#ifdef QMUD_ENABLE_QSOUND
		if (buffer < 0 || buffer > WorldRuntime::kMaxSoundBuffers)
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		if (buffer == 0 && fileName.isEmpty())
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		if (callbackScopeSyncBridgeForbidden())
		{
			const int results = enqueueRuntimeThreadAsyncStatusResult(
			    L, engine, runtime, QStringLiteral("PlaySound"), eOK, eCannotPlaySound,
			    [buffer, fileName, loop, volume, pan](WorldRuntime &targetRuntime) -> int
			    { return targetRuntime.playSound(buffer, fileName, loop, volume, pan); },
			    [](const int status) { return status == eOK; });
			if (buffer > 0 && lua_tointeger(L, -results) == eOK)
				cacheCallbackSoundStatus(engine, buffer, loop ? 2 : 1);
			return results;
		}
		{
			const int result = runOnRuntimeThreadDeferredMutation(
			    engine, runtime, [buffer, fileName, loop, volume, pan](WorldRuntime &targetRuntime) -> int
			    { return targetRuntime.playSound(buffer, fileName, loop, volume, pan); }, eCannotPlaySound);
			if (result == eOK && buffer > 0)
				cacheCallbackSoundStatus(engine, buffer, loop ? 2 : 1);
			lua_pushnumber(L, result);
			return 1;
		}
#else
		lua_pushnumber(L, eCannotPlaySound);
		return 1;
#endif
	}
	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime, [=]() -> int { return runtime->playSound(buffer, fileName, loop, volume, pan); },
	    eCannotPlaySound);
	lua_pushnumber(L, result);
	return 1;
}

