static QString trimDirection(const QString &text)
{
	QString trimmed = text;
	trimmed         = trimmed.trimmed();
	return trimmed;
}

static int luaRemoveBacktracks(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushstring(L, "");
		return 1;
	}
	const QHash<QString, AppController::MapDirection> directionSnapshot =
	    AppController::instance() ? AppController::instance()->mapDirectionSnapshot()
	                              : QHash<QString, AppController::MapDirection>{};
	const auto directionMapping =
	    [&directionSnapshot](const QString &direction) -> AppController::MapDirection
	{ return directionSnapshot.value(direction.trimmed().toLower()); };
	const QString path = QString::fromUtf8(luaL_checkstring(L, 1));
	QString       walk;
	if (!resolveSpeedwalkForApi(engine, runtime, path, walk))
		walk.clear();
	if (walk.isEmpty() || walk.startsWith(QLatin1Char('*')))
	{
		lua_pushstring(L, walk.toLocal8Bit().constData());
		return 1;
	}

	const QStringList items = walk.split(QRegularExpression(QStringLiteral("[\\r\\n]+")), Qt::SkipEmptyParts);
	if (items.isEmpty())
	{
		lua_pushstring(L, "");
		return 1;
	}

	QVector<QString> output;
	for (const QString &item : items)
	{
		QString current = trimDirection(item);
		if (current.isEmpty())
		{
			continue;
		}
		if (const QString mapped = directionMapping(current).toLog; !mapped.isEmpty())
			current = mapped;

		if (output.isEmpty())
		{
			output.push_back(current);
			continue;
		}

		QString top = output.back();
		if (const QString topReverse = directionMapping(top).reverse;
		    !topReverse.isEmpty() && topReverse == current)
			output.pop_back();
		else
			output.push_back(current);
	}

	QString result;
	QString prev;
	int     count = 0;
	for (const QString &entry : output)
	{
		QString dir = trimDirection(entry);
		if (dir.isEmpty())
			continue;
		if (dir.size() > 1)
			dir = QStringLiteral("(%1)").arg(dir);
		if (dir == prev && count < 99)
		{
			count++;
			continue;
		}
		if (!prev.isEmpty())
		{
			if (count > 1)
				result += QString::number(count) + prev;
			else
				result += prev;
			result += QLatin1Char(' ');
		}
		prev  = dir;
		count = 1;
	}

	if (!prev.isEmpty())
	{
		if (count > 1)
			result += QString::number(count) + prev;
		else
			result += prev;
		result += QLatin1Char(' ');
	}

	lua_pushstring(L, result.toLocal8Bit().constData());
	return 1;
}

