static int luaReverseSpeedwalk(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushstring(L, "");
		return 1;
	}
	const QHash<QString, AppController::MapDirection> directionSnapshot =
	    AppController::instance() ? AppController::instance()->mapDirectionSnapshot()
	                              : QHash<QString, AppController::MapDirection>{};
	const auto directionMapping =
	    [&directionSnapshot](const QString &direction) -> AppController::MapDirection
	{ return directionSnapshot.value(direction.trimmed().toLower()); };
	const QString input = QString::fromUtf8(luaL_checkstring(L, 1));
	QString       walk;
	if (!resolveSpeedwalkForApi(engine, runtime, input, walk))
		walk.clear();
	if (walk.isEmpty() || walk.startsWith(QLatin1Char('*')))
	{
		lua_pushstring(L, walk.toLocal8Bit().constData());
		return 1;
	}

	const QStringList items = walk.split(QRegularExpression(QStringLiteral("[\\r\\n]+")), Qt::SkipEmptyParts);
	if (items.isEmpty())
	{
		lua_pushstring(L, "");
		return 1;
	}

	QString result;
	QString lastDir;
	int     count = 0;
	bool    first = true;

	for (const QString &item : items)
	{
		QString current = trimDirection(item);
		if (current.isEmpty())
		{
			continue;
		}
		if (const QString reverse = directionMapping(current).reverse; !reverse.isEmpty())
			current = reverse;

		if (current == lastDir && count < 99)
		{
			count++;
			continue;
		}

		if (!first)
		{
			if (lastDir.size() > 1)
				lastDir = QStringLiteral("(%1)").arg(lastDir);
			if (count > 1)
				result += QString::number(count) + lastDir + QLatin1Char(' ');
			else
				result += lastDir + QLatin1Char(' ');
		}

		first   = false;
		lastDir = current;
		count   = 1;
	}

	if (!lastDir.isEmpty())
	{
		if (lastDir.size() > 1)
			lastDir = QStringLiteral("(%1)").arg(lastDir);
		if (count > 1)
			result += QString::number(count) + lastDir + QLatin1Char(' ');
		else
			result += lastDir + QLatin1Char(' ');
	}

	lua_pushstring(L, result.toLocal8Bit().constData());
	return 1;
}

