static int luaSave(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushboolean(L, false);
		return 1;
	}
	const bool  saveAs   = optBool(L, 2, false);
	const char *nameArg  = lua_gettop(L) >= 1 && !lua_isnil(L, 1) ? lua_tostring(L, 1) : "";
	QString     fileName = QString::fromUtf8(nameArg ? nameArg : "");
	if (saveAs)
	{
		if (fileName.isEmpty())
		{
			lua_pushboolean(L, false);
			return 1;
		}
	}
	else if (fileName.isEmpty())
	{
		WorldRuntime::RuntimeCountersSnapshot snapshot;
		if (resolveRuntimeCountersSnapshotWithStringsForApi(engine, runtime, snapshot))
			fileName = snapshot.worldFilePath;
	}

	if (fileName.isEmpty())
	{
		lua_pushboolean(L, false);
		return 1;
	}

	QString       error;
	bool          ok               = false;
	quint64       asyncRequestId   = 0;
	const QString callbackPluginId = engine->pluginId();
	if (activeCallbackContextConst(engine))
	{
		if (callbackScopeSyncBridgeForbidden())
		{
			asyncRequestId      = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
			const bool accepted = enqueueRuntimeThreadDeferredMutationNoResult(
			    engine, runtime,
			    [fileName, callbackPluginId, asyncRequestId](WorldRuntime &targetRuntime)
			    {
				    QString    saveError;
				    const bool saved = targetRuntime.saveWorldFile(fileName, &saveError);
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, asyncRequestId,
				                          QStringLiteral("Save"), saved, 0, saved ? QString() : saveError);
			    });
			ok = accepted;
			if (!accepted)
				asyncRequestId = 0;
			else
				invalidateCallbackRuntimeSnapshots(engine);
		}
		else
		{
			ok = runOnRuntimeThreadDeferredMutation(
			    engine, runtime, [&fileName, &error](WorldRuntime &targetRuntime) -> bool
			    { return targetRuntime.saveWorldFile(fileName, &error); }, false);
			if (ok)
			{
				WorldRuntime::RuntimeCountersSnapshot snapshot;
				static_cast<void>(resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot));
				setCallbackWorldFileModifiedSnapshot(engine, false);
			}
		}
	}
	else
	{
		ok = runOnRuntimeThreadDeferredMutationCall(engine, runtime, &WorldRuntime::saveWorldFile, 0,
		                                            fileName, static_cast<QString *>(nullptr)) != 0;
	}
	lua_pushboolean(L, ok ? 1 : 0);
	if (asyncRequestId != 0)
	{
		lua_pushnumber(L, static_cast<lua_Number>(asyncRequestId));
		return 2;
	}
	return 1;
}

static int luaSaveNotepad(lua_State *L)
{
	const QString title    = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString fileName = QString::fromUtf8(luaL_checkstring(L, 2));
	const bool    replace  = optBool(L, 3, false);
	auto         *engine   = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime  = runtimeFromLuaUpvalue(L);
	const QString worldId = resolveWorldAttributeValueForApi(engine, runtime, QStringLiteral("id")).trimmed();
	if (fileName.isEmpty())
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	QString resolvedFileName;
	QString pathError;
	if (!resolveLuaFileApiPath(engine, fileName, &resolvedFileName, &pathError))
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	if (!replace && QFileInfo::exists(resolvedFileName))
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		QPointer<QCoreApplication> app = QCoreApplication::instance();
		QPointer<WorldRuntime>     runtimeGuard(runtime);
		const bool                 queued =
		    app && QMetaObject::invokeMethod(
		               app.data(),
		               [runtimeGuard, title, worldId, resolvedFileName, callbackPluginId, requestId]
		               {
			               WorldRuntime *targetRuntime = runtimeGuard.data();
			               if (!targetRuntime)
				               return;
			               bool    ok = false;
			               QString error;
			               if (TextChildWindow *text = findNotepadWindow(title, targetRuntime, worldId);
			                   text && text->editor())
			               {
				               ok = text->saveToFile(resolvedFileName, &error);
			               }
			               emitPluginAsyncResult(*targetRuntime, callbackPluginId, requestId,
			                                     QStringLiteral("SaveNotepad"), ok, ok ? 0 : -1, error);
		               },
		               Qt::QueuedConnection);
		lua_pushnumber(L, queued ? 1 : 0);
		if (queued && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}
	const bool ok = runOnMainWindowThread(
	    [title, runtime, worldId, resolvedFileName](MainWindow *) -> bool
	    {
		    TextChildWindow *text = findNotepadWindow(title, runtime, worldId);
		    if (!text || !text->editor())
			    return false;
		    QString error;
		    return text->saveToFile(resolvedFileName, &error);
	    },
	    false, true);
	lua_pushnumber(L, ok ? 1 : 0);
	return 1;
}

static int luaSelectCommand(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
		return 0;
	enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime,
	                                             [](const WorldRuntime &targetRuntime)
	                                             {
		                                             WorldView *view = targetRuntime.view();
		                                             if (!view)
			                                             return;
		                                             view->focusInput();
		                                             if (QPlainTextEdit *input = view->inputEditor())
			                                             input->selectAll();
	                                             });
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::CommandUiSnapshot snapshot;
		if (resolveCommandUiSnapshotLightForApi(engine, runtime, snapshot))
		{
			const int endColumn =
			    snapshot.commandInputText.isEmpty() ? 0 : sizeToInt(snapshot.commandInputText.size());
			updateCachedCommandUiSnapshot(engine,
			                              [endColumn](WorldRuntime::CommandUiSnapshot &cached)
			                              {
				                              cached.inputSelectionStartColumn = 1;
				                              cached.inputSelectionEndColumn   = endColumn;
			                              });
		}
	}
	return 0;
}

static int luaSendPkt(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	size_t           packetLength = 0;
	const char      *packetData   = luaL_checklstring(L, 1, &packetLength);
	const QByteArray payload(packetData, static_cast<int>(packetLength));
	bool             connected = false;
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::RuntimeCountersSnapshot snapshot;
		connected = resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot) &&
		            snapshot.connectPhase == WorldRuntime::eConnectConnectedToMud;
	}
	else
	{
		connected = runOnRuntimeThread(
		    runtime,
		    [&]() -> bool { return runtime->connectPhase() == WorldRuntime::eConnectConnectedToMud; }, false);
	}
	if (!connected)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime,
	                                             [payload](WorldRuntime &targetRuntime)
	                                             {
		                                             if (targetRuntime.connectPhase() ==
		                                                 WorldRuntime::eConnectConnectedToMud)
			                                             targetRuntime.sendToWorld(payload);
	                                             });
	incrementCallbackOutboundPacketSnapshot(engine, runtime, payload.size(), 0);
	lua_pushnumber(L, eOK);
	return 1;
}

static int luaSetBackgroundColour(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	const long newColour = luaL_checkinteger(L, 1);
	if (activeCallbackContextConst(engine))
	{
		long oldColour = 0;
		if (!tryResolveCallbackBackgroundColourFromCache(engine, oldColour) &&
		    !callbackNoFlushRuntimeReadBridgeForbidden(engine, true))
		{
			oldColour = runOnRuntimeThreadNoDeferredFlush(
			    runtime, [&]() -> long { return runtime->backgroundColour(); }, 0L);
		}
		enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime, [newColour](WorldRuntime &targetRuntime)
		                                             { targetRuntime.setBackgroundColour(newColour); });
		cacheCallbackBackgroundColour(engine, newColour);
		updateCallbackRuntimeSnapshot(engine, [newColour](WorldRuntime::RuntimeCountersSnapshot &snapshot)
		                              { snapshot.backgroundColour = newColour; });
		updateCallbackWorldAttributeSnapshot(engine, QStringLiteral("output_background_colour"),
		                                     QString::number(newColour), false);
		lua_pushnumber(L, static_cast<lua_Number>(oldColour));
		return 1;
	}
	const long oldColour = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [=]() -> int
	    {
		    const int previous = static_cast<int>(runtime->backgroundColour());
		    runtime->setBackgroundColour(newColour);
		    return previous;
	    },
	    0);
	lua_pushnumber(L, static_cast<lua_Number>(oldColour));
	return 1;
}

