static int luaTransparency(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	const long    key     = luaL_checkinteger(L, 1);
	const int     amount  = static_cast<int>(luaL_checkinteger(L, 2));
	const int     clamped = qBound(0, amount, 255);
	const auto    applyTransparency = [key, clamped](MainWindow *window) -> bool
	{
		// Use the same Qt window-mask/opacity path on all platforms.
		if (key != -1)
		{
			const auto    packed = static_cast<QMudColorRef>(key);
			const QColor  keyColor(qmudRed(packed), qmudGreen(packed), qmudBlue(packed));
			const QPixmap snapshot = window->grab();
			const QImage  image    = snapshot.toImage();
			const QBitmap mask =
			    QBitmap::fromImage(image.createMaskFromColor(keyColor.rgb(), Qt::MaskOutColor));
			window->setMask(mask);
			window->setAttribute(Qt::WA_TranslucentBackground, true);
		}
		else
		{
			window->clearMask();
			window->setAttribute(Qt::WA_TranslucentBackground, false);
		}
		window->setWindowOpacity(static_cast<qreal>(clamped) / 255.0);
		return true;
	};
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		QPointer<QCoreApplication> app = QCoreApplication::instance();
		QPointer<WorldRuntime>     runtimeGuard(runtime);
		const bool                 queued = app && QMetaObject::invokeMethod(
		                                               app.data(),
		                                               [runtimeGuard, callbackPluginId, requestId, applyTransparency]
		                                               {
			                               WorldRuntime *targetRuntime = runtimeGuard.data();
			                               if (!targetRuntime)
				                               return;
			                               MainWindow *window = resolveMainWindow();
			                               const bool  ok     = window && applyTransparency(window);
			                               emitPluginAsyncResult(*targetRuntime, callbackPluginId, requestId,
			                                                     QStringLiteral("Transparency"), ok,
			                                                     ok ? eOK : eBadParameter);
		                                               },
		                                               Qt::QueuedConnection);
		lua_pushboolean(L, queued);
		if (queued && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}
	const bool ok = runOnMainWindowThread([applyTransparency](MainWindow *window) -> bool
	                                      { return applyTransparency(window); }, false, true);
	lua_pushboolean(L, ok);
	return 1;
}

static int luaTextRectangle(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}

	const long left              = luaL_checkinteger(L, 1);
	const long top               = luaL_checkinteger(L, 2);
	const long right             = luaL_checkinteger(L, 3);
	const long bottom            = luaL_checkinteger(L, 4);
	const long borderOffset      = luaL_checkinteger(L, 5);
	const long borderColour      = luaL_checkinteger(L, 6);
	const long borderWidth       = luaL_checkinteger(L, 7);
	const long outsideFillColour = luaL_checkinteger(L, 8);
	const long outsideFillStyle  = luaL_checkinteger(L, 9);

	if (qmudValidateBrushStyle(outsideFillStyle, borderColour, outsideFillColour) != eOK)
	{
		lua_pushnumber(L, eBrushStyleNotValid);
		return 1;
	}

	WorldRuntime::TextRectangleSettings settings;
	settings.left              = static_cast<int>(left);
	settings.top               = static_cast<int>(top);
	settings.right             = static_cast<int>(right);
	settings.bottom            = static_cast<int>(bottom);
	settings.borderOffset      = static_cast<int>(borderOffset);
	settings.borderColour      = static_cast<int>(borderColour);
	settings.borderWidth       = static_cast<int>(borderWidth);
	settings.outsideFillColour = static_cast<int>(outsideFillColour);
	settings.outsideFillStyle  = static_cast<int>(outsideFillStyle);
	WorldRuntime::CommandUiSnapshot snapshot;
	static_cast<void>(resolveCommandUiSnapshotForApi(engine, runtime, snapshot));
	enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime, [settings](WorldRuntime &targetRuntime)
	                                             { targetRuntime.setTextRectangle(settings); });
	updateCachedCommandUiSnapshot(engine,
	                              [settings](WorldRuntime::CommandUiSnapshot &cached)
	                              {
		                              cached.textRectangleLeft              = settings.left;
		                              cached.textRectangleTop               = settings.top;
		                              cached.textRectangleRight             = settings.right;
		                              cached.textRectangleBottom            = settings.bottom;
		                              cached.textRectangleBorderOffset      = settings.borderOffset;
		                              cached.textRectangleBorderWidth       = settings.borderWidth;
		                              cached.textRectangleOutsideFillColour = settings.outsideFillColour;
		                              cached.textRectangleOutsideFillStyle  = settings.outsideFillStyle;
		                              cached.textRectangleBorderColour      = settings.borderColour;
	                              });

	lua_pushnumber(L, eOK);
	return 1;
}

