static int luaSetToolBarPosition(lua_State *L)
{
	struct ToolBarDockState
	{
			Qt::ToolBarArea area{Qt::TopToolBarArea};
			QPoint          pos;
			bool            floating{false};
	};
	static QHash<QToolBar *, ToolBarDockState> s_toolbarStates;
	static QSet<QToolBar *>                    s_toolbarStateHooks;
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	const int     which   = static_cast<int>(luaL_checkinteger(L, 1));
	const bool    doFloat = optBool(L, 2, false);
	const int     side    = static_cast<int>(luaL_checkinteger(L, 3));
	const int     top     = static_cast<int>(luaL_checkinteger(L, 4));
	const int     left    = static_cast<int>(luaL_checkinteger(L, 5));

	const auto    applyToolBarPosition = [which, doFloat, side, top, left](MainWindow *frame) -> int
	{
		QToolBar    *toolBar = nullptr;
		QDockWidget *dock    = nullptr;
		switch (which)
		{
		case 1:
			toolBar = frame->mainToolbar();
			break;
		case 2:
			toolBar = frame->worldToolbar();
			break;
		case 3:
			toolBar = frame->activityToolbar();
			break;
		case 4:
			dock = frame->infoDock();
			break;
		default:
			return eBadParameter;
		}

		if (toolBar && !s_toolbarStateHooks.contains(toolBar))
		{
			s_toolbarStateHooks.insert(toolBar);
			auto *toolbarStates     = &s_toolbarStates;
			auto *toolbarStateHooks = &s_toolbarStateHooks;
			QObject::connect(toolBar, &QObject::destroyed, toolBar,
			                 [toolbarStates, toolbarStateHooks](QObject *destroyed)
			                 {
				                 auto *removed = qobject_cast<QToolBar *>(destroyed);
				                 if (!removed)
					                 return;
				                 toolbarStates->remove(removed);
				                 toolbarStateHooks->remove(removed);
			                 });
		}

		if (dock)
		{
			if (doFloat)
			{
				if (side != 1 && side != 3)
					return eBadParameter;
				dock->setFloating(true);
				const QPoint pos = frame->mapToGlobal(QPoint(left, top));
				dock->move(pos);
			}
			else
			{
				Qt::DockWidgetArea area;
				switch (side)
				{
				case 1:
				case 0:
					area = Qt::TopDockWidgetArea;
					break;
				case 2:
					area = Qt::BottomDockWidgetArea;
					break;
				case 3:
					area = Qt::LeftDockWidgetArea;
					break;
				case 4:
					area = Qt::RightDockWidgetArea;
					break;
				default:
					return eBadParameter;
				}
				frame->addDockWidget(area, dock);
			}
			return eOK;
		}

		if (!toolBar)
			return eBadParameter;

		Qt::ToolBarArea area = Qt::TopToolBarArea;
		switch (side)
		{
		case 1:
		case 0:
			area = Qt::TopToolBarArea;
			break;
		case 2:
			area = Qt::BottomToolBarArea;
			break;
		case 3:
			area = Qt::LeftToolBarArea;
			break;
		case 4:
			area = Qt::RightToolBarArea;
			break;
		default:
			return eBadParameter;
		}

		if (doFloat)
		{
			if (side != 1 && side != 3)
				return eBadParameter;
			frame->removeToolBar(toolBar);
			toolBar->setFloatable(true);
			toolBar->setMovable(true);
			toolBar->setParent(frame);
			toolBar->setWindowFlags(Qt::Tool);
			toolBar->setOrientation(side == 3 ? Qt::Vertical : Qt::Horizontal);
			toolBar->show();
			const QPoint pos = frame->mapToGlobal(QPoint(left, top));
			toolBar->move(pos);
			ToolBarDockState state;
			state.area     = area;
			state.pos      = QPoint(left, top);
			state.floating = true;
			s_toolbarStates.insert(toolBar, state);
		}
		else
		{
			toolBar->setWindowFlags(Qt::Widget);
			frame->addToolBar(area, toolBar);
			toolBar->setOrientation(
			    area == Qt::LeftToolBarArea || area == Qt::RightToolBarArea ? Qt::Vertical : Qt::Horizontal);

			ToolBarDockState state;
			state.area     = area;
			state.pos      = QPoint(left, top);
			state.floating = false;
			s_toolbarStates.insert(toolBar, state);

			QVector<QToolBar *> areaToolbars;
			for (const QVector known = {frame->mainToolbar(), frame->worldToolbar(),
			                            frame->activityToolbar()};
			     QToolBar *candidate : known)
			{
				if (!candidate)
					continue;
				const auto it = s_toolbarStates.constFind(candidate);
				if (it == s_toolbarStates.constEnd())
					continue;
				if (it->floating || it->area != area)
					continue;
				areaToolbars.append(candidate);
			}

			if (!areaToolbars.isEmpty())
			{
				std::ranges::sort(areaToolbars,
				                  [&](QToolBar *a, QToolBar *b)
				                  {
					                  const ToolBarDockState &sa = s_toolbarStates.value(a);
					                  const ToolBarDockState &sb = s_toolbarStates.value(b);
					                  const int               primaryA =
					                      area == Qt::LeftToolBarArea || area == Qt::RightToolBarArea
					                          ? sa.pos.y()
					                          : sa.pos.x();
					                  const int primaryB =
					                      area == Qt::LeftToolBarArea || area == Qt::RightToolBarArea
					                          ? sb.pos.y()
					                          : sb.pos.x();
					                  return primaryA < primaryB;
				                  });
				for (QToolBar *candidate : areaToolbars)
					frame->removeToolBar(candidate);
				for (QToolBar *candidate : areaToolbars)
					frame->addToolBar(area, candidate);
			}
		}

		return eOK;
	};

	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		QPointer<QCoreApplication> app = QCoreApplication::instance();
		QPointer<WorldRuntime>     runtimeGuard(runtime);
		const bool                 queued =
		    app && QMetaObject::invokeMethod(
		               app.data(),
		               [runtimeGuard, callbackPluginId, requestId, applyToolBarPosition]
		               {
			               WorldRuntime *targetRuntime = runtimeGuard.data();
			               if (!targetRuntime)
				               return;
			               MainWindow *frame  = resolveMainWindow();
			               const int   result = frame ? applyToolBarPosition(frame) : eBadParameter;
			               emitPluginAsyncResult(*targetRuntime, callbackPluginId, requestId,
			                                     QStringLiteral("SetToolBarPosition"), result == eOK, result);
		               },
		               Qt::QueuedConnection);
		invalidateCachedCommandUiSnapshot(engine);
		lua_pushnumber(L, queued ? eOK : eBadParameter);
		if (queued && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}

	const int result = runOnMainWindowThread([applyToolBarPosition](MainWindow *frame) -> int
	                                         { return applyToolBarPosition(frame); }, eBadParameter, true);
	invalidateCachedCommandUiSnapshot(engine);
	lua_pushnumber(L, result);
	return 1;
}

static int luaSetChatOption(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eChatIDNotFound);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eChatIDNotFound);
		return 1;
	}
	const long    id     = luaL_checkinteger(L, 1);
	const QString option = QString::fromUtf8(luaL_checkstring(L, 2));
	const QString value  = luaOptionValue(L, 3);
	if (activeCallbackContextConst(engine))
	{
		QList<long> ids;
		if (!resolveChatConnectionIdsForApi(engine, runtime, ids) || !ids.contains(id))
		{
			lua_pushnumber(L, eChatIDNotFound);
			return 1;
		}

		const QString name = option.trimmed().toLower();
		QVariant      cachedValue;
		int           cachedInfoType = 0;

		if (name == QStringLiteral("can_send_commands") || name == QStringLiteral("can_send_files") ||
		    name == QStringLiteral("can_snoop") || name == QStringLiteral("ignore") ||
		    name == QStringLiteral("served") || name == QStringLiteral("private") ||
		    name == QStringLiteral("user"))
		{
			if (!parseCallbackChatNumericOption(name, value, cachedValue, cachedInfoType))
			{
				lua_pushnumber(L, eOptionOutOfRange);
				return 1;
			}
		}
		else if (name == QStringLiteral("server") || name == QStringLiteral("username") ||
		         name == QStringLiteral("version") || name == QStringLiteral("address"))
		{
			lua_pushnumber(L, ePluginCannotSetOption);
			return 1;
		}
		else if (name != QStringLiteral("group"))
		{
			lua_pushnumber(L, eUnknownOption);
			return 1;
		}
		else
		{
			cachedValue    = value.trimmed();
			cachedInfoType = 3;
		}

		const int results = enqueueRuntimeThreadAsyncOkStatusResult(
		    L, engine, runtime, QStringLiteral("SetChatOption"), eChatIDNotFound,
		    [id, option, value](WorldRuntime &targetRuntime) -> int
		    { return targetRuntime.chatSetOption(id, option, value); });
		if (lua_tointeger(L, -results) != eOK)
			return results;
		cacheCallbackChatOptionValue(engine, id, option, cachedValue);
		if (cachedInfoType > 0)
		{
			const QVariant infoValue = cachedInfoType == 3 || cachedInfoType == 46
			                               ? cachedValue
			                               : QVariant(cachedValue.toLongLong() != 0);
			cacheCallbackChatInfoValue(engine, id, cachedInfoType, infoValue);
		}
		return results;
	}
	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime, [=]() -> int { return runtime->chatSetOption(id, option, value); }, eChatIDNotFound);
	lua_pushnumber(L, result);
	return 1;
}

