static int luaSetCommand(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	const QString message = QString::fromUtf8(luaL_checkstring(L, 1));
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::CommandUiSnapshot snapshot;
		if (!resolveCommandUiSnapshotLightForApi(engine, runtime, snapshot) || !snapshot.hasView)
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		if (!snapshot.commandInputText.isEmpty())
		{
			lua_pushnumber(L, eCommandNotEmpty);
			return 1;
		}
		enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime,
		                                             [message](const WorldRuntime &targetRuntime)
		                                             {
			                                             if (WorldView *view = targetRuntime.view())
				                                             view->setInputText(message, true);
		                                             });
		const int cursorColumn = sizeToInt(message.size()) + 1;
		updateCachedCommandUiSnapshot(engine,
		                              [message, cursorColumn](WorldRuntime::CommandUiSnapshot &cached)
		                              {
			                              cached.commandInputText          = message;
			                              cached.inputSelectionStartColumn = cursorColumn;
			                              cached.inputSelectionEndColumn   = 0;
		                              });
		lua_pushnumber(L, eOK);
		return 1;
	}
	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [=]() -> int
	    {
		    WorldView *view = runtime->view();
		    if (!view)
			    return eBadParameter;
		    if (!view->inputText().isEmpty())
			    return eCommandNotEmpty;
		    view->setInputText(message, true);
		    return eOK;
	    },
	    eBadParameter);
	lua_pushnumber(L, result);
	return 1;
}

static int luaSetCommandSelection(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	const int first = static_cast<int>(luaL_checkinteger(L, 1));
	const int last  = static_cast<int>(luaL_checkinteger(L, 2));
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::CommandUiSnapshot snapshot;
		if (!resolveCommandUiSnapshotLightForApi(engine, runtime, snapshot) || !snapshot.hasView)
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}

		const int maxPos             = sizeToInt(snapshot.commandInputText.size());
		const int boundedStartOffset = qBound(0, first - 1, maxPos);
		const int boundedEndOffset   = qBound(0, last, maxPos);
		const int startColumn        = boundedStartOffset + 1;
		const int endColumn          = boundedEndOffset <= boundedStartOffset ? 0 : boundedEndOffset;

		enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime,
		                                             [first, last](const WorldRuntime &targetRuntime)
		                                             {
			                                             if (WorldView *view = targetRuntime.view())
				                                             static_cast<void>(
				                                                 view->setCommandSelection(first, last));
		                                             });
		updateCachedCommandUiSnapshot(engine,
		                              [startColumn, endColumn](WorldRuntime::CommandUiSnapshot &cached)
		                              {
			                              cached.inputSelectionStartColumn = startColumn;
			                              cached.inputSelectionEndColumn   = endColumn;
		                              });
		lua_pushnumber(L, eOK);
		return 1;
	}
	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [=]() -> int
	    {
		    if (WorldView *view = runtime->view())
			    return view->setCommandSelection(first, last);
		    return eBadParameter;
	    },
	    eBadParameter);
	lua_pushnumber(L, result);
	return 1;
}

static int luaSetCommandWindowHeight(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	const int height = static_cast<int>(luaL_checkinteger(L, 1));
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::CommandUiSnapshot snapshot;
		if (!resolveCommandUiSnapshotLightForApi(engine, runtime, snapshot) || !snapshot.hasView)
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		if (height < 0 || snapshot.viewHeight <= 0 || (snapshot.viewHeight - height) < 20)
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime,
		                                             [height](const WorldRuntime &targetRuntime)
		                                             {
			                                             if (WorldView *view = targetRuntime.view())
				                                             static_cast<void>(
				                                                 view->setCommandWindowHeight(height));
		                                             });
		updateCachedCommandUiSnapshot(
		    engine,
		    [height](WorldRuntime::CommandUiSnapshot &cached)
		    {
			    const int outputHeight =
			        qMax(20, cached.viewHeight > 0 ? cached.viewHeight - height : cached.outputClientHeight);
			    cached.outputClientHeight   = outputHeight;
			    cached.outputTextRectBottom = qMin(cached.outputTextRectBottom, outputHeight);
		    });
		lua_pushnumber(L, eOK);
		return 1;
	}
	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [=]() -> int
	    {
		    if (WorldView *view = runtime->view())
			    return view->setCommandWindowHeight(height);
		    return eBadParameter;
	    },
	    eBadParameter);
	lua_pushnumber(L, result);
	return 1;
}

