static int luaSetCustomColourName(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	const int     index = static_cast<int>(luaL_checkinteger(L, 1));
	const QString name  = QString::fromUtf8(luaL_checkstring(L, 2));
	if (activeCallbackContextConst(engine))
	{
		if (index < 1 || index > MAX_CUSTOM)
		{
			lua_pushnumber(L, eOptionOutOfRange);
			return 1;
		}
		const QString trimmed = name.trimmed();
		if (trimmed.isEmpty())
		{
			lua_pushnumber(L, eNoNameSpecified);
			return 1;
		}
		if (trimmed.size() > 30)
		{
			lua_pushnumber(L, eInvalidObjectLabel);
			return 1;
		}
		enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime, [index, name](WorldRuntime &targetRuntime)
		    { static_cast<void>(targetRuntime.setCustomColourName(index, name)); });
		cacheCallbackCustomColourName(engine, index, trimmed);
		lua_pushnumber(L, eOK);
		return 1;
	}
	lua_pushnumber(L, runOnRuntimeThreadDeferredMutation(
	                      engine, runtime, [=]() -> int { return runtime->setCustomColourName(index, name); },
	                      eBadParameter));
	return 1;
}

static int luaBase64Decode(lua_State *L)
{
	const auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr; !runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	const QString input      = QString::fromUtf8(luaL_checkstring(L, 1));
	QByteArray    normalized = input.toUtf8();
	normalized.replace('\r', "");
	normalized.replace('\n', "");
	const auto [decoded, decodingStatus] =
	    QByteArray::fromBase64Encoding(normalized, QByteArray::AbortOnBase64DecodingErrors);
	if (decodingStatus != QByteArray::Base64DecodingStatus::Ok)
	{
		lua_pushnil(L);
		return 1;
	}
	lua_pushstring(L, QString::fromUtf8(decoded).toUtf8().constData());
	return 1;
}

static int luaBase64Encode(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (!runtime)
	{
		lua_pushstring(L, "");
		return 1;
	}
	const QString input     = QString::fromUtf8(luaL_checkstring(L, 1));
	const bool    multiLine = optBool(L, 2, false);
	const QString encoded   = WorldRuntime::base64Encode(input, multiLine);
	lua_pushstring(L, encoded.toUtf8().constData());
	return 1;
}

static int luaAppendToNotepad(lua_State *L)
{
	const QString title    = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString contents = concatLuaArgs(L, 2);
	auto         *engine   = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime  = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	const QString worldId = resolveWorldAttributeValueForApi(engine, runtime, QStringLiteral("id")).trimmed();
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		const bool    accepted         = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [title, contents, callbackPluginId, requestId](WorldRuntime &targetRuntime)
		    {
			    const QPointer<WorldRuntime> runtimeGuard(&targetRuntime);
			    const bool                   queued = enqueueOnMainThread(
			        [runtimeGuard, title, contents, callbackPluginId, requestId]()
			        {
				        WorldRuntime *targetRuntimeOnMain = runtimeGuard.data();
				        if (!targetRuntimeOnMain)
					        return;
				        bool ok = false;
				        if (MainWindow *mw = resolveMainWindow())
					        ok = mw->appendToNotepad(title, contents, false, targetRuntimeOnMain);
				        emitPluginAsyncResult(*targetRuntimeOnMain, callbackPluginId, requestId,
				                              QStringLiteral("AppendToNotepad"), ok, 0);
			        });
			    if (!queued)
			    {
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId,
				                          QStringLiteral("AppendToNotepad"), false, 0);
			    }
		    });
		if (accepted)
			cacheCallbackNotepadDocumentTextAfterWrite(engine, runtime, title, worldId, contents, false);
		lua_pushboolean(L, accepted);
		if (accepted && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}
	const bool ok =
	    runOnMainWindowThread([title, contents, runtime](MainWindow *mw) -> bool
	                          { return mw->appendToNotepad(title, contents, false, runtime); }, false);
	if (ok)
	{
		cacheCallbackNotepadDocumentTextAfterWrite(engine, runtime, title, worldId, contents, false);
	}
	lua_pushboolean(L, ok);
	return 1;
}

