static int luaGetConnectDuration(lua_State *L)
{
	const auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	WorldRuntime::RuntimeCountersSnapshot snapshot;
	if (!resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot))
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	if (snapshot.connectPhase != WorldRuntime::eConnectConnectedToMud || !snapshot.connectTime.isValid())
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	const qint64 seconds = snapshot.connectTime.secsTo(QDateTime::currentDateTime());
	lua_pushnumber(L, static_cast<lua_Number>(seconds));
	return 1;
}

static int luaGetConnectTime(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	QDateTime     connectTime;
	if (runtime)
	{
		WorldRuntime::RuntimeCountersSnapshot snapshot;
		if (resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot))
			connectTime = snapshot.connectTime;
	}
	if (!connectTime.isValid())
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	lua_pushnumber(L, toLuaSystemTime(connectTime));
	return 1;
}

