static quint64 nextPluginAsyncResultRequestId()
{
	static std::atomic<quint64> nextRequestId{1};
	return nextRequestId.fetch_add(1, std::memory_order_relaxed);
}

static QString encodeWindowOutputMetricsPayload(const WorldRuntime::WindowOutputMetrics &metrics)
{
	return QStringLiteral("left=%1;top=%2;right=%3;bottom=%4;width=%5;height=%6;line_count=%7;hotspot_count=%"
	                      "8;has_output=%9")
	    .arg(metrics.left)
	    .arg(metrics.top)
	    .arg(metrics.right)
	    .arg(metrics.bottom)
	    .arg(metrics.width)
	    .arg(metrics.height)
	    .arg(metrics.lineCount)
	    .arg(metrics.hotspotCount)
	    .arg(metrics.hasOutput ? 1 : 0);
}

static QString encodeDatabaseFieldAsyncPayload(const QVariant &value)
{
	if (!value.isValid() || value.isNull())
		return QStringLiteral("null:");
	switch (value.typeId())
	{
	case QMetaType::Bool:
		return QStringLiteral("bool:%1").arg(value.toBool() ? 1 : 0);
	case QMetaType::Float:
	case QMetaType::Int:
	case QMetaType::LongLong:
	case QMetaType::UInt:
	case QMetaType::ULongLong:
	case QMetaType::Double:
		return QStringLiteral("number:%1").arg(QString::number(value.toDouble(), 'g', 17));
	case QMetaType::QByteArray:
		return QStringLiteral("bytes:%1")
		    .arg(QString::fromLatin1(value.toByteArray().toBase64(QByteArray::Base64Encoding)));
	default:
		return QStringLiteral("string:%1").arg(value.toString());
	}
}

static QString encodeAsyncPayloadField(const QString &value)
{
	return QString::fromLatin1(QUrl::toPercentEncoding(value));
}

static QString encodeAsyncKeyValuePayload(const QList<QPair<QString, QString>> &fields)
{
	QStringList parts;
	parts.reserve(fields.size());
	for (const auto &field : fields)
	{
		parts.push_back(QStringLiteral("%1=%2").arg(field.first, encodeAsyncPayloadField(field.second)));
	}
	return parts.join(QLatin1Char(';'));
}

static void emitPluginAsyncResult(WorldRuntime &runtime, const QString &pluginId, const quint64 requestId,
                                  const QString &apiName, const bool ok, const int errorCode,
                                  const QString &payload)
{
	if (requestId == 0 || pluginId.trimmed().isEmpty() || apiName.trimmed().isEmpty())
		return;
	runtime.dispatchPluginAsyncResult(pluginId, requestId, apiName, ok, errorCode, payload);
}

static QColor colourFromRef(const int value)
{
	const int r = value & 0xFF;
	const int g = value >> 8 & 0xFF;
	const int b = value >> 16 & 0xFF;
	return {r, g, b};
}

static int colourRefFromQColor(const QColor &color)
{
	return color.blue() << 16 | color.green() << 8 | color.red();
}

static int luaUtilsTimer(lua_State *L)
{
	thread_local QElapsedTimer timer;
	if (!timer.isValid())
		timer.start();
	const double seconds = static_cast<double>(timer.nsecsElapsed()) / 1000000000.0;
	lua_pushnumber(L, seconds);
	return 1;
}

static int luaUtilsFontPicker(lua_State *L)
{
	auto         *engine     = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime    = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	const char   *fontname   = luaL_optstring(L, 1, "");
	const int     fontsize   = static_cast<int>(luaL_optnumber(L, 2, 10));
	const int     fontcolour = static_cast<int>(luaL_optnumber(L, 3, 0));

	const QFont   initialFont(QString::fromUtf8(fontname), fontsize);
	const QColor  initialColour = colourFromRef(fontcolour);
	struct FontPickerResult
	{
			bool   accepted{false};
			QFont  font;
			QColor colour;
	};
	const auto pickFont = [initialFont, initialColour](MainWindow *frame) -> FontPickerResult
	{
		FontPickerResult pickerResult;
		bool             ok = false;
		pickerResult.font   = QFontDialog::getFont(&ok, initialFont, frame, QStringLiteral("Select Font"));
		if (!ok)
			return pickerResult;
		pickerResult.accepted = true;
		pickerResult.colour   = QColorDialog::getColor(initialColour, frame, QStringLiteral("Select Colour"));
		if (!pickerResult.colour.isValid())
			pickerResult.colour = initialColour;
		return pickerResult;
	};
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		quint64    requestId = 0;
		const bool accepted  = enqueueMainWindowAsyncResult(
		    engine, runtime, QStringLiteral("FontPicker"),
		    [pickFont](MainWindow *frame) -> PluginAsyncDialogResult
		    {
			    const FontPickerResult result = pickFont(frame);
			    if (!result.accepted)
				    return {false, -1, QString()};
			    const QString payload = encodeAsyncKeyValuePayload({
			        {QStringLiteral("name"),      result.font.family()                               },
			        {QStringLiteral("style"),     QFontDatabase::styleString(result.font)            },
			        {QStringLiteral("size"),      QString::number(result.font.pointSize())           },
			        {QStringLiteral("colour"),    QString::number(colourRefFromQColor(result.colour))},
			        {QStringLiteral("bold"),      QString::number(result.font.bold() ? 1 : 0)        },
			        {QStringLiteral("italic"),    QString::number(result.font.italic() ? 1 : 0)      },
			        {QStringLiteral("underline"), QString::number(result.font.underline() ? 1 : 0)   },
			        {QStringLiteral("strikeout"), QString::number(result.font.strikeOut() ? 1 : 0)   },
			        {QStringLiteral("charset"),   QStringLiteral("0")                                }
                });
			    return {true, eOK, payload};
		    },
		    requestId);
		lua_pushnil(L);
		if (accepted && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}
	const FontPickerResult result = runOnMainWindowThreadAllowNestedEvents(
	    [&](MainWindow *frame) -> FontPickerResult { return pickFont(frame); }, {});
	if (!result.accepted)
	{
		lua_pushnil(L);
		return 1;
	}

	lua_newtable(L);

	const QString family    = result.font.family();
	QByteArray    nameBytes = family.toUtf8();
	lua_pushlstring(L, nameBytes.constData(), nameBytes.size());
	lua_setfield(L, -2, "name");

	const QString styleName  = QFontDatabase::styleString(result.font);
	QByteArray    styleBytes = styleName.toUtf8();
	lua_pushlstring(L, styleBytes.constData(), styleBytes.size());
	lua_setfield(L, -2, "style");

	lua_pushnumber(L, result.font.pointSize());
	lua_setfield(L, -2, "size");

	lua_pushnumber(L, colourRefFromQColor(result.colour));
	lua_setfield(L, -2, "colour");

	lua_pushboolean(L, result.font.bold());
	lua_setfield(L, -2, "bold");

	lua_pushboolean(L, result.font.italic());
	lua_setfield(L, -2, "italic");

	lua_pushboolean(L, result.font.underline());
	lua_setfield(L, -2, "underline");

	lua_pushboolean(L, result.font.strikeOut());
	lua_setfield(L, -2, "strikeout");

	lua_pushnumber(L, 0);
	lua_setfield(L, -2, "charset");

	return 1;
}

static int luaUtilsMsgBoxInternal(lua_State *L)
{
	auto         *engine      = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime     = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	size_t        boxmsgLen   = 0;
	size_t        boxtitleLen = 0;
	const char   *boxmsg      = luaL_checklstring(L, 1, &boxmsgLen);
	const char   *boxtitle    = luaL_optlstring(L, 2, "QMud", &boxtitleLen);
	const char   *boxtype     = luaL_optstring(L, 3, "ok");
	const char   *boxicon     = luaL_optstring(L, 4, "!");
	const int     boxdefault  = static_cast<int>(luaL_optnumber(L, 5, 1));

	if (boxmsgLen > 1000)
		luaL_error(L, "msgbox message too long (max 1000 characters)");
	if (boxtitleLen > 100)
		luaL_error(L, "msgbox title too long (max 100 characters)");

	const QString                type          = QString::fromUtf8(boxtype).toLower();
	QMessageBox::StandardButtons buttons       = QMessageBox::NoButton;
	QMessageBox::StandardButton  defaultButton = QMessageBox::NoButton;

	if (type == QStringLiteral("ok"))
	{
		buttons       = QMessageBox::Ok;
		defaultButton = QMessageBox::Ok;
	}
	else if (type == QStringLiteral("abortretryignore"))
	{
		buttons = QMessageBox::Abort | QMessageBox::Retry | QMessageBox::Ignore;
		if (boxdefault == 1)
			defaultButton = QMessageBox::Abort;
		else if (boxdefault == 2)
			defaultButton = QMessageBox::Retry;
		else if (boxdefault == 3)
			defaultButton = QMessageBox::Ignore;
		else
			luaL_error(L, "msgbox default button must be 1, 2 or 3");
	}
	else if (type == QStringLiteral("okcancel"))
	{
		buttons = QMessageBox::Ok | QMessageBox::Cancel;
		if (boxdefault == 1)
			defaultButton = QMessageBox::Ok;
		else if (boxdefault == 2)
			defaultButton = QMessageBox::Cancel;
		else
			luaL_error(L, "msgbox default button must be 1 or 2");
	}
	else if (type == QStringLiteral("retrycancel"))
	{
		buttons = QMessageBox::Retry | QMessageBox::Cancel;
		if (boxdefault == 1)
			defaultButton = QMessageBox::Retry;
		else if (boxdefault == 2)
			defaultButton = QMessageBox::Cancel;
		else
			luaL_error(L, "msgbox default button must be 1 or 2");
	}
	else if (type == QStringLiteral("yesno"))
	{
		buttons = QMessageBox::Yes | QMessageBox::No;
		if (boxdefault == 1)
			defaultButton = QMessageBox::Yes;
		else if (boxdefault == 2)
			defaultButton = QMessageBox::No;
		else
			luaL_error(L, "msgbox default button must be 1 or 2");
	}
	else if (type == QStringLiteral("yesnocancel"))
	{
		buttons = QMessageBox::Yes | QMessageBox::No | QMessageBox::Cancel;
		if (boxdefault == 1)
			defaultButton = QMessageBox::Yes;
		else if (boxdefault == 2)
			defaultButton = QMessageBox::No;
		else if (boxdefault == 3)
			defaultButton = QMessageBox::Cancel;
		else
			luaL_error(L, "msgbox default button must be 1, 2 or 3");
	}
	else
	{
		luaL_error(L, "msgbox type unknown");
	}
	const QString     boxMessage = QString::fromUtf8(boxmsg, sizeToInt(static_cast<qsizetype>(boxmsgLen)));
	const QString     boxTitle = QString::fromUtf8(boxtitle, sizeToInt(static_cast<qsizetype>(boxtitleLen)));

	const char        iconChar = asciiToLower(boxicon[0]);
	QMessageBox::Icon icon     = QMessageBox::Warning;
	switch (iconChar)
	{
	case '?':
		icon = QMessageBox::Question;
		break;
	case '!':
		icon = QMessageBox::Warning;
		break;
	case 'i':
		icon = QMessageBox::Information;
		break;
	case '.':
		icon = QMessageBox::Critical;
		break;
	default:
		luaL_error(L, "msgbox icon unknown");
	}

	const auto showMessageBox = [=](MainWindow *frame) -> QMessageBox::StandardButton
	{
		QMessageBox box(icon, boxTitle, boxMessage, buttons, frame);
		if (defaultButton != QMessageBox::NoButton)
			box.setDefaultButton(defaultButton);
		return static_cast<QMessageBox::StandardButton>(box.exec());
	};
	const auto buttonName = [](const QMessageBox::StandardButton button) -> const char *
	{
		switch (button)
		{
		case QMessageBox::Yes:
			return "yes";
		case QMessageBox::No:
			return "no";
		case QMessageBox::Ok:
			return "ok";
		case QMessageBox::Retry:
			return "retry";
		case QMessageBox::Ignore:
			return "ignore";
		case QMessageBox::Cancel:
			return "cancel";
		case QMessageBox::Abort:
			return "abort";
		default:
			return "other";
		}
	};
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		quint64    requestId = 0;
		const bool accepted  = enqueueMainWindowAsyncResult(
		    engine, runtime, QStringLiteral("MsgBox"),
		    [showMessageBox, buttonName](MainWindow *frame) -> PluginAsyncDialogResult
		    {
			    const QMessageBox::StandardButton result = showMessageBox(frame);
			    return {true, eOK, QString::fromLatin1(buttonName(result))};
		    },
		    requestId);
		lua_pushstring(L, "other");
		if (accepted && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}

	const auto result =
	    runOnMainWindowThreadAllowNestedEvents([&](MainWindow *frame) -> QMessageBox::StandardButton
	                                           { return showMessageBox(frame); }, QMessageBox::NoButton);
	const char *out = buttonName(result);

	lua_pushstring(L, out);
	return 1;
}

