static void registerLuaPreloads(lua_State *L)
{
	lua_getglobal(L, "package");
	if (!lua_istable(L, -1))
	{
		lua_pop(L, 1);
		return;
	}
	lua_getfield(L, -1, "preload");
	if (lua_istable(L, -1))
	{
		lua_pushcfunction(L, luaopen_lsqlite3);
		lua_setfield(L, -2, "sqlite3");
		lua_pushcfunction(L, luaopen_lsqlite3);
		lua_setfield(L, -2, "lsqlite3");
		QMudLuacomShim::registerPreload(L);
#ifdef QMUD_BUNDLED_BC
		lua_pushcfunction(L, luaopen_bc);
		lua_setfield(L, -2, "bc");
#endif
	}
	lua_pop(L, 2);
}

static bool requireModuleNoThrow(lua_State *L, const char *moduleName)
{
	if (!L || !moduleName || *moduleName == '\0')
		return false;

	const int stackTop = lua_gettop(L);
	lua_getglobal(L, "require");
	if (!lua_isfunction(L, -1))
	{
		lua_settop(L, stackTop);
		return false;
	}
	lua_pushstring(L, moduleName);
	if (QMudLuaSupport::callLuaProtected(L, 1, 1, 0) != 0)
	{
		lua_settop(L, stackTop);
		return false;
	}

	lua_settop(L, stackTop);
	return true;
}

static void registerSocketLibraries(lua_State *L)
{
	// Load networking modules while package C loaders are still available.
	// When package restrictions are applied afterwards, already-loaded modules
	// remain usable and preserve Mushclient-compatible socket.http behavior.
	(void)requireModuleNoThrow(L, "socket.core");
	(void)requireModuleNoThrow(L, "mime.core");
	(void)requireModuleNoThrow(L, "socket");
	(void)requireModuleNoThrow(L, "mime");
	(void)requireModuleNoThrow(L, "ltn12");
	(void)requireModuleNoThrow(L, "socket.url");
	(void)requireModuleNoThrow(L, "socket.http");
	(void)requireModuleNoThrow(L, "ssl");
	(void)requireModuleNoThrow(L, "ssl.https");
}

static void registerSqliteLibrary(lua_State *L)
{
	// Prefer standard Lua loader path first.
	lua_getglobal(L, "require");
	if (lua_isfunction(L, -1))
	{
		lua_pushstring(L, "sqlite3");
		if (QMudLuaSupport::callLuaProtected(L, 1, 1, 0) == 0)
		{
			lua_pushvalue(L, -1);
			lua_setglobal(L, "sqlite3");
			lua_pushvalue(L, -1);
			lua_setglobal(L, "lsqlite3");
			lua_pop(L, 1);
			return;
		}
		lua_pop(L, 1); // require error
	}
	else
	{
		lua_pop(L, 1);
	}

	// Fallback to bundled sqlite binding; luaopen_lsqlite3 installs sqlite3/lsqlite3 globals.
	lua_pushcfunction(L, luaopen_lsqlite3);
	(void)QMudLuaSupport::callLuaProtected(L, 0, 1, 0);
	lua_pop(L, 1);
}

static void registerBcLibrary(lua_State *L)
{
	// System-first: load distro-provided Lua bc module through Lua's loader path.
	lua_getglobal(L, "require");
	if (lua_isfunction(L, -1))
	{
		lua_pushstring(L, "bc");
		if (QMudLuaSupport::callLuaProtected(L, 1, 1, 0) == 0)
		{
			lua_setglobal(L, "bc");
			return;
		}
		lua_pop(L, 1); // require error
	}
	else
	{
		lua_pop(L, 1);
	}

#ifdef QMUD_BUNDLED_BC
	lua_pushcfunction(L, luaopen_bc);
	if (QMudLuaSupport::callLuaProtected(L, 0, 1, 0) == 0)
		lua_setglobal(L, "bc");
	else
		lua_pop(L, 1);
#endif
}

static void registerLpegLibrary(lua_State *L)
{
	// System-first: load distro-provided lua-lpeg module through Lua's loader path.
	lua_getglobal(L, "require");
	if (lua_isfunction(L, -1))
	{
		lua_pushstring(L, "lpeg");
		if (QMudLuaSupport::callLuaProtected(L, 1, 1, 0) == 0)
		{
			if (lua_istable(L, -1))
			{
				const int lpegIndex = lua_gettop(L);

				lua_getfield(L, lpegIndex, "ptree");
				if (lua_isfunction(L, -1))
					lua_setfield(L, lpegIndex, "print");
				else
					lua_pop(L, 1);

				luaL_getmetatable(L, "lpeg-pattern");
				if (lua_istable(L, -1))
				{
					constexpr const char *kMetaFns[] = {"__add", "__div", "__len", "__mul",
					                                    "__pow", "__sub", "__unm", nullptr};
					for (const char *const *fn = kMetaFns; *fn; ++fn)
					{
						lua_getfield(L, -1, *fn);
						if (lua_isfunction(L, -1))
							lua_setfield(L, lpegIndex, *fn);
						else
							lua_pop(L, 1);
					}
				}
				lua_pop(L, 1);
			}
			lua_setglobal(L, "lpeg");
			return;
		}
		lua_pop(L, 1); // require error
	}
	else
	{
		lua_pop(L, 1);
	}
}

namespace
{
	struct LuaProgressDialog
	{
			QPointer<QProgressDialog> dialog{nullptr};
			int                       step{1};
			bool                      createPending{false};
			QString                   pendingStatus;
			bool                      hasPendingStatus{false};
			bool                      lastKnownCanceled{false};
			bool                      hasLastKnownCanceled{false};
			std::mutex                mutex;
	};

	using LuaProgressDialogHandle = std::shared_ptr<LuaProgressDialog>;

	constexpr auto          kProgressMetaName = "mushclient.progress_dialog_handle";

	LuaProgressDialogHandle progressCheck(lua_State *L)
	{
		auto *ud = static_cast<LuaProgressDialogHandle **>(luaL_checkudata(L, 1, kProgressMetaName));
		if (!ud || !*ud || !(**ud))
		{
			luaL_argerror(L, 1, "progress dialog userdata expected");
			return {};
		}
		return **ud;
	}

	LuaCallbackEngine *progressEngine(lua_State *L)
	{
		return static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	}
} // namespace

static int luaProgressGc(lua_State *L)
{
	if (auto *ud = static_cast<LuaProgressDialogHandle **>(luaL_checkudata(L, 1, kProgressMetaName));
	    ud && *ud && **ud)
	{
		const LuaProgressDialogHandle handle      = **ud;
		auto                         *engine      = progressEngine(L);
		WorldRuntime                 *runtime     = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
		auto                          closeDialog = [handle](MainWindow *) -> bool
		{
			QPointer<QProgressDialog> dialog;
			{
				const std::lock_guard<std::mutex> lock(handle->mutex);
				dialog                       = handle->dialog;
				handle->dialog               = nullptr;
				handle->createPending        = false;
				handle->pendingStatus        = {};
				handle->hasPendingStatus     = false;
				handle->lastKnownCanceled    = false;
				handle->hasLastKnownCanceled = false;
			}
			if (!dialog)
				return false;
			dialog->close();
			delete dialog.data();
			return true;
		};
		if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
		{
			const QString callbackPluginId = engine->pluginId();
			const quint64 requestId = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
			const bool    accepted  = enqueueRuntimeThreadDeferredMutationNoResult(
			    engine, runtime,
			    [closeDialog, callbackPluginId, requestId](WorldRuntime &targetRuntime)
			    {
				    const QPointer<WorldRuntime> runtimeGuard(&targetRuntime);
				    const bool                   queued = enqueueOnMainThread(
				        [runtimeGuard, closeDialog, callbackPluginId, requestId]()
				        {
					        WorldRuntime *targetRuntimeOnMain = runtimeGuard.data();
					        if (!targetRuntimeOnMain)
						        return;
					        const bool closed = closeDialog(nullptr);
					        emitPluginAsyncResult(*targetRuntimeOnMain, callbackPluginId, requestId,
					                              QStringLiteral("ProgressClose"), closed, closed ? eOK : -1);
				        });
				    if (!queued)
				    {
					    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId,
					                          QStringLiteral("ProgressClose"), false, -1);
				    }
			    });
			if (!accepted)
				static_cast<void>(runOnMainWindowThread(closeDialog, false, true));
		}
		else
		{
			static_cast<void>(runOnMainWindowThread(closeDialog, false));
		}
		delete *ud;
		*ud = nullptr;
	}
	return 0;
}

static int luaProgressToString(lua_State *L)
{
	Q_UNUSED(L);
	lua_pushstring(L, "progress_dialog");
	return 1;
}

static int luaProgressNew(lua_State *L)
{
	const QString title = QString::fromUtf8(luaL_optstring(L, 1, "Progress ..."));
	auto *ud = static_cast<LuaProgressDialogHandle **>(lua_newuserdata(L, sizeof(LuaProgressDialogHandle *)));
	*ud      = new LuaProgressDialogHandle(std::make_shared<LuaProgressDialog>());
	const LuaProgressDialogHandle handle         = **ud;
	auto                         *engine         = progressEngine(L);
	WorldRuntime                 *runtime        = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	quint64                       asyncRequestId = 0;

	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		asyncRequestId                 = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		{
			const std::lock_guard<std::mutex> lock(handle->mutex);
			handle->createPending = true;
		}
		const bool accepted = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [title, handle, callbackPluginId, asyncRequestId](WorldRuntime &targetRuntime)
		    {
			    const QPointer<WorldRuntime> runtimeGuard(&targetRuntime);
			    const bool                   queued = enqueueOnMainThread(
			        [runtimeGuard, title, handle, callbackPluginId, asyncRequestId]()
			        {
				        WorldRuntime *targetRuntimeOnMain = runtimeGuard.data();
				        if (!targetRuntimeOnMain)
					        return;

				        QProgressDialog *dialog = nullptr;
				        if (MainWindow *frame = resolveMainWindow())
				        {
					        auto *newDialog = new QProgressDialog(frame);
					        newDialog->setWindowTitle(title);
					        newDialog->setLabelText(QString());
					        newDialog->setCancelButtonText(QStringLiteral("Cancel"));
					        newDialog->setRange(0, 100);
					        newDialog->setValue(0);
					        newDialog->setAutoClose(false);
					        newDialog->setAutoReset(false);
					        QObject::connect(newDialog, &QProgressDialog::canceled, newDialog,
					                         [handle]()
					                         {
						                         const std::lock_guard<std::mutex> lock(handle->mutex);
						                         handle->lastKnownCanceled    = true;
						                         handle->hasLastKnownCanceled = true;
					                         });
					        newDialog->show();
					        dialog = newDialog;
				        }

				        QString pendingStatus;
				        bool    hasPendingStatus = false;
				        {
					        const std::lock_guard<std::mutex> lock(handle->mutex);
					        handle->dialog               = dialog;
					        handle->createPending        = false;
					        handle->lastKnownCanceled    = false;
					        handle->hasLastKnownCanceled = dialog != nullptr;
					        if (dialog && handle->hasPendingStatus)
					        {
						        pendingStatus            = handle->pendingStatus;
						        hasPendingStatus         = true;
						        handle->pendingStatus    = {};
						        handle->hasPendingStatus = false;
					        }
				        }
				        if (dialog && hasPendingStatus)
					        dialog->setLabelText(pendingStatus);

				        const bool ok = dialog != nullptr;
				        emitPluginAsyncResult(*targetRuntimeOnMain, callbackPluginId, asyncRequestId,
				                              QStringLiteral("ProgressNew"), ok, ok ? eOK : -1);
			        });
			    if (!queued)
			    {
				    {
					    const std::lock_guard<std::mutex> lock(handle->mutex);
					    handle->createPending = false;
				    }
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, asyncRequestId,
				                          QStringLiteral("ProgressNew"), false, -1);
			    }
		    });
		if (!accepted)
		{
			const std::lock_guard<std::mutex> lock(handle->mutex);
			handle->createPending = false;
			asyncRequestId        = 0;
		}
	}
	else
	{
		QProgressDialog *dialog = runOnMainWindowThread(
		    [title, handle](MainWindow *frame) -> QProgressDialog *
		    {
			    auto *newDialog = new QProgressDialog(frame);
			    newDialog->setWindowTitle(title);
			    newDialog->setLabelText(QString());
			    newDialog->setCancelButtonText(QStringLiteral("Cancel"));
			    newDialog->setRange(0, 100);
			    newDialog->setValue(0);
			    newDialog->setAutoClose(false);
			    newDialog->setAutoReset(false);
			    QObject::connect(newDialog, &QProgressDialog::canceled, newDialog,
			                     [handle]()
			                     {
				                     const std::lock_guard<std::mutex> lock(handle->mutex);
				                     handle->lastKnownCanceled    = true;
				                     handle->hasLastKnownCanceled = true;
			                     });
			    newDialog->show();
			    return newDialog;
		    },
		    static_cast<QProgressDialog *>(nullptr), false);
		const std::lock_guard<std::mutex> lock(handle->mutex);
		handle->dialog               = dialog;
		handle->createPending        = false;
		handle->lastKnownCanceled    = false;
		handle->hasLastKnownCanceled = dialog != nullptr;
	}

	luaL_getmetatable(L, kProgressMetaName);
	lua_setmetatable(L, -2);
	if (asyncRequestId != 0)
	{
		lua_pushnumber(L, static_cast<lua_Number>(asyncRequestId));
		return 2;
	}
	return 1;
}

static int luaProgressSetStatus(lua_State *L)
{
	const LuaProgressDialogHandle handle = progressCheck(L);
	if (!handle)
		return 0;
	const QString status  = QString::fromUtf8(luaL_checkstring(L, 2));
	auto         *engine  = progressEngine(L);
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		QString       previousPendingStatus;
		bool          hadPendingStatus = false;
		{
			const std::lock_guard<std::mutex> lock(handle->mutex);
			previousPendingStatus    = handle->pendingStatus;
			hadPendingStatus         = handle->hasPendingStatus;
			handle->pendingStatus    = status;
			handle->hasPendingStatus = true;
		}
		const bool accepted = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [handle, status, callbackPluginId, requestId](WorldRuntime &targetRuntime)
		    {
			    const QPointer<WorldRuntime> runtimeGuard(&targetRuntime);
			    const bool                   queued = enqueueOnMainThread(
			        [runtimeGuard, handle, status, callbackPluginId, requestId]()
			        {
				        WorldRuntime *targetRuntimeOnMain = runtimeGuard.data();
				        if (!targetRuntimeOnMain)
					        return;
				        QPointer<QProgressDialog> dialog;
				        bool                      pendingCreate = false;
				        {
					        const std::lock_guard<std::mutex> lock(handle->mutex);
					        dialog        = handle->dialog;
					        pendingCreate = handle->createPending;
					        if (!dialog)
					        {
						        handle->pendingStatus    = status;
						        handle->hasPendingStatus = true;
					        }
					        else
					        {
						        handle->pendingStatus    = {};
						        handle->hasPendingStatus = false;
					        }
				        }
				        const bool applied = dialog != nullptr;
				        if (dialog)
					        dialog->setLabelText(status);
				        const bool ok = applied || pendingCreate;
				        emitPluginAsyncResult(*targetRuntimeOnMain, callbackPluginId, requestId,
				                              QStringLiteral("ProgressSetStatus"), ok, ok ? eOK : -1);
			        });
			    if (!queued)
			    {
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId,
				                          QStringLiteral("ProgressSetStatus"), false, -1);
			    }
		    });
		if (!accepted)
		{
			const std::lock_guard<std::mutex> lock(handle->mutex);
			handle->pendingStatus    = previousPendingStatus;
			handle->hasPendingStatus = hadPendingStatus;
		}
		return 0;
	}

	QPointer<QProgressDialog> dialog;
	{
		const std::lock_guard<std::mutex> lock(handle->mutex);
		dialog = handle->dialog;
		if (!dialog && handle->createPending)
		{
			handle->pendingStatus    = status;
			handle->hasPendingStatus = true;
		}
	}
	if (dialog)
	{
		static_cast<void>(runOnMainWindowThread(
		    [dialog, status](MainWindow *) -> bool
		    {
			    if (!dialog)
				    return false;
			    dialog->setLabelText(status);
			    return true;
		    },
		    false));
	}
	return 0;
}

static int luaProgressSetRange(lua_State *L)
{
	const LuaProgressDialogHandle handle = progressCheck(L);
	if (!handle)
		return 0;
	const int     start   = static_cast<int>(luaL_checkinteger(L, 2));
	const int     end     = static_cast<int>(luaL_checkinteger(L, 3));
	auto         *engine  = progressEngine(L);
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		const bool    accepted         = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [handle, start, end, callbackPluginId, requestId](WorldRuntime &targetRuntime)
		    {
			    const QPointer<WorldRuntime> runtimeGuard(&targetRuntime);
			    const bool                   queued = enqueueOnMainThread(
			        [runtimeGuard, handle, start, end, callbackPluginId, requestId]()
			        {
				        WorldRuntime *targetRuntimeOnMain = runtimeGuard.data();
				        if (!targetRuntimeOnMain)
					        return;
				        QPointer<QProgressDialog> dialog;
				        bool                      pendingCreate = false;
				        {
					        const std::lock_guard<std::mutex> lock(handle->mutex);
					        dialog        = handle->dialog;
					        pendingCreate = handle->createPending;
				        }
				        const bool applied = dialog != nullptr;
				        if (dialog)
					        dialog->setRange(start, end);
				        const bool ok = applied || pendingCreate;
				        emitPluginAsyncResult(*targetRuntimeOnMain, callbackPluginId, requestId,
				                              QStringLiteral("ProgressSetRange"), ok, ok ? eOK : -1);
			        });
			    if (!queued)
			    {
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId,
				                          QStringLiteral("ProgressSetRange"), false, -1);
			    }
		    });
		if (!accepted)
		{
			// No callback-local progress state is modified here.
		}
		return 0;
	}
	QPointer<QProgressDialog> dialog;
	{
		const std::lock_guard<std::mutex> lock(handle->mutex);
		dialog = handle->dialog;
	}
	if (dialog)
	{
		static_cast<void>(runOnMainWindowThread(
		    [dialog, start, end](MainWindow *) -> bool
		    {
			    if (!dialog)
				    return false;
			    dialog->setRange(start, end);
			    return true;
		    },
		    false));
	}
	return 0;
}

static int luaProgressSetPosition(lua_State *L)
{
	const LuaProgressDialogHandle handle = progressCheck(L);
	if (!handle)
		return 0;
	const int     pos     = static_cast<int>(luaL_checkinteger(L, 2));
	auto         *engine  = progressEngine(L);
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		const bool    accepted         = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [handle, pos, callbackPluginId, requestId](WorldRuntime &targetRuntime)
		    {
			    const QPointer<WorldRuntime> runtimeGuard(&targetRuntime);
			    const bool                   queued = enqueueOnMainThread(
			        [runtimeGuard, handle, pos, callbackPluginId, requestId]()
			        {
				        WorldRuntime *targetRuntimeOnMain = runtimeGuard.data();
				        if (!targetRuntimeOnMain)
					        return;
				        QPointer<QProgressDialog> dialog;
				        bool                      pendingCreate = false;
				        {
					        const std::lock_guard<std::mutex> lock(handle->mutex);
					        dialog        = handle->dialog;
					        pendingCreate = handle->createPending;
				        }
				        const bool applied = dialog != nullptr;
				        if (dialog)
					        dialog->setValue(pos);
				        const bool ok = applied || pendingCreate;
				        emitPluginAsyncResult(*targetRuntimeOnMain, callbackPluginId, requestId,
				                              QStringLiteral("ProgressSetPosition"), ok, ok ? eOK : -1);
			        });
			    if (!queued)
			    {
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId,
				                          QStringLiteral("ProgressSetPosition"), false, -1);
			    }
		    });
		if (!accepted)
		{
			// No callback-local progress state is modified here.
		}
		return 0;
	}
	QPointer<QProgressDialog> dialog;
	{
		const std::lock_guard<std::mutex> lock(handle->mutex);
		dialog = handle->dialog;
	}
	if (dialog)
	{
		static_cast<void>(runOnMainWindowThread(
		    [dialog, pos](MainWindow *) -> bool
		    {
			    if (!dialog)
				    return false;
			    dialog->setValue(pos);
			    return true;
		    },
		    false));
	}
	return 0;
}

static int luaProgressSetStep(lua_State *L)
{
	const LuaProgressDialogHandle handle = progressCheck(L);
	if (!handle)
		return 0;
	int value = static_cast<int>(luaL_checkinteger(L, 2));
	if (value <= 0)
		value = 1;
	const std::lock_guard<std::mutex> lock(handle->mutex);
	handle->step = value;
	return 0;
}

static int luaProgressStep(lua_State *L)
{
	const LuaProgressDialogHandle handle = progressCheck(L);
	if (!handle)
		return 0;
	int step = 1;
	{
		const std::lock_guard<std::mutex> lock(handle->mutex);
		step = handle->step;
	}
	auto         *engine  = progressEngine(L);
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		const bool    accepted         = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [handle, step, callbackPluginId, requestId](WorldRuntime &targetRuntime)
		    {
			    const QPointer<WorldRuntime> runtimeGuard(&targetRuntime);
			    const bool                   queued = enqueueOnMainThread(
			        [runtimeGuard, handle, step, callbackPluginId, requestId]()
			        {
				        WorldRuntime *targetRuntimeOnMain = runtimeGuard.data();
				        if (!targetRuntimeOnMain)
					        return;
				        QPointer<QProgressDialog> dialog;
				        bool                      pendingCreate = false;
				        {
					        const std::lock_guard<std::mutex> lock(handle->mutex);
					        dialog        = handle->dialog;
					        pendingCreate = handle->createPending;
				        }
				        const bool applied = dialog != nullptr;
				        if (dialog)
					        dialog->setValue(dialog->value() + step);
				        const bool ok = applied || pendingCreate;
				        emitPluginAsyncResult(*targetRuntimeOnMain, callbackPluginId, requestId,
				                              QStringLiteral("ProgressStep"), ok, ok ? eOK : -1);
			        });
			    if (!queued)
			    {
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId,
				                          QStringLiteral("ProgressStep"), false, -1);
			    }
		    });
		if (!accepted)
		{
			// No callback-local progress state is modified here.
		}
		return 0;
	}
	QPointer<QProgressDialog> dialog;
	{
		const std::lock_guard<std::mutex> lock(handle->mutex);
		dialog = handle->dialog;
	}
	if (dialog)
	{
		static_cast<void>(runOnMainWindowThread(
		    [dialog, step](MainWindow *) -> bool
		    {
			    if (!dialog)
				    return false;
			    dialog->setValue(dialog->value() + step);
			    return true;
		    },
		    false));
	}
	return 0;
}

static int luaProgressCheckCancel(lua_State *L)
{
	const LuaProgressDialogHandle handle = progressCheck(L);
	if (!handle)
	{
		lua_pushboolean(L, 0);
		return 1;
	}
	auto         *engine  = progressEngine(L);
	WorldRuntime *runtime = engine ? engine->worldRuntimeForBridgedCall() : nullptr;
	if (engine && runtime && activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		bool canceled = false;
		{
			const std::lock_guard<std::mutex> lock(handle->mutex);
			canceled = handle->hasLastKnownCanceled ? handle->lastKnownCanceled : false;
		}
		lua_pushboolean(L, canceled ? 1 : 0);
		return 1;
	}

	QPointer<QProgressDialog> dialog;
	{
		const std::lock_guard<std::mutex> lock(handle->mutex);
		dialog = handle->dialog;
	}
	bool canceled = false;
	if (dialog)
	{
		canceled = runOnMainWindowThread(
		    [dialog](MainWindow *) -> bool
		    {
			    if (!dialog)
				    return false;
			    return dialog->wasCanceled();
		    },
		    false);
		const std::lock_guard<std::mutex> lock(handle->mutex);
		handle->lastKnownCanceled    = canceled;
		handle->hasLastKnownCanceled = true;
	}
	else
	{
		const std::lock_guard<std::mutex> lock(handle->mutex);
		canceled = handle->hasLastKnownCanceled ? handle->lastKnownCanceled : false;
	}
	lua_pushboolean(L, canceled ? 1 : 0);
	return 1;
}

static void registerProgressLibrary(lua_State *L, LuaCallbackEngine *engine)
{
	auto setFn = [L, engine](const char *name, const lua_CFunction fn)
	{
		lua_pushlightuserdata(L, engine);
		lua_pushcclosure(L, fn, 1);
		lua_setfield(L, -2, name);
	};

	luaL_newmetatable(L, kProgressMetaName);
	lua_pushvalue(L, -1);
	lua_setfield(L, -2, "__index");
	setFn("__gc", luaProgressGc);
	setFn("__tostring", luaProgressToString);
	setFn("checkcancel", luaProgressCheckCancel);
	setFn("close", luaProgressGc);
	setFn("position", luaProgressSetPosition);
	setFn("range", luaProgressSetRange);
	setFn("setstep", luaProgressSetStep);
	setFn("status", luaProgressSetStatus);
	setFn("step", luaProgressStep);
	lua_pop(L, 1);

	lua_newtable(L);
	setFn("new", luaProgressNew);
	lua_setglobal(L, "progress");
}

static void registerCheckFunction(lua_State *L)
{
	const auto code = "function check (result) "
	                  "if result ~= error_code.eOK then "
	                  "error (error_desc [result] or "
	                  "string.format (\"Unknown error code: %i\", result), 2) "
	                  "end end";
	if (luaL_dostring(L, code) != 0)
	{
		const char *err = lua_tostring(L, -1);
		qWarning() << "Failed to register check function:" << (err ? err : "unknown");
		lua_pop(L, 1);
	}
}

static void pushVariant(lua_State *L, const QVariant &value)
{
	if (!value.isValid() || value.isNull())
	{
		lua_pushnil(L);
		return;
	}

	switch (value.typeId())
	{
	case QMetaType::Bool:
		lua_pushboolean(L, value.toBool());
		return;
	case QMetaType::Float:
	case QMetaType::Int:
	case QMetaType::LongLong:
	case QMetaType::UInt:
	case QMetaType::ULongLong:
	case QMetaType::Double:
		lua_pushnumber(L, value.toDouble());
		return;
	case QMetaType::QDateTime:
		lua_pushnumber(L, static_cast<lua_Number>(value.toDateTime().toLocalTime().toSecsSinceEpoch()));
		return;
	case QMetaType::QDate:
		lua_pushnumber(
		    L, static_cast<lua_Number>(QDateTime(value.toDate(), QTime(0, 0), QTimeZone::systemTimeZone())
		                                   .toLocalTime()
		                                   .toSecsSinceEpoch()));
		return;
	case QMetaType::QTime:
	{
		const QDateTime dt(QDate::currentDate(), value.toTime(), QTimeZone::systemTimeZone());
		lua_pushnumber(L, static_cast<lua_Number>(dt.toLocalTime().toSecsSinceEpoch()));
		return;
	}
	default:
		break;
	}

	const QByteArray text = value.toString().toLocal8Bit();
	lua_pushlstring(L, text.constData(), text.size());
}

static void pushStringList(lua_State *L, const QStringList &list)
{
	lua_newtable(L);
	int index = 1;
	for (const QString &entry : list)
	{
		const QByteArray bytes = entry.toLocal8Bit();
		lua_pushlstring(L, bytes.constData(), bytes.size());
		lua_rawseti(L, -2, index++);
	}
}

static int pushOptionalStringList(lua_State *L, const QStringList &list)
{
	if (list.isEmpty())
	{
		lua_pushnil(L);
		return 1;
	}
	pushStringList(L, list);
	return 1;
}

static bool isEnabledValue(const QString &value)
{
	return value == QStringLiteral("1") || value.compare(QStringLiteral("y"), Qt::CaseInsensitive) == 0 ||
	       value.compare(QStringLiteral("true"), Qt::CaseInsensitive) == 0;
}

static bool parseBooleanKeywordValue(const QString &text, bool &out)
{
	if (text.compare(QStringLiteral("y"), Qt::CaseInsensitive) == 0 ||
	    text.compare(QStringLiteral("yes"), Qt::CaseInsensitive) == 0 ||
	    text.compare(QStringLiteral("true"), Qt::CaseInsensitive) == 0)
	{
		out = true;
		return true;
	}
	if (text.compare(QStringLiteral("n"), Qt::CaseInsensitive) == 0 ||
	    text.compare(QStringLiteral("no"), Qt::CaseInsensitive) == 0 ||
	    text.compare(QStringLiteral("false"), Qt::CaseInsensitive) == 0)
	{
		out = false;
		return true;
	}
	return false;
}

static QString attrFlag(const bool value)
{
	return value ? QStringLiteral("1") : QStringLiteral("0");
}

static int buildTriggerMatchFlags(const WorldRuntime::Trigger &trigger)
{
	auto attrBool = [&](const QString &key) { return isEnabledValue(trigger.attributes.value(key)); };
	auto attrInt  = [&](const QString &key) { return trigger.attributes.value(key).toInt(); };

	int  match = 0;
	match |= (attrInt(QStringLiteral("text_colour")) & 0x0F) << 4;
	match |= (attrInt(QStringLiteral("back_colour")) & 0x0F) << 8;
	if (attrBool(QStringLiteral("bold")))
		match |= kStyleHilite;
	if (attrBool(QStringLiteral("italic")))
		match |= kStyleBlink;
	if (attrBool(QStringLiteral("underline")))
		match |= kStyleUnderline;
	if (attrBool(QStringLiteral("inverse")))
		match |= kStyleInverse;
	if (attrBool(QStringLiteral("match_text_colour")))
		match |= kTriggerMatchText;
	if (attrBool(QStringLiteral("match_back_colour")))
		match |= kTriggerMatchBack;
	if (attrBool(QStringLiteral("match_bold")))
		match |= kTriggerMatchHilite;
	if (attrBool(QStringLiteral("match_italic")))
		match |= kTriggerMatchBlink;
	if (attrBool(QStringLiteral("match_inverse")))
		match |= kTriggerMatchInverse;
	if (attrBool(QStringLiteral("match_underline")))
		match |= kTriggerMatchUnderline;
	return match;
}

static int buildTriggerStyleFlags(const WorldRuntime::Trigger &trigger)
{
	auto attrBool = [&](const QString &key) { return isEnabledValue(trigger.attributes.value(key)); };
	int  style    = 0;
	if (attrBool(QStringLiteral("make_bold")))
		style |= kStyleHilite;
	if (attrBool(QStringLiteral("make_italic")))
		style |= kStyleBlink;
	if (attrBool(QStringLiteral("make_underline")))
		style |= kStyleUnderline;
	return style;
}

static QString normalizeObjectName(const QString &name)
{
	return name.trimmed().toLower();
}

static bool isValidLabel(const QString &label)
{
	const QString trimmed = label.trimmed();
	if (trimmed.isEmpty())
		return false;
	for (int i = 0; i < trimmed.size(); ++i)
	{
		const QChar ch = trimmed.at(i);
		if (ch == QLatin1Char('_'))
			continue;
		if (!ch.isLetterOrNumber())
			return false;
	}
	return true;
}

static QString makeAutoName(const QString &prefix)
{
	return prefix + QUuid::createUuid().toString(QUuid::WithoutBraces).remove('-');
}

static bool parseBoolArg(lua_State *L, bool &out)
{
	constexpr int kValueIndex = 3;
	if (lua_isboolean(L, kValueIndex))
	{
		out = lua_toboolean(L, kValueIndex);
		return true;
	}
	if (lua_isnumber(L, kValueIndex))
	{
		out = lua_tonumber(L, kValueIndex) != 0.0;
		return true;
	}
	const QString text = luaOptionValue(L, kValueIndex);
	if (parseBooleanKeywordValue(text, out))
		return true;
	bool         ok     = false;
	const double number = text.toDouble(&ok);
	if (!ok)
		return false;
	out = number != 0.0;
	return true;
}

static bool parseNumberArg(lua_State *L, double &out)
{
	constexpr int kValueIndex = 3;
	if (lua_isnumber(L, kValueIndex))
	{
		out = lua_tonumber(L, kValueIndex);
		return true;
	}
	const QString text = luaOptionValue(L, kValueIndex);
	bool          ok   = false;
	out                = text.toDouble(&ok);
	return ok;
}

static int triggerColourFromCustom(const int customColour)
{
	if (customColour <= 0)
		return -1;
	if (customColour == OTHER_CUSTOM + 1)
		return OTHER_CUSTOM;
	if (customColour > OTHER_CUSTOM + 1)
		return -1;
	return customColour - 1;
}

static int customFromTriggerColour(const int colour)
{
	if (colour < 0)
		return 0;
	if (colour == OTHER_CUSTOM)
		return OTHER_CUSTOM + 1;
	if (colour >= MAX_CUSTOM)
		return 0;
	return colour + 1;
}

