static void updateCallbackSendCommandSnapshots(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                               const QString &text, const bool echo, const bool queue,
                                               const bool log, const bool immediate)
{
	const std::optional<bool> onPluginSendPresent =
	    resolvePluginCallbackPresenceForApi(engine, runtime, QStringLiteral("OnPluginSend"));
	const bool sendCanBeCancelled = onPluginSendPresent.value_or(true);
	if (immediate)
	{
		if (!sendCanBeCancelled)
		{
			incrementCallbackOutboundPacketSnapshot(
			    engine, runtime, callbackOutboundCommandByteCount(engine, runtime, text), 1);
			QString commandText = text;
			if (commandText.endsWith(QStringLiteral("\r\n")))
				commandText.chop(2);
			updateCallbackLastCommandSentSnapshot(engine, runtime, commandText);
		}
		return;
	}

	const QStringList immediateLines =
	    updateCallbackCommandQueueAfterSend(engine, runtime, text, echo, queue, log);
	if (!sendCanBeCancelled)
	{
		for (const QString &line : immediateLines)
		{
			incrementCallbackOutboundPacketSnapshot(
			    engine, runtime, callbackOutboundCommandByteCount(engine, runtime, line), 1);
			updateCallbackLastCommandSentSnapshot(engine, runtime, line);
		}
	}
}

static int pushDispatchSendCommandResult(lua_State *L, const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                         const QString &apiName, const QString &text, const bool echo,
                                         const bool queue, const bool log, const bool history,
                                         const bool immediate)
{
	if (!engine || !runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::RuntimeCountersSnapshot snapshot;
		if (!resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot))
		{
			lua_pushnumber(L, eWorldClosed);
			return 1;
		}
		if (snapshot.connectPhase != WorldRuntime::eConnectConnectedToMud)
		{
			lua_pushnumber(L, eWorldClosed);
			return 1;
		}
		if (snapshot.pluginProcessingSent)
		{
			lua_pushnumber(L, eItemInUse);
			return 1;
		}

		const QPointer<WorldRuntime> runtimeGuard(runtime);
		const int                    results = enqueueRuntimeThreadAsyncOkStatusResult(
		    L, engine, runtime, apiName, eWorldClosed,
		    [runtimeGuard, text, echo, queue, log, history, immediate](WorldRuntime &) -> int
		    {
			    if (!runtimeGuard)
				    return eWorldClosed;
			    return runtimeGuard->sendCommand(text, echo, queue, log, history, immediate);
		    });
		if (lua_tointeger(L, -results) == eOK)
			updateCallbackSendCommandSnapshots(engine, runtime, text, echo, queue, log, immediate);
		return results;
	}

	const QPointer<WorldRuntime> runtimeGuard(runtime);
	const int                    result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [runtimeGuard, text, echo, queue, log, history, immediate]() -> int
	    {
		    if (!runtimeGuard)
			    return eWorldClosed;
		    return runtimeGuard->sendCommand(text, echo, queue, log, history, immediate);
	    },
	    eWorldClosed);
	lua_pushnumber(L, result);
	return 1;
}

