static int luaConnect(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::RuntimeCountersSnapshot snapshot;
		if (!resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot))
		{
			lua_pushnumber(L, eWorldClosed);
			return 1;
		}
		if (snapshot.connectPhase != WorldRuntime::eConnectNotConnected)
		{
			lua_pushnumber(L, eWorldOpen);
			return 1;
		}
		const QString host = resolveWorldAttributeValueForApi(engine, runtime, QStringLiteral("site"));
		const auto    port = static_cast<quint16>(
		    resolveWorldAttributeValueForApi(engine, runtime, QStringLiteral("port")).toUInt());
		enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime,
		                                             [host, port](WorldRuntime &targetRuntime)
		                                             { targetRuntime.connectToWorld(host, port); });
		invalidateCallbackRuntimeSnapshots(engine);
		lua_pushnumber(L, eOK);
		return 1;
	}
	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [](WorldRuntime &targetRuntime) -> int
	    {
		    if (targetRuntime.connectPhase() != WorldRuntime::eConnectNotConnected)
			    return eWorldOpen;
		    const QString host = targetRuntime.worldAttributeValue(QStringLiteral("site"));
		    const auto    port =
		        static_cast<quint16>(targetRuntime.worldAttributeValue(QStringLiteral("port")).toUInt());
		    targetRuntime.connectToWorld(host, port);
		    return eOK;
	    },
	    eWorldClosed);
	lua_pushnumber(L, result);
	return 1;
}

static int luaDisconnect(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	if (activeCallbackContextConst(engine))
	{
		WorldRuntime::RuntimeCountersSnapshot snapshot;
		if (!resolveRuntimeCountersSnapshotForApi(engine, runtime, snapshot))
		{
			lua_pushnumber(L, eWorldClosed);
			return 1;
		}
		const int phase = snapshot.connectPhase;
		if (phase == WorldRuntime::eConnectNotConnected || phase == WorldRuntime::eConnectDisconnecting)
		{
			lua_pushnumber(L, eWorldClosed);
			return 1;
		}
		enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime, [](WorldRuntime &targetRuntime)
		                                             { targetRuntime.disconnectFromWorld(); });
		invalidateCallbackRuntimeSnapshots(engine);
		lua_pushnumber(L, eOK);
		return 1;
	}
	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [](WorldRuntime &targetRuntime) -> int
	    {
		    if (const int phase = targetRuntime.connectPhase();
		        phase == WorldRuntime::eConnectNotConnected || phase == WorldRuntime::eConnectDisconnecting)
		    {
			    return eWorldClosed;
		    }
		    targetRuntime.disconnectFromWorld();
		    return eOK;
	    },
	    eWorldClosed);
	lua_pushnumber(L, result);
	return 1;
}

