static int luaGetQueue(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnil(L);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	WorldRuntime::CommandUiSnapshot snapshot;
	if (!resolveCommandUiSnapshotLightForApi(engine, runtime, snapshot))
	{
		lua_pushnil(L);
		return 1;
	}
	const QStringList commands = snapshot.queuedCommands;
	if (commands.isEmpty())
	{
		lua_pushnil(L);
		return 1;
	}
	lua_newtable(L);
	for (int i = 0; i < commands.size(); ++i)
	{
		QString entry = commands.at(i);
		if (entry.size() > 1)
			entry = entry.mid(1);
		else if (!entry.isEmpty())
			entry.clear();
		const QByteArray bytes = entry.toUtf8();
		lua_pushlstring(L, bytes.constData(), bytes.size());
		lua_rawseti(L, -2, i + 1);
	}
	return 1;
}

static QString acceleratorSendTag(const int sendTo)
{
	if (sendTo == eSendToExecute)
		return {};
	return QStringLiteral("\t[%1]").arg(sendTo);
}

static int applyAcceleratorRegistrationForApi(WorldRuntime &runtime, const qint64 mapKey,
                                              const QString &sendTextValue, const int sendTo,
                                              const QString &pluginId)
{
	if (sendTextValue.isEmpty() || (sendTo == eSendToScript && sendTextValue.trimmed().isEmpty()))
	{
		runtime.removeAccelerator(mapKey);
		return eOK;
	}

	int commandId = runtime.acceleratorCommandForKey(mapKey);
	if (commandId < 0)
	{
		commandId = runtime.allocateAcceleratorCommand();
		if (commandId < 0)
			return eBadParameter;
	}

	WorldRuntime::AcceleratorEntry entry;
	entry.text     = sendTextValue;
	entry.sendTo   = sendTo;
	entry.pluginId = pluginId;
	runtime.registerAccelerator(mapKey, commandId, entry);
	return eOK;
}

static int pushAcceleratorRegistrationResult(lua_State *L, const LuaCallbackEngine *engine,
                                             WorldRuntime *runtime, const QString &apiName,
                                             const qint64 mapKey, const QString &sendTextValue,
                                             const int sendTo)
{
	const bool remove =
	    sendTextValue.isEmpty() || (sendTo == eSendToScript && sendTextValue.trimmed().isEmpty());
	if (activeCallbackContextConst(engine))
	{
		if (!remove)
		{
			QVector<WorldRuntime::AcceleratorSnapshot> snapshot;
			if (resolveAcceleratorSnapshotForApi(engine, runtime, snapshot))
			{
				const bool keyExists =
				    std::ranges::any_of(snapshot, [mapKey](const WorldRuntime::AcceleratorSnapshot &row)
				                        { return row.key == mapKey; });
				if (!keyExists && snapshot.size() >= WorldRuntime::kAcceleratorCount)
				{
					lua_pushnumber(L, eBadParameter);
					return 1;
				}
			}
		}

		const QString pluginId = engine ? engine->pluginId() : QString();
		const int     results  = enqueueRuntimeThreadAsyncOkStatusResult(
		    L, engine, runtime, apiName, eWorldClosed,
		    [mapKey, sendTextValue, sendTo, pluginId](WorldRuntime &targetRuntime) -> int
		    {
			    return applyAcceleratorRegistrationForApi(targetRuntime, mapKey, sendTextValue, sendTo,
			                                              pluginId);
		    });
		if (lua_tointeger(L, -results) == eOK)
		{
			if (remove)
				cacheCallbackAcceleratorSnapshotAfterRemove(engine, runtime, mapKey);
			else
				cacheCallbackAcceleratorSnapshotAfterSet(engine, runtime, mapKey, sendTextValue, sendTo);
		}
		return results;
	}

	const QString pluginId = engine ? engine->pluginId() : QString();
	const int     result   = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [mapKey, sendTextValue, sendTo, pluginId](WorldRuntime &targetRuntime) -> int
	    {
		    return applyAcceleratorRegistrationForApi(targetRuntime, mapKey, sendTextValue, sendTo, pluginId);
	    },
	    eWorldClosed);
	lua_pushnumber(L, result);
	return 1;
}

static int luaAcceleratorTo(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}

	const char *keyText       = luaL_checkstring(L, 1);
	const char *sendText      = luaL_checkstring(L, 2);
	const int   sendTo        = static_cast<int>(luaL_checkinteger(L, 3));
	const auto  sendTextValue = QString::fromUtf8(sendText);
	if (sendTo < 0 || sendTo >= eSendToLast)
	{
		lua_pushnumber(L, eOptionOutOfRange);
		return 1;
	}

	quint32 virt = 0;
	quint16 key  = 0;
	if (!AcceleratorUtils::stringToAccelerator(QString::fromUtf8(keyText), virt, key))
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}

	const qint64 mapKey = static_cast<qint64>(virt) << 16 | key;
	return pushAcceleratorRegistrationResult(L, engine, runtime, QStringLiteral("AcceleratorTo"), mapKey,
	                                         sendTextValue, sendTo);
}

static int luaAccelerator(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eWorldClosed);
		return 1;
	}

	const char *keyText  = luaL_checkstring(L, 1);
	const char *sendText = luaL_checkstring(L, 2);

	quint32     virt = 0;
	quint16     key  = 0;
	if (!AcceleratorUtils::stringToAccelerator(QString::fromUtf8(keyText), virt, key))
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}

	const qint64  mapKey        = static_cast<qint64>(virt) << 16 | key;
	const QString sendTextValue = QString::fromUtf8(sendText);
	return pushAcceleratorRegistrationResult(L, engine, runtime, QStringLiteral("Accelerator"), mapKey,
	                                         sendTextValue, eSendToExecute);
}

static int luaAcceleratorList(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	lua_newtable(L);
	if (!engine)
		return 1;
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
		return 1;

	QVector<WorldRuntime::AcceleratorSnapshot> snapshot;
	if (!resolveAcceleratorSnapshotForApi(engine, runtime, snapshot))
		return 1;
	int index = 1;
	for (const WorldRuntime::AcceleratorSnapshot &row : snapshot)
	{
		if (row.commandId < 0)
			continue;
		const auto    keyCode   = static_cast<quint16>(row.key & 0xFFFF);
		const auto    virt      = static_cast<quint32>(row.key >> 16 & 0xFFFFFFFF);
		const QString keyString = AcceleratorUtils::acceleratorToString(virt, keyCode);
		const QString line = QStringLiteral("%1 = %2%3")
		                         .arg(keyString.isEmpty() ? QStringLiteral("<unknown>") : keyString, row.text,
		                              acceleratorSendTag(row.sendTo));
		const QByteArray bytes = line.toUtf8();
		lua_pushlstring(L, bytes.constData(), bytes.size());
		lua_rawseti(L, -2, index++);
	}

	return 1;
}

