static int luaGetLinesInBufferCount(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, 0);
		return 1;
	}
	int lineCount = 0;
	if (tryResolveCallbackLineCountFromCache(engine, lineCount))
	{
		lua_pushnumber(L, lineCount);
		return 1;
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
	{
		if (const auto *context = activeCallbackContextConst(engine))
		{
			if (context->hasBufferedLineCount)
				lineCount = context->bufferedLineCount;
			else if (context->wildcardDomain == CallbackWildcardDomain::Trigger &&
			         context->triggerMatchedLineBufferIndexAtDispatch > 0)
			{
				lineCount = context->triggerMatchedLineBufferIndexAtDispatch;
			}
		}
		cacheCallbackLineCount(engine, lineCount);
		lua_pushnumber(L, lineCount);
		return 1;
	}
	WorldRuntime::LineEntry currentEntry;
	bool                    hasLineEntry = false;
	const bool              resolved =
	    inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                     runtime,
	                     [&]() -> bool
	                     {
		                     lineCount = runtime->luaContextLinesInBufferCount();
		                     if (lineCount > 0)
			                     hasLineEntry = runtime->luaContextLineEntry(lineCount, currentEntry);
		                     return true;
	                     },
	                     false)
	               : runOnRuntimeThread(
	                     runtime,
	                     [&]() -> bool
	                     {
		                     lineCount = runtime->luaContextLinesInBufferCount();
		                     if (lineCount > 0)
			                     hasLineEntry = runtime->luaContextLineEntry(lineCount, currentEntry);
		                     return true;
	                     },
	                     false);
	if (resolved)
	{
		cacheCallbackLineCount(engine, lineCount);
		if (lineCount > 0)
			cacheCallbackLineEntry(engine, lineCount, hasLineEntry, currentEntry);
	}
	lua_pushnumber(L, lineCount);
	return 1;
}

static int luaGetRecentLines(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushstring(L, "");
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushstring(L, "");
		return 1;
	}
	const int count = static_cast<int>(luaL_checkinteger(L, 1));
	if (count <= 0)
	{
		lua_pushstring(L, "");
		return 1;
	}
	QStringList out;
	static_cast<void>(resolveRecentLinesForApi(engine, runtime, count, out));
	// Legacy behavior: GetRecentLines joins with '\n'.
	const QString joined = out.join(QStringLiteral("\n"));
	lua_pushstring(L, joined.toLocal8Bit().constData());
	return 1;
}

template <typename Option> static int pushOptionNameList(lua_State *L, const Option *options)
{
	lua_newtable(L);
	int index = 1;
	for (int i = 0; options[i].name; ++i)
	{
		lua_pushstring(L, options[i].name);
		lua_rawseti(L, -2, index++);
	}
	return 1;
}

static int luaGetOptionList(lua_State *L)
{
	return pushOptionNameList(L, worldNumericOptions());
}

static int luaGetAlphaOptionList(lua_State *L)
{
	return pushOptionNameList(L, worldAlphaOptions());
}

