static WorldRuntime *findWorldRuntimeByAttribute(const LuaCallbackEngine *engine,
                                                 const QString &attributeName, const QString &value)
{
	if (attributeName.isEmpty() || value.isEmpty())
		return nullptr;
	if (activeCallbackContextConst(engine))
	{
		if (const LuaCallbackWorldRuntimeSnapshot *snapshot =
		        findWorldRuntimeSnapshotByAttribute(engine, attributeName, value);
		    snapshot)
		{
			return snapshot->runtime;
		}
		return nullptr;
	}
	return findWorldRuntimeWhere(engine,
	                             [&attributeName, &value](const WorldRuntime *runtime)
	                             {
		                             auto         *mutableRuntime = const_cast<WorldRuntime *>(runtime);
		                             const QString attr           = runOnRuntimeThread(
		                                 mutableRuntime, [mutableRuntime, &attributeName]() -> QString
		                                 { return mutableRuntime->worldAttributeValue(attributeName); },
		                                 QString());
		                             return attr.compare(value, Qt::CaseInsensitive) == 0;
	                             });
}

static WorldRuntime *findWorldRuntimeById(const LuaCallbackEngine *engine, const QString &id)
{
	return findWorldRuntimeByAttribute(engine, QStringLiteral("id"), id);
}

static WorldRuntime *findWorldRuntimeByName(const LuaCallbackEngine *engine, const QString &name)
{
	return findWorldRuntimeByAttribute(engine, QStringLiteral("name"), name);
}

static WorldRuntime *findWorldRuntimeByPointer(const LuaCallbackEngine *engine,
                                               const WorldRuntime      *runtimePtr)
{
	if (!runtimePtr)
		return nullptr;
	if (activeCallbackContextConst(engine))
	{
		if (const LuaCallbackWorldRuntimeSnapshot *snapshot =
		        findWorldRuntimeSnapshotByPointer(engine, runtimePtr);
		    snapshot)
		{
			return snapshot->runtime;
		}
		return nullptr;
	}
	return findWorldRuntimeWhere(engine,
	                             [runtimePtr](const WorldRuntime *runtime) { return runtime == runtimePtr; });
}

static WorldRuntime *resolveWorldRuntimeFromProxy(const LuaCallbackEngine *engine,
                                                  const WorldRuntime *worldPtr, const char *worldId)
{
	WorldRuntime *target = findWorldRuntimeByPointer(engine, worldPtr);
	if (!target && worldId)
		target = findWorldRuntimeById(engine, QString::fromUtf8(worldId));
	return target;
}

static int luaWorldProxyCall(lua_State *L)
{
	auto       *engine   = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	auto       *worldPtr = static_cast<WorldRuntime *>(lua_touserdata(L, lua_upvalueindex(2)));
	const char *worldId  = lua_tostring(L, lua_upvalueindex(3));
	const char *name     = lua_tostring(L, lua_upvalueindex(4));
	if (!engine || !name)
		return 0;

	WorldRuntime *target = resolveWorldRuntimeFromProxy(engine, worldPtr, worldId);
	if (!target)
		return 0;

	if (lua_gettop(L) >= 1)
		lua_remove(L, 1); // drop proxy table for ":" calls

	const int argCount = lua_gettop(L);
	lua_getglobal(L, "world");
	lua_getfield(L, -1, name);
	if (!lua_isfunction(L, -1))
	{
		lua_pop(L, 2);
		return 0;
	}
	lua_remove(L, -2);
	lua_insert(L, 1);

	WorldRuntime *previous = engine->swapWorldRuntime(target);
	int           status   = 0;
	{
		const ScopedLuaCallbackExecutionContext callbackContextGuard(
		    engine, CallbackWildcardDomain::None, QString(), QStringList(), QMap<QString, QString>());
		QElapsedTimer timer;
		timer.start();
		ScriptExecutionDepthGuard depthGuard(engine);
		status = QMudLuaSupport::callLuaProtected(L, argCount, LUA_MULTRET, 0);
		addScriptTimeForRuntime(engine, target, timer.nsecsElapsed());
	}
	engine->swapWorldRuntime(previous);

	if (status != 0)
		return lua_error(L);
	return lua_gettop(L);
}

static int luaWorldProxyIndex(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnil(L);
		return 1;
	}

	const char *key = lua_tostring(L, 2);
	if (!key)
	{
		lua_pushnil(L);
		return 1;
	}

	lua_getfield(L, 1, "__worldId");
	const char *worldId = lua_tostring(L, -1);
	lua_pop(L, 1);
	if (!worldId)
	{
		lua_pushnil(L);
		return 1;
	}

	lua_getfield(L, 1, "__worldPtr");
	auto *worldPtr = static_cast<WorldRuntime *>(lua_touserdata(L, -1));
	lua_pop(L, 1);
	WorldRuntime *target = resolveWorldRuntimeFromProxy(engine, worldPtr, worldId);
	if (!target)
	{
		lua_pushnil(L);
		return 1;
	}

	lua_getglobal(L, "world");
	lua_getfield(L, -1, key);
	const bool isFunction = lua_isfunction(L, -1);
	lua_pop(L, 2);
	if (!isFunction)
	{
		lua_pushnil(L);
		return 1;
	}

	lua_pushlightuserdata(L, engine);
	lua_pushlightuserdata(L, target);
	lua_pushstring(L, worldId);
	lua_pushstring(L, key);
	lua_pushcclosure(L, luaWorldProxyCall, 4);
	return 1;
}

static int luaWorldProxyToString(lua_State *L)
{
	Q_UNUSED(L);
	lua_pushliteral(L, "world");
	return 1;
}

static void pushWorldProxy(lua_State *L, LuaCallbackEngine *engine, WorldRuntime *runtime,
                           const QString &worldId)
{
	static constexpr char kWorldProxyMeta[] = "QMud.WorldProxy";
	lua_newtable(L);
	lua_pushstring(L, worldId.toUtf8().constData());
	lua_setfield(L, -2, "__worldId");
	lua_pushlightuserdata(L, runtime);
	lua_setfield(L, -2, "__worldPtr");
	if (luaL_newmetatable(L, kWorldProxyMeta))
	{
		lua_pushlightuserdata(L, engine);
		lua_pushcclosure(L, luaWorldProxyIndex, 1);
		lua_setfield(L, -2, "__index");
		lua_pushcfunction(L, luaWorldProxyToString);
		lua_setfield(L, -2, "__tostring");
	}
	lua_setmetatable(L, -2);
}

