static int         findTriggerIndex(const QList<WorldRuntime::Trigger> &triggers, const QString &name)
{
	const QString normalized = normalizeObjectName(name);
	for (int i = 0; i < triggers.size(); ++i)
	{
		if (const QString label = triggers.at(i).attributes.value(QStringLiteral("name"));
		    normalizeObjectName(label) == normalized)
			return i;
	}
	return -1;
}

static int findAliasIndex(const QList<WorldRuntime::Alias> &aliases, const QString &name)
{
	const QString normalized = normalizeObjectName(name);
	for (int i = 0; i < aliases.size(); ++i)
	{
		if (const QString label = aliases.at(i).attributes.value(QStringLiteral("name"));
		    normalizeObjectName(label) == normalized)
			return i;
	}
	return -1;
}

static int findTimerIndex(const QList<WorldRuntime::Timer> &timers, const QString &name)
{
	const QString normalized = normalizeObjectName(name);
	for (int i = 0; i < timers.size(); ++i)
	{
		if (const QString label = timers.at(i).attributes.value(QStringLiteral("name"));
		    normalizeObjectName(label) == normalized)
			return i;
	}
	return -1;
}

static int findTriggerRuntimeIdIndex(const QList<WorldRuntime::Trigger> &triggers, const quint64 runtimeId)
{
	if (runtimeId == 0)
		return -1;
	for (int i = 0; i < triggers.size(); ++i)
	{
		if (triggers.at(i).runtimeId == runtimeId)
			return i;
	}
	return -1;
}

static int findAliasRuntimeIdIndex(const QList<WorldRuntime::Alias> &aliases, const quint64 runtimeId)
{
	if (runtimeId == 0)
		return -1;
	for (int i = 0; i < aliases.size(); ++i)
	{
		if (aliases.at(i).runtimeId == runtimeId)
			return i;
	}
	return -1;
}

static int findTimerRuntimeIdIndex(const QList<WorldRuntime::Timer> &timers, const quint64 runtimeId)
{
	if (runtimeId == 0)
		return -1;
	for (int i = 0; i < timers.size(); ++i)
	{
		if (timers.at(i).runtimeId == runtimeId)
			return i;
	}
	return -1;
}

static bool fetchTriggerSnapshotForContext(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                           const QString &pluginId, const QString &name,
                                           WorldRuntime::Trigger &trigger, bool *pluginMissing = nullptr)
{
	if (pluginMissing)
		*pluginMissing = false;
	if (!runtime)
		return false;

	bool localPluginMissing = false;
	bool cacheHit           = false;
	if (tryResolveCallbackTriggerSnapshotFromCache(engine, pluginId, name, trigger, localPluginMissing,
	                                               cacheHit))
	{
		if (pluginMissing)
			*pluginMissing = false;
		return true;
	}
	if (cacheHit)
	{
		if (pluginMissing)
			*pluginMissing = localPluginMissing;
		return false;
	}

	const QList<WorldRuntime::Trigger> *cachedTriggers    = nullptr;
	bool                                listPluginMissing = false;
	bool                                listCacheHit      = false;
	if (tryResolveCallbackTriggerListViewFromCache(engine, pluginId, cachedTriggers, listPluginMissing,
	                                               listCacheHit))
	{
		const int  index = findTriggerIndex(*cachedTriggers, name);
		const bool found = index >= 0;
		if (found)
			trigger = cachedTriggers->at(index);
		cacheCallbackTriggerSnapshot(engine, pluginId, name, found, trigger, false);
		if (pluginMissing)
			*pluginMissing = false;
		return found;
	}
	if (listCacheHit && listPluginMissing)
	{
		localPluginMissing = true;
		cacheCallbackTriggerSnapshot(engine, pluginId, name, false, trigger, true);
		if (pluginMissing)
			*pluginMissing = true;
		return false;
	}

	auto resolveOnRuntimeThread = [&]() -> bool
	{
		const QList<WorldRuntime::Trigger> *triggers = nullptr;
		if (pluginId.isEmpty())
		{
			triggers = &runtime->triggers();
		}
		else
		{
			WorldRuntime::Plugin *plugin = runtime->pluginForId(pluginId);
			if (!plugin)
			{
				localPluginMissing = true;
				return false;
			}
			triggers = &plugin->triggers;
		}
		const int index = findTriggerIndex(*triggers, name);
		if (index < 0)
			return false;
		trigger = triggers->at(index);
		return true;
	};

	const bool useNoFlush = canUseNoFlushRuntimeReadForPluginContext(engine, pluginId);
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, useNoFlush))
		return false;
	const bool found = useNoFlush ? runOnRuntimeThreadNoDeferredFlush(runtime, resolveOnRuntimeThread, false)
	                              : runOnRuntimeThread(runtime, resolveOnRuntimeThread, false);
	cacheCallbackTriggerSnapshot(engine, pluginId, name, found, trigger, localPluginMissing);

	if (pluginMissing)
		*pluginMissing = localPluginMissing;
	return found;
}

