static int luaArrayImport(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	const QString name = QString::fromUtf8(luaL_checkstring(L, 1));

	if (lua_istable(L, 2))
	{
		QVector<QPair<QString, QString>> entries;
		for (lua_pushnil(L); lua_next(L, 2) != 0; lua_pop(L, 1))
		{
			if (!lua_isstring(L, -2))
				luaL_error(L, "table must have string keys");
			const char   *key    = lua_tostring(L, -2);
			const char   *value  = lua_tostring(L, -1);
			const QString keyStr = QString::fromUtf8(key ? key : "");
			const QString valStr = QString::fromUtf8(value ? value : "");
			entries.push_back({keyStr, valStr});
		}
		if (activeCallbackContextConst(engine))
		{
			QMap<QString, QString> arrayValues;
			bool                   exists = false;
			if (!resolveArraySnapshotForApi(engine, runtime, name, arrayValues, exists))
			{
				lua_pushnumber(L, eBadParameter);
				return 1;
			}
			if (!exists)
			{
				lua_pushnumber(L, eArrayDoesNotExist);
				return 1;
			}
			int duplicates = 0;
			for (const auto &[key, value] : entries)
			{
				if (arrayValues.contains(key))
					duplicates++;
				arrayValues.insert(key, value);
			}
			cacheCallbackArraySnapshot(engine, name, arrayValues, true);
			enqueueRuntimeThreadDeferredMutationNoResult(
			    engine, runtime,
			    [name, entries](WorldRuntime &targetRuntime)
			    {
				    for (const auto &[key, value] : entries)
					    static_cast<void>(targetRuntime.arraySet(name, key, value));
			    });
			lua_pushnumber(L, duplicates ? eImportedWithDuplicates : eOK);
			return 1;
		}
		const int result = runOnRuntimeThreadDeferredMutation(
		    engine, runtime,
		    [=]() -> int
		    {
			    if (!runtime->arrayExists(name))
				    return eArrayDoesNotExist;
			    int duplicates = 0;
			    for (const auto &[key, value] : entries)
			    {
				    if (const int rc = runtime->arraySet(name, key, value); rc == eSetReplacingExistingValue)
					    duplicates++;
			    }
			    return duplicates ? eImportedWithDuplicates : eOK;
		    },
		    eBadParameter);
		lua_pushnumber(L, result);
		return 1;
	}

	const QString serializedValues = QString::fromUtf8(luaL_checkstring(L, 2));
	QChar         delimiter;
	if (!arrayDelimiterFromLua(L, 3, delimiter))
	{
		lua_pushnumber(L, eBadDelimiter);
		return 1;
	}
	QString       valueString = serializedValues;
	const QString delimStr(delimiter);
	QString       tempMarker;
	if (const QString escapedDelimiter = QStringLiteral("\\") + delimStr;
	    valueString.contains(escapedDelimiter))
	{
		bool found = false;
		for (int code = 1; code <= 255; ++code)
		{
			if (const QChar candidate(code); !valueString.contains(candidate))
			{
				tempMarker = QString(candidate);
				found      = true;
				break;
			}
		}
		if (!found)
		{
			lua_pushnumber(L, eCannotImport);
			return 1;
		}
		valueString.replace(escapedDelimiter, tempMarker);
	}

	const QStringList parts = valueString.split(delimStr, Qt::KeepEmptyParts);
	if (parts.size() % 2 != 0)
	{
		lua_pushnumber(L, eArrayNotEvenNumberOfValues);
		return 1;
	}

	QVector<QPair<QString, QString>> entries;
	entries.reserve(parts.size() / 2);
	for (int i = 0; i < parts.size(); i += 2)
	{
		QString key = parts.at(i);
		QString val = parts.at(i + 1);
		key.replace(QStringLiteral("\\\\"), QStringLiteral("\\"));
		if (!tempMarker.isEmpty())
			key.replace(tempMarker, delimStr);
		val.replace(QStringLiteral("\\\\"), QStringLiteral("\\"));
		if (!tempMarker.isEmpty())
			val.replace(tempMarker, delimStr);
		entries.push_back({key, val});
	}
	if (activeCallbackContextConst(engine))
	{
		QMap<QString, QString> values;
		bool                   exists = false;
		if (!resolveArraySnapshotForApi(engine, runtime, name, values, exists))
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		if (!exists)
		{
			lua_pushnumber(L, eArrayDoesNotExist);
			return 1;
		}
		int duplicates = 0;
		for (const auto &[key, value] : entries)
		{
			if (values.contains(key))
				duplicates++;
			values.insert(key, value);
		}
		cacheCallbackArraySnapshot(engine, name, values, true);
		enqueueRuntimeThreadDeferredMutationNoResult(engine, runtime,
		                                             [name, entries](WorldRuntime &targetRuntime)
		                                             {
			                                             for (const auto &[key, value] : entries)
				                                             static_cast<void>(
				                                                 targetRuntime.arraySet(name, key, value));
		                                             });
		lua_pushnumber(L, duplicates ? eImportedWithDuplicates : eOK);
		return 1;
	}

	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [=]() -> int
	    {
		    if (!runtime->arrayExists(name))
			    return eArrayDoesNotExist;
		    int duplicates = 0;
		    for (const auto &[key, value] : entries)
		    {
			    if (const int rc = runtime->arraySet(name, key, value); rc == eSetReplacingExistingValue)
				    duplicates++;
		    }
		    return duplicates ? eImportedWithDuplicates : eOK;
	    },
	    eBadParameter);

	lua_pushnumber(L, result);
	return 1;
}

