static int luaArrayList(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
		return 0;
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
		return 0;
	const QString name = QString::fromUtf8(luaL_checkstring(L, 1));
	if (activeCallbackContextConst(engine))
	{
		QMap<QString, QString> values;
		bool                   exists = false;
		if (!resolveArraySnapshotForApi(engine, runtime, name, values, exists) || !exists)
		{
			return 0;
		}
		lua_newtable(L);
		for (auto it = values.constBegin(); it != values.constEnd(); ++it)
		{
			lua_pushstring(L, it.key().toLocal8Bit().constData());
			lua_pushstring(L, it.value().toLocal8Bit().constData());
			lua_rawset(L, -3);
		}
		return 1;
	}
	QStringList      keys;
	QVector<QString> values;
	const bool       exists = runOnRuntimeThread(
	    runtime,
	    [&]() -> bool
	    {
		    if (!runtime->arrayExists(name))
			    return false;
		    keys = runtime->arrayListKeys(name);
		    values.reserve(keys.size());
		    for (const QString &key : keys)
		    {
			    QString value;
			    runtime->arrayGet(name, key, value);
			    values.push_back(value);
		    }
		    return true;
	    },
	    false);
	if (!exists)
		return 0;
	lua_newtable(L);
	for (int i = 0; i < keys.size(); ++i)
	{
		const QString &key   = keys.at(i);
		const QString &value = values.at(i);
		lua_pushstring(L, key.toLocal8Bit().constData());
		lua_pushstring(L, value.toLocal8Bit().constData());
		lua_rawset(L, -3);
	}
	return 1;
}

template <typename Func, typename OkFunc, typename PayloadFunc>
static int enqueueDatabaseAsyncStatusResult(lua_State *L, const LuaCallbackEngine *engine,
                                            WorldRuntime *runtime, const QString &apiName,
                                            const int acceptedCode, const int enqueueFailureCode, Func &&func,
                                            OkFunc &&okFunc, PayloadFunc &&payloadFunc)
{
	using DecayedFunc        = std::decay_t<Func>;
	using DecayedOkFunc      = std::decay_t<OkFunc>;
	using DecayedPayloadFunc = std::decay_t<PayloadFunc>;
	static_assert(std::is_invocable_r_v<int, DecayedFunc, WorldRuntime &>,
	              "Database async callable must return int and accept WorldRuntime&");
	static_assert(std::is_invocable_r_v<bool, DecayedOkFunc, int>,
	              "Database async success predicate must return bool and accept int");
	static_assert(std::is_invocable_r_v<QString, DecayedPayloadFunc, int>,
	              "Database async payload callable must return QString and accept int");

	const QString callbackPluginId = engine ? engine->pluginId() : QString();
	const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
	auto          funcCopy         = DecayedFunc(std::forward<Func>(func));
	auto          okCopy           = DecayedOkFunc(std::forward<OkFunc>(okFunc));
	auto          payloadCopy      = DecayedPayloadFunc(std::forward<PayloadFunc>(payloadFunc));
	const bool    accepted         = enqueueRuntimeThreadDeferredMutationNoResult(
	    engine, runtime,
	    [apiName, callbackPluginId, requestId, funcCopy = std::move(funcCopy), okCopy = std::move(okCopy),
	     payloadCopy = std::move(payloadCopy)](WorldRuntime &targetRuntime) mutable
	    {
		    const int status = funcCopy(targetRuntime);
		    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId, apiName, okCopy(status), status,
		                          payloadCopy(status));
	    });
	lua_pushnumber(L, accepted ? acceptedCode : enqueueFailureCode);
	if (accepted && requestId != 0)
	{
		lua_pushnumber(L, static_cast<lua_Number>(requestId));
		return 2;
	}
	return 1;
}

template <typename Func, typename OkFunc>
static int enqueueDatabaseAsyncStatusResult(lua_State *L, const LuaCallbackEngine *engine,
                                            WorldRuntime *runtime, const QString &apiName,
                                            const int acceptedCode, const int enqueueFailureCode, Func &&func,
                                            OkFunc &&okFunc)
{
	return enqueueDatabaseAsyncStatusResult(L, engine, runtime, apiName, acceptedCode, enqueueFailureCode,
	                                        std::forward<Func>(func), std::forward<OkFunc>(okFunc),
	                                        [](int) -> QString { return {}; });
}

static int luaDatabaseOpen(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnumber(L, eBadParameter);
		return 1;
	}
	const QString name     = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString filename = QString::fromUtf8(luaL_checkstring(L, 2));
	const int     flags = static_cast<int>(luaL_optnumber(L, 3, SQLITE_OPEN_READWRITE | SQLITE_OPEN_CREATE));
	if (activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		return enqueueDatabaseAsyncStatusResult(
		    L, engine, runtime, QStringLiteral("DatabaseOpen"), SQLITE_OK, eBadParameter,
		    [name, filename, flags](WorldRuntime &targetRuntime) -> int
		    { return targetRuntime.databaseOpen(name, filename, flags); },
		    [](const int status) { return status == SQLITE_OK; });
	}
	const int result = runOnRuntimeThreadDeferredMutationCall(engine, runtime, &WorldRuntime::databaseOpen,
	                                                          eBadParameter, name, filename, flags);
	invalidateCallbackDatabaseSnapshotForName(engine, name);
	if (result == SQLITE_OK)
		cacheCallbackDatabaseListAfterOpen(engine, name);
	lua_pushnumber(L, result);
	return 1;
}

