static bool resolveDatabaseInfoForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                      const QString &name, const int infoType, QVariant &value)
{
	if (!engine || !runtime)
		return false;
	bool cacheHit = false;
	if (tryResolveCallbackDatabaseInfoFromCache(engine, name, infoType, value, cacheHit))
		return true;
	if (cacheHit)
		return false;
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		bool snapshotAvailable = false;
		if (const auto *database = callbackDatabaseSnapshotForApi(engine, name, snapshotAvailable))
		{
			switch (infoType)
			{
			case 1:
				value = database->diskName;
				break;
			case 2:
				value = database->stmtPrepared;
				break;
			case 3:
				value = database->validRow;
				break;
			case 4:
				value = database->columns;
				break;
			default:
				value = {};
				break;
			}
			const bool found = value.isValid();
			cacheCallbackDatabaseInfo(engine, name, infoType, found, value);
			return found;
		}
		if (snapshotAvailable)
		{
			value = {};
			cacheCallbackDatabaseInfo(engine, name, infoType, false, value);
			return false;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	QVariant   resolvedValue;
	const bool resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       resolvedValue = runtime->databaseInfo(name, infoType);
		                                       return true;
	                                       },
	                                       false)
	                                 : runOnRuntimeThread(
	                                       runtime,
	                                       [&]() -> bool
	                                       {
		                                       resolvedValue = runtime->databaseInfo(name, infoType);
		                                       return true;
	                                       },
	                                       false);
	if (!resolved)
		return false;
	const bool found = resolvedValue.isValid();
	cacheCallbackDatabaseInfo(engine, name, infoType, found, resolvedValue);
	if (!found)
		return false;
	value = resolvedValue;
	return true;
}

static bool resolveDatabaseColumnNamesForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                             const QString &name, QStringList &names)
{
	if (!engine || !runtime)
		return false;
	bool cacheHit = false;
	if (tryResolveCallbackDatabaseColumnNamesFromCache(engine, name, names, cacheHit))
		return true;
	if (cacheHit)
	{
		names.clear();
		return true;
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		bool snapshotAvailable = false;
		if (const auto *database = callbackDatabaseSnapshotForApi(engine, name, snapshotAvailable))
		{
			const bool found = database->stmtPrepared && !database->columnNames.isEmpty();
			cacheCallbackDatabaseColumnNames(engine, name, found, database->columnNames);
			if (!found)
			{
				names.clear();
				return true;
			}
			names = database->columnNames;
			for (int index = 1; index <= names.size(); ++index)
				cacheCallbackDatabaseColumnName(engine, name, index, true, names.at(index - 1));
			return true;
		}
		if (snapshotAvailable)
		{
			cacheCallbackDatabaseColumnNames(engine, name, false, {});
			names.clear();
			return true;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	QStringList resolvedNames;
	const bool  resolved = inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                                        runtime,
	                                        [&]() -> bool
	                                        {
		                                       resolvedNames = runtime->databaseColumnNames(name);
		                                       return true;
	                                        },
	                                        false)
	                                  : runOnRuntimeThread(
	                                        runtime,
	                                        [&]() -> bool
	                                        {
		                                       resolvedNames = runtime->databaseColumnNames(name);
		                                       return true;
	                                        },
	                                        false);
	if (!resolved)
		return false;
	const bool found = !resolvedNames.isEmpty();
	cacheCallbackDatabaseColumnNames(engine, name, found, resolvedNames);
	if (!found)
	{
		names.clear();
		return true;
	}
	names = resolvedNames;
	for (int index = 1; index <= names.size(); ++index)
	{
		cacheCallbackDatabaseColumnName(engine, name, index, true, names.at(index - 1));
	}
	return true;
}

static bool resolveDatabaseColumnValuesForApi(const LuaCallbackEngine *engine, WorldRuntime *runtime,
                                              const QString &name, QVector<QVariant> &values)
{
	if (!engine || !runtime)
		return false;
	bool cacheHit = false;
	if (tryResolveCallbackDatabaseColumnValuesFromCache(engine, name, values, cacheHit))
		return true;
	if (cacheHit)
	{
		values.clear();
		return true;
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		bool snapshotAvailable = false;
		if (const auto *database = callbackDatabaseSnapshotForApi(engine, name, snapshotAvailable))
		{
			const bool found = database->validRow && !database->columnValues.isEmpty();
			cacheCallbackDatabaseColumnValues(engine, name, found, database->columnValues);
			if (!found)
			{
				values.clear();
				return true;
			}
			values = database->columnValues;
			for (int index = 1; index <= values.size(); ++index)
			{
				cacheCallbackDatabaseColumnValue(engine, name, index, true, values.at(index - 1));
				cacheCallbackDatabaseColumnType(engine, name, index,
				                                mapCallbackDatabaseVariantTypeToSqlite(values.at(index - 1)));
			}
			return true;
		}
		if (snapshotAvailable)
		{
			cacheCallbackDatabaseColumnValues(engine, name, false, {});
			values.clear();
			return true;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return false;
	QVector<QVariant> resolvedValues;
	const bool        found     = inCallback
	                                  ? runOnRuntimeThreadNoDeferredFlush(
	                                        runtime, [&]() -> bool
	                                        { return runtime->databaseColumnValues(name, resolvedValues); }, false)
	                                  : runOnRuntimeThread(
	                                        runtime, [&]() -> bool
	                                        { return runtime->databaseColumnValues(name, resolvedValues); }, false);
	const bool        hasValues = found && !resolvedValues.isEmpty();
	cacheCallbackDatabaseColumnValues(engine, name, hasValues, resolvedValues);
	if (!hasValues)
	{
		values.clear();
		return true;
	}
	values = resolvedValues;
	for (int index = 1; index <= values.size(); ++index)
	{
		cacheCallbackDatabaseColumnValue(engine, name, index, true, values.at(index - 1));
		cacheCallbackDatabaseColumnType(engine, name, index,
		                                mapCallbackDatabaseVariantTypeToSqlite(values.at(index - 1)));
	}
	return true;
}

