static int luaDatabaseGetField(lua_State *L)
{
	auto *engine = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	if (!engine)
	{
		lua_pushnil(L);
		return 1;
	}
	WorldRuntime *runtime = engine->worldRuntimeForBridgedCall();
	if (!runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	const QString name = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString sql  = QString::fromUtf8(luaL_checkstring(L, 2));
	if (activeCallbackContextConst(engine) && callbackScopeSyncBridgeForbidden())
	{
		const QString callbackPluginId = engine->pluginId();
		const quint64 requestId        = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
		const bool    accepted         = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [name, sql, callbackPluginId, requestId](WorldRuntime &targetRuntime)
		    {
			    QVariant value;
			    QString  payload = QStringLiteral("null:");
			    int      status  = targetRuntime.databasePrepare(name, sql);
			    bool     ok      = status == SQLITE_OK;
			    if (ok)
			    {
				    const auto finalize =
				        qScopeGuard([&]() { static_cast<void>(targetRuntime.databaseFinalize(name)); });
				    status = targetRuntime.databaseStep(name);
				    if (status == SQLITE_ROW)
				    {
					    if (targetRuntime.databaseColumnValue(name, 1, value))
					    {
						    status  = eOK;
						    payload = encodeDatabaseFieldAsyncPayload(value);
					    }
					    else
					    {
						    status = kDbErrorColumnOutOfRange;
						    ok     = false;
					    }
				    }
				    else if (status == SQLITE_DONE)
				    {
					    status = eOK;
				    }
				    else
				    {
					    ok = false;
				    }
			    }
			    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId,
			                          QStringLiteral("DatabaseGetField"), ok, status, payload);
		    });
		lua_pushnil(L);
		if (accepted && requestId != 0)
		{
			lua_pushnumber(L, static_cast<lua_Number>(requestId));
			return 2;
		}
		return 1;
	}
	struct DatabaseGetFieldResult
	{
			bool     hasValue{false};
			QVariant value;
	};
	const DatabaseGetFieldResult result = runOnRuntimeThread(
	    runtime,
	    [&]() -> DatabaseGetFieldResult
	    {
		    DatabaseGetFieldResult out;
		    if (runtime->databasePrepare(name, sql) != SQLITE_OK)
			    return out;
		    const auto finalize = qScopeGuard([&]() { static_cast<void>(runtime->databaseFinalize(name)); });
		    if (runtime->databaseStep(name) != SQLITE_ROW)
			    return out;
		    out.hasValue = runtime->databaseColumnValue(name, 1, out.value);
		    return out;
	    },
	    DatabaseGetFieldResult{});
	invalidateCallbackDatabaseSnapshotForName(engine, name);
	if (result.hasValue)
		pushDatabaseColumnValue(L, result.value);
	else
		lua_pushnil(L);
	return 1;
}

