static int luaWindowFont(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnumber(L, eNoSuchWindow);
		return 1;
	}
	const QString name         = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString fontId       = QString::fromUtf8(luaL_checkstring(L, 2));
	const QString fontName     = QString::fromUtf8(luaL_checkstring(L, 3));
	const double  size         = luaL_checknumber(L, 4);
	const bool    bold         = optBool(L, 5, false);
	const bool    italic       = optBool(L, 6, false);
	const bool    underline    = optBool(L, 7, false);
	const bool    strikeout    = optBool(L, 8, false);
	const int     charset      = static_cast<int>(luaL_optinteger(L, 9, DEFAULT_CHARSET));
	const int     pitch        = static_cast<int>(luaL_optinteger(L, 10, kFontFamilyDontCare));
	const bool    removingFont = isMiniWindowFontRemovalRequest(fontName, size);
	if (activeCallbackContextConst(engine))
	{
		if (!resolveMiniWindowExistsForApi(engine, runtime, name))
		{
			lua_pushnumber(L, eNoSuchWindow);
			return 1;
		}
		enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [=](WorldRuntime &targetRuntime)
		    {
			    static_cast<void>(targetRuntime.windowFont(name, fontId, fontName, size, bold, italic,
			                                               underline, strikeout, charset, pitch));
		    });
		cacheCallbackMiniWindowFontExists(engine, name, fontId, !removingFont);
		invalidateCallbackMiniWindowTextWidthCacheForFont(engine, name, fontId);
		invalidateCallbackMiniWindowReadCachesForFont(engine, name, fontId);
		setCallbackMiniWindowShadowFont(engine, name, fontId, fontName, size, bold, italic, underline,
		                                strikeout, charset, pitch);
		cacheCallbackMiniWindowFontInfoPreview(engine, name, fontId, fontName, size, bold, italic, underline,
		                                       strikeout, charset, pitch);
		lua_pushnumber(L, eOK);
		return 1;
	}
	const int result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime,
	    [=]() -> int
	    {
		    return runtime->windowFont(name, fontId, fontName, size, bold, italic, underline, strikeout,
		                               charset, pitch);
	    },
	    eNoSuchWindow);
	if (result == eOK)
	{
		cacheCallbackMiniWindowFontExists(engine, name, fontId, !removingFont);
		invalidateCallbackMiniWindowTextWidthCacheForFont(engine, name, fontId);
		invalidateCallbackMiniWindowReadCachesForFont(engine, name, fontId);
		cacheCallbackMiniWindowFontInfoPreview(engine, name, fontId, fontName, size, bold, italic, underline,
		                                       strikeout, charset, pitch);
	}
	lua_pushnumber(L, result);
	return 1;
}

static int luaWindowFontInfo(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	const QString name     = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString fontId   = QString::fromUtf8(luaL_checkstring(L, 2));
	const int     infoType = luaToInt(L, 3);
	if (activeCallbackContextConst(engine))
	{
		QVariant cached;
		if (tryResolveCallbackMiniWindowFontInfoFromShadow(engine, name, fontId, infoType, cached))
		{
			cacheCallbackMiniWindowFontInfo(engine, name, fontId, infoType, cached);
			pushVariant(L, cached);
			return 1;
		}
		if (tryResolveCallbackMiniWindowFontInfoFromCache(engine, name, fontId, infoType, cached))
		{
			pushVariant(L, cached);
			return 1;
		}
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
	{
		pushVariant(L, QVariant());
		return 1;
	}
	const QVariant value = inCallback
	                           ? runOnRuntimeThreadNoDeferredFlush(
	                                 runtime, [&]() -> QVariant
	                                 { return runtime->windowFontInfo(name, fontId, infoType); }, QVariant())
	                           : runOnRuntimeThreadFlushingDeferred(
	                                 L, runtime, [&]() -> QVariant
	                                 { return runtime->windowFontInfo(name, fontId, infoType); }, QVariant());
	if (activeCallbackContextConst(engine))
		cacheCallbackMiniWindowFontInfo(engine, name, fontId, infoType, value);
	pushVariant(L, value);
	return 1;
}

static int luaWindowFontList(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	const QString name = QString::fromUtf8(luaL_checkstring(L, 1));
	if (activeCallbackContextConst(engine))
	{
		if (const MiniWindow *shadow = callbackMiniWindowShadowConst(engine, name))
			return pushOptionalStringList(L, shadow->fonts.keys());
		QStringList cached;
		if (tryResolveCallbackMiniWindowFontListFromCache(engine, name, cached))
			return pushOptionalStringList(L, cached);
		if (tryBackfillCallbackMiniWindowFontListFromDispatch(engine, name, cached))
			return pushOptionalStringList(L, cached);
	}
	const bool inCallback = activeCallbackContextConst(engine) != nullptr;
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return pushOptionalStringList(L, QStringList());
	const QStringList fonts =
	    inCallback
	        ? runOnRuntimeThreadNoDeferredFlush(
	              runtime, [&]() -> QStringList { return runtime->windowFontList(name); }, QStringList())
	        : runOnRuntimeThreadFlushingDeferred(
	              L, runtime, [&]() -> QStringList { return runtime->windowFontList(name); }, QStringList());
	if (activeCallbackContextConst(engine))
		cacheCallbackMiniWindowFontList(engine, name, fonts);
	return pushOptionalStringList(L, fonts);
}

static bool decodeMiniWindowTextArg(lua_State *L, const int argumentIndex, const bool unicode, QString &out)
{
	if (!unicode)
	{
		out = QString::fromLocal8Bit(luaL_checkstring(L, argumentIndex));
		return true;
	}
	const char      *raw = luaL_checkstring(L, argumentIndex);
	const QByteArray bytes(raw);
	QStringDecoder   decoder(QStringConverter::Utf8);
	out = decoder.decode(bytes);
	return !decoder.hasError();
}

static int luaWindowText(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnumber(L, eNoSuchWindow);
		return 1;
	}
	const QString name    = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString fontId  = QString::fromUtf8(luaL_checkstring(L, 2));
	const bool    unicode = optBool(L, 9, false);
	QString       text;
	if (!decodeMiniWindowTextArg(L, 3, unicode, text))
	{
		lua_pushnumber(L, -3);
		return 1;
	}
	const int  left   = luaToInt(L, 4);
	const int  top    = luaToInt(L, 5);
	const int  right  = luaToInt(L, 6);
	const int  bottom = luaToInt(L, 7);
	const long colour = luaToLong(L, 8);
	if (activeCallbackContextConst(engine))
	{
		if (!resolveMiniWindowExistsForApi(engine, runtime, name))
		{
			lua_pushnumber(L, -1);
			return 1;
		}
		if (!resolveMiniWindowFontExistsForApi(engine, runtime, name, fontId))
		{
			lua_pushnumber(L, -2);
			return 1;
		}

		const int result = drawCallbackMiniWindowShadowTextForApi(engine, name, fontId, text, left, top,
		                                                          right, bottom, colour);
		if (result < 0)
		{
			lua_pushnumber(L, result);
			return 1;
		}
		const bool accepted = enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime,
		    [=](WorldRuntime &targetRuntime)
		    {
			    static_cast<void>(
			        targetRuntime.windowText(name, fontId, text, left, top, right, bottom, colour));
		    });
		lua_pushnumber(L, accepted ? result : -1);
		return 1;
	}
	lua_pushnumber(L,
	               runOnRuntimeThreadDeferredMutation(
	                   engine, runtime, [=]() -> int
	                   { return runtime->windowText(name, fontId, text, left, top, right, bottom, colour); },
	                   eNoSuchWindow));
	return 1;
}

static int luaWindowTextWidth(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnumber(L, eNoSuchWindow);
		return 1;
	}
	const QString name    = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString fontId  = QString::fromUtf8(luaL_checkstring(L, 2));
	const bool    unicode = optBool(L, 4, false);
	QString       text;
	if (!decodeMiniWindowTextArg(L, 3, unicode, text))
	{
		lua_pushnumber(L, -3);
		return 1;
	}
	if (activeCallbackContextConst(engine))
	{
		const auto *callbackContext = activeCallbackContextConst(engine);
		const bool  hasPendingDeferredMutations =
		    callbackContext && callbackContext->hasPendingDeferredRuntimeMutations;
		if (!resolveMiniWindowExistsForApi(engine, runtime, name))
		{
			lua_pushnumber(L, -1);
			return 1;
		}
		if (!resolveMiniWindowFontExistsForApi(engine, runtime, name, fontId))
		{
			lua_pushnumber(L, -2);
			return 1;
		}
		int shadowWidth = 0;
		if (tryResolveCallbackMiniWindowTextWidthFromShadow(engine, name, fontId, text, shadowWidth))
		{
			cacheCallbackMiniWindowTextWidth(engine, name, fontId, text, shadowWidth);
			lua_pushnumber(L, shadowWidth);
			return 1;
		}
		int cachedWidth = 0;
		if (tryResolveCallbackMiniWindowTextWidthFromCache(engine, name, fontId, text, cachedWidth))
		{
			lua_pushnumber(L, cachedWidth);
			return 1;
		}
		if (callbackNoFlushRuntimeReadBridgeForbidden(engine, true))
		{
			int previewWidth = 0;
			if (tryResolveCallbackMiniWindowTextWidthFromPreviewFont(engine, name, fontId, text,
			                                                         previewWidth))
			{
				cacheCallbackMiniWindowTextWidth(engine, name, fontId, text, previewWidth);
				lua_pushnumber(L, previewWidth);
				return 1;
			}
			const int fallbackWidth = qMax(0, QFontMetrics(QFont()).horizontalAdvance(text));
			cacheCallbackMiniWindowTextWidth(engine, name, fontId, text, fallbackWidth);
			lua_pushnumber(L, fallbackWidth);
			return 1;
		}
		const int width = runOnRuntimeThreadNoDeferredFlush(
		    runtime, [&]() -> int { return runtime->windowTextWidth(name, fontId, text); }, eNoSuchWindow);
		if (width < 0 && hasPendingDeferredMutations && (width == eNoSuchWindow || width == -2))
		{
			int previewWidth = 0;
			if (tryResolveCallbackMiniWindowTextWidthFromPreviewFont(engine, name, fontId, text,
			                                                         previewWidth))
			{
				cacheCallbackMiniWindowTextWidth(engine, name, fontId, text, previewWidth);
				lua_pushnumber(L, previewWidth);
				return 1;
			}
		}
		if (width >= 0)
			cacheCallbackMiniWindowTextWidth(engine, name, fontId, text, width);
		lua_pushnumber(L, width);
		return 1;
	}
	lua_pushnumber(L, runOnRuntimeThreadFlushingDeferred(
	                      L, runtime, [&]() -> int { return runtime->windowTextWidth(name, fontId, text); },
	                      eNoSuchWindow));
	return 1;
}

static int luaWindowOutputText(lua_State *L)
{
	auto *engine                  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	auto  pushWindowOutputMetrics = [L](const WorldRuntime::WindowOutputMetrics &metrics)
	{
		lua_newtable(L);
		lua_pushnumber(L, metrics.left);
		lua_setfield(L, -2, "left");
		lua_pushnumber(L, metrics.top);
		lua_setfield(L, -2, "top");
		lua_pushnumber(L, metrics.right);
		lua_setfield(L, -2, "right");
		lua_pushnumber(L, metrics.bottom);
		lua_setfield(L, -2, "bottom");
		lua_pushnumber(L, metrics.width);
		lua_setfield(L, -2, "width");
		lua_pushnumber(L, metrics.height);
		lua_setfield(L, -2, "height");
		lua_pushnumber(L, metrics.lineCount);
		lua_setfield(L, -2, "line_count");
		lua_pushnumber(L, metrics.hotspotCount);
		lua_setfield(L, -2, "hotspot_count");
		lua_pushboolean(L, metrics.hasOutput);
		lua_setfield(L, -2, "has_output");
	};

	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		constexpr WorldRuntime::WindowOutputMetrics metrics;
		lua_pushnumber(L, eNoSuchWindow);
		pushWindowOutputMetrics(metrics);
		return 2;
	}
	const QString name          = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString fontId        = QString::fromUtf8(luaL_checkstring(L, 2));
	const QString mouseUp       = QString::fromUtf8(luaL_optstring(L, 9, ""));
	const QString hotspotPrefix = QString::fromUtf8(luaL_optstring(L, 10, "output_link"));
	const bool    unicode       = optBool(L, 11, false);
	QString       text;
	if (!decodeMiniWindowTextArg(L, 3, unicode, text))
	{
		constexpr WorldRuntime::WindowOutputMetrics metrics;
		lua_pushnumber(L, -3);
		pushWindowOutputMetrics(metrics);
		return 2;
	}
	const int                         left   = luaToInt(L, 4);
	const int                         top    = luaToInt(L, 5);
	const int                         right  = luaToInt(L, 6);
	const int                         bottom = luaToInt(L, 7);
	const long                        colour = luaToLong(L, 8);
	WorldRuntime::WindowOutputMetrics metrics;
	const QString                     pluginId       = pluginIdFromLua(L);
	quint64                           asyncRequestId = 0;
	int                               result         = eNoSuchWindow;
	if (activeCallbackContextConst(engine))
	{
		const auto *callbackContext = activeCallbackContextConst(engine);
		const bool  hasPendingDeferredMutations =
		    callbackContext && callbackContext->hasPendingDeferredRuntimeMutations;
		if (!resolveMiniWindowExistsForApi(engine, runtime, name))
		{
			result = eNoSuchWindow;
		}
		else if (!resolveMiniWindowFontExistsForApi(engine, runtime, name, fontId))
		{
			result = -2;
		}
		else if (!mouseUp.isEmpty() && !isValidScriptLabelForApi(mouseUp))
		{
			result = eInvalidObjectLabel;
		}
		else
		{
			result = renderCallbackMiniWindowShadowOutputTextForApi(engine, name, fontId, text, left, top,
			                                                        right, bottom, colour, mouseUp,
			                                                        hotspotPrefix, pluginId, &metrics);
			if (result < 0 && hasPendingDeferredMutations && (result == eNoSuchWindow || result == -2))
			{
				// Install/startup callbacks can queue create/font before this call; treat the deferred
				// mutation path as authoritative and keep synchronous preview failures from short-circuiting
				// first render.
				result  = eOK;
				metrics = WorldRuntime::WindowOutputMetrics{};
			}

			if (result >= 0)
			{
				asyncRequestId      = pluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
				const bool accepted = enqueueRuntimeThreadDeferredMutationNoResult(
				    engine, runtime,
				    [name, fontId, text, left, top, right, bottom, colour, mouseUp, hotspotPrefix, pluginId,
				     asyncRequestId](WorldRuntime &targetRuntime)
				    {
					    WorldRuntime::WindowOutputMetrics deferredMetrics;
					    const int                         deferredResult = targetRuntime.windowOutputText(
					        name, fontId, text, left, top, right, bottom, colour, mouseUp, hotspotPrefix,
					        pluginId, &deferredMetrics);
					    emitPluginAsyncResult(
					        targetRuntime, pluginId, asyncRequestId, QStringLiteral("WindowOutputText"),
					        deferredResult == eOK, deferredResult,
					        deferredResult == eOK ? encodeWindowOutputMetricsPayload(deferredMetrics)
					                              : QString());
				    });
				if (accepted)
				{
					invalidateCallbackMiniWindowHotspotCacheForWindow(engine, name);
				}
				else
				{
					asyncRequestId = 0;
					result         = eNoSuchWindow;
				}
			}
		}
	}
	else
	{
		result = runOnRuntimeThread(
		    runtime,
		    [&]() -> int
		    {
			    return runtime->windowOutputText(name, fontId, text, left, top, right, bottom, colour,
			                                     mouseUp, hotspotPrefix, pluginId, &metrics);
		    },
		    eNoSuchWindow);
	}
	lua_pushnumber(L, result);
	pushWindowOutputMetrics(metrics);
	if (asyncRequestId != 0)
	{
		lua_pushnumber(L, static_cast<lua_Number>(asyncRequestId));
		return 3;
	}
	return 2;
}

