static int luaWindowLoadImage(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnumber(L, eNoSuchWindow);
		return 1;
	}
	const QString name     = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString imageId  = QString::fromUtf8(luaL_checkstring(L, 2));
	const QString filename = QString::fromUtf8(luaL_checkstring(L, 3));
	int           result   = eNoSuchWindow;
	if (activeCallbackContextConst(engine))
	{
		if (!resolveMiniWindowExistsForApi(engine, runtime, name))
		{
			lua_pushnumber(L, eNoSuchWindow);
			return 1;
		}
		const auto removeShadowImage = [&]()
		{
			loadCallbackMiniWindowShadowImage(engine, name, imageId, QString());
			cacheCallbackMiniWindowImageExists(engine, name, imageId, false);
			cacheCallbackMiniWindowImageHasAlpha(engine, name, imageId, false);
			invalidateCallbackMiniWindowListCachesForWindow(engine, name);
		};
		const auto enqueueRuntimeLoad = [&]()
		{
			enqueueRuntimeThreadDeferredMutationNoResult(
			    engine, runtime, [name, imageId, filename](WorldRuntime &targetRuntime)
			    { static_cast<void>(targetRuntime.windowLoadImage(name, imageId, filename)); });
		};
		const QString trimmed = filename.trimmed();
		if (trimmed.isEmpty())
		{
			enqueueRuntimeLoad();
			removeShadowImage();
			lua_pushnumber(L, eOK);
			return 1;
		}
		if (trimmed.size() < 5)
		{
			enqueueRuntimeLoad();
			removeShadowImage();
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		const QString lower = trimmed.toLower();
		if (!lower.endsWith(QStringLiteral(".bmp")) && !lower.endsWith(QStringLiteral(".png")))
		{
			enqueueRuntimeLoad();
			removeShadowImage();
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		QString resolvedFileName;
		QString pathError;
		if (!resolveLuaFileApiPath(engine, trimmed, &resolvedFileName, &pathError))
		{
			enqueueRuntimeLoad();
			removeShadowImage();
			lua_pushnumber(L, eFileNotFound);
			return 1;
		}
		if (!QFileInfo::exists(resolvedFileName))
		{
			enqueueRuntimeLoad();
			removeShadowImage();
			lua_pushnumber(L, eFileNotFound);
			return 1;
		}
		QImage image;
		if (!image.load(resolvedFileName))
		{
			enqueueRuntimeLoad();
			removeShadowImage();
			lua_pushnumber(L, eUnableToLoadImage);
			return 1;
		}
		enqueueRuntimeLoad();
		loadCallbackMiniWindowShadowImage(engine, name, imageId, resolvedFileName);
		cacheCallbackMiniWindowImageExists(engine, name, imageId, true);
		clearCallbackMiniWindowImageHasAlphaCache(engine, name, imageId);
		invalidateCallbackMiniWindowListCachesForWindow(engine, name);
		lua_pushnumber(L, eOK);
		return 1;
	}
	result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime, [=]() -> int { return runtime->windowLoadImage(name, imageId, filename); },
	    eNoSuchWindow);
	if (result == eOK)
	{
		cacheCallbackMiniWindowImageExists(engine, name, imageId, !filename.trimmed().isEmpty());
		if (filename.trimmed().isEmpty())
			cacheCallbackMiniWindowImageHasAlpha(engine, name, imageId, false);
		else
			clearCallbackMiniWindowImageHasAlphaCache(engine, name, imageId);
	}
	else if (result != eNoSuchWindow)
	{
		cacheCallbackMiniWindowImageExists(engine, name, imageId, false);
		cacheCallbackMiniWindowImageHasAlpha(engine, name, imageId, false);
	}
	lua_pushnumber(L, result);
	return 1;
}

static int luaWindowLoadImageMemory(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnumber(L, eNoSuchWindow);
		return 1;
	}
	const QString    name      = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString    imageId   = QString::fromUtf8(luaL_checkstring(L, 2));
	size_t           length    = 0;
	const char      *buffer    = luaL_checklstring(L, 3, &length);
	const bool       swapAlpha = optBool(L, 4, false);
	const QByteArray bytes(buffer, static_cast<int>(length));
	int              result = eNoSuchWindow;
	if (activeCallbackContextConst(engine))
	{
		if (!resolveMiniWindowExistsForApi(engine, runtime, name))
		{
			lua_pushnumber(L, eNoSuchWindow);
			return 1;
		}
		if (!loadCallbackMiniWindowShadowImageMemory(engine, name, imageId, bytes, swapAlpha))
		{
			enqueueRuntimeThreadDeferredMutationNoResult(
			    engine, runtime, [name, imageId, bytes, swapAlpha](WorldRuntime &targetRuntime)
			    { static_cast<void>(targetRuntime.windowLoadImageMemory(name, imageId, bytes, swapAlpha)); });
			cacheCallbackMiniWindowImageExists(engine, name, imageId, false);
			cacheCallbackMiniWindowImageHasAlpha(engine, name, imageId, false);
			invalidateCallbackMiniWindowListCachesForWindow(engine, name);
			lua_pushnumber(L, eUnableToLoadImage);
			return 1;
		}
		enqueueRuntimeThreadDeferredMutationNoResult(
		    engine, runtime, [name, imageId, bytes, swapAlpha](WorldRuntime &targetRuntime)
		    { static_cast<void>(targetRuntime.windowLoadImageMemory(name, imageId, bytes, swapAlpha)); });
		cacheCallbackMiniWindowImageExists(engine, name, imageId, true);
		clearCallbackMiniWindowImageHasAlphaCache(engine, name, imageId);
		invalidateCallbackMiniWindowListCachesForWindow(engine, name);
		lua_pushnumber(L, eOK);
		return 1;
	}
	result = runOnRuntimeThreadDeferredMutation(
	    engine, runtime, [=]() -> int
	    { return runtime->windowLoadImageMemory(name, imageId, bytes, swapAlpha); }, eNoSuchWindow);
	if (result == eOK)
	{
		cacheCallbackMiniWindowImageExists(engine, name, imageId, true);
		clearCallbackMiniWindowImageHasAlphaCache(engine, name, imageId);
	}
	else if (result != eNoSuchWindow)
	{
		cacheCallbackMiniWindowImageExists(engine, name, imageId, false);
		cacheCallbackMiniWindowImageHasAlpha(engine, name, imageId, false);
	}
	lua_pushnumber(L, result);
	return 1;
}

static int luaWindowImageList(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	const QString name       = QString::fromUtf8(luaL_checkstring(L, 1));
	const bool    inCallback = activeCallbackContextConst(engine) != nullptr;
	if (const MiniWindow *shadow = callbackMiniWindowShadowConst(engine, name))
		return pushOptionalStringList(L, shadow->images.keys());
	QStringList cached;
	if (tryResolveCallbackMiniWindowImageListFromCache(engine, name, cached))
		return pushOptionalStringList(L, cached);
	if (inCallback && tryBackfillCallbackMiniWindowImageListFromDispatch(engine, name, cached))
		return pushOptionalStringList(L, cached);
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return pushOptionalStringList(L, QStringList());
	const QStringList images =
	    inCallback
	        ? runOnRuntimeThreadNoDeferredFlush(
	              runtime, [&]() -> QStringList { return runtime->windowImageList(name); }, QStringList())
	        : runOnRuntimeThreadFlushingDeferred(
	              L, runtime, [&]() -> QStringList { return runtime->windowImageList(name); }, QStringList());
	if (inCallback)
	{
		cacheCallbackMiniWindowImageList(engine, name, images);
		for (const QString &imageId : images)
			cacheCallbackMiniWindowImageExists(engine, name, imageId, true);
	}
	return pushOptionalStringList(L, images);
}

