static int luaWindowWrite(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnumber(L, eNoSuchWindow);
		return 1;
	}
	const QString name     = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString fileName = QString::fromUtf8(luaL_checkstring(L, 2));
	if (activeCallbackContextConst(engine))
	{
		if (!resolveMiniWindowExistsForApi(engine, runtime, name))
		{
			lua_pushnumber(L, eNoSuchWindow);
			return 1;
		}
		const QString trimmedFileName = fileName.trimmed();
		if (trimmedFileName.isEmpty())
		{
			lua_pushnumber(L, eNoNameSpecified);
			return 1;
		}
		if (trimmedFileName.size() < 5)
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		const QString lower = trimmedFileName.toLower();
		if (!lower.endsWith(QStringLiteral(".bmp")) && !lower.endsWith(QStringLiteral(".png")))
		{
			lua_pushnumber(L, eBadParameter);
			return 1;
		}
		QString resolvedFileName;
		QString pathError;
		if (!resolveLuaFileApiPath(engine, trimmedFileName, &resolvedFileName, &pathError))
		{
			lua_pushnumber(L, eCouldNotOpenFile);
			return 1;
		}
		if (const MiniWindow *shadow = callbackMiniWindowShadowConst(engine, name))
		{
			lua_pushnumber(L, MiniWindowUtils::saveWindowImage24Bit(*shadow, resolvedFileName)
			                      ? eOK
			                      : eCouldNotOpenFile);
			return 1;
		}
		if (callbackScopeSyncBridgeForbidden())
		{
			const QString callbackPluginId = engine->pluginId();
			const quint64 requestId = callbackPluginId.isEmpty() ? 0 : nextPluginAsyncResultRequestId();
			const bool    accepted  = enqueueRuntimeThreadDeferredMutationNoResult(
			    engine, runtime,
			    [name, trimmedFileName, callbackPluginId, requestId](WorldRuntime &targetRuntime)
			    {
				    const int status = targetRuntime.windowWrite(name, trimmedFileName);
				    emitPluginAsyncResult(targetRuntime, callbackPluginId, requestId,
				                          QStringLiteral("WindowWrite"), status == eOK, status, QString());
			    });
			lua_pushnumber(L, accepted ? eOK : eBadParameter);
			if (accepted && requestId != 0)
			{
				lua_pushnumber(L, static_cast<lua_Number>(requestId));
				return 2;
			}
			return 1;
		}
		QImage    snapshot;
		const int snapshotStatus = runOnRuntimeThread(
		    runtime, [&]() -> int { return runtime->windowSnapshotImage(name, snapshot); }, eNoSuchWindow);
		if (snapshotStatus != eOK)
		{
			lua_pushnumber(L, snapshotStatus);
			return 1;
		}
		MiniWindow snapshotWindow;
		snapshotWindow.width = qMax(1, static_cast<int>(std::ceil(snapshot.deviceIndependentSize().width())));
		snapshotWindow.height =
		    qMax(1, static_cast<int>(std::ceil(snapshot.deviceIndependentSize().height())));
		snapshotWindow.setBackingSurface(snapshot);
		lua_pushnumber(L, MiniWindowUtils::saveWindowImage24Bit(snapshotWindow, resolvedFileName)
		                      ? eOK
		                      : eCouldNotOpenFile);
		return 1;
	}
	lua_pushnumber(L, runOnRuntimeThreadDeferredMutation(
	                      engine, runtime, [=]() -> int { return runtime->windowWrite(name, fileName); },
	                      eNoSuchWindow));
	return 1;
}

