static int luaWindowHotspotList(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	const QString name       = QString::fromUtf8(luaL_checkstring(L, 1));
	const bool    inCallback = activeCallbackContextConst(engine) != nullptr;
	if (const MiniWindow *shadow = callbackMiniWindowShadowConst(engine, name))
		return pushOptionalStringList(L, shadow->hotspots.keys());
	QStringList cached;
	if (tryResolveCallbackMiniWindowHotspotListFromCache(engine, name, cached))
		return pushOptionalStringList(L, cached);
	if (inCallback && tryBackfillCallbackMiniWindowHotspotListFromDispatch(engine, name, cached))
		return pushOptionalStringList(L, cached);
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
		return pushOptionalStringList(L, QStringList());
	const QStringList hotspots =
	    inCallback
	        ? runOnRuntimeThreadNoDeferredFlush(
	              runtime, [&]() -> QStringList { return runtime->windowHotspotList(name); }, QStringList())
	        : runOnRuntimeThreadFlushingDeferred(
	              L, runtime, [&]() -> QStringList { return runtime->windowHotspotList(name); },
	              QStringList());
	if (inCallback)
	{
		cacheCallbackMiniWindowHotspotList(engine, name, hotspots);
		for (const QString &hotspotId : hotspots)
			cacheCallbackMiniWindowHotspotExists(engine, name, hotspotId, true);
	}
	return pushOptionalStringList(L, hotspots);
}

static int luaWindowHotspotInfo(lua_State *L)
{
	auto         *engine  = static_cast<LuaCallbackEngine *>(lua_touserdata(L, lua_upvalueindex(1)));
	WorldRuntime *runtime = runtimeFromLuaUpvalue(L);
	if (!runtime)
	{
		lua_pushnil(L);
		return 1;
	}
	const QString name       = QString::fromUtf8(luaL_checkstring(L, 1));
	const QString hotspotId  = QString::fromUtf8(luaL_checkstring(L, 2));
	const int     infoType   = luaToInt(L, 3);
	const bool    inCallback = activeCallbackContextConst(engine) != nullptr;
	if (inCallback)
	{
		QVariant shadowValue;
		if (tryResolveCallbackMiniWindowHotspotInfoFromShadow(engine, name, hotspotId, infoType, shadowValue))
		{
			pushVariant(L, shadowValue);
			return 1;
		}
	}
	if (callbackNoFlushRuntimeReadBridgeForbidden(engine, inCallback))
	{
		pushVariant(L, QVariant());
		return 1;
	}
	const QVariant value =
	    inCallback ? runOnRuntimeThreadNoDeferredFlush(
	                     runtime, [&]() -> QVariant
	                     { return runtime->windowHotspotInfo(name, hotspotId, infoType); }, QVariant())
	               : runOnRuntimeThreadFlushingDeferred(
	                     L, runtime, [&]() -> QVariant
	                     { return runtime->windowHotspotInfo(name, hotspotId, infoType); }, QVariant());
	pushVariant(L, value);
	return 1;
}

